function getAppBaseUrl(): string {
  if (process.env.APP_URL) return process.env.APP_URL.replace(/\/$/, "");
  if (process.env.REPLIT_DEPLOYMENT_URL) return `https://${process.env.REPLIT_DEPLOYMENT_URL}`;
  const domains = process.env.REPLIT_DOMAINS;
  if (domains) {
    const prodDomain = domains.split(",").find(d => d.includes(".replit.app")) || domains.split(",")[0];
    if (prodDomain) return `https://${prodDomain.trim()}`;
  }
  if (process.env.REPLIT_DEV_DOMAIN) return `https://${process.env.REPLIT_DEV_DOMAIN}`;
  return "";
}

async function loadClubEngineSettings(clubId: number, modeOverride?: string): Promise<MatchEngineSettings> {
  const club = await storage.getClub(clubId);
  const saved = (club as any)?.matchEngineSettings;
  const cfg = saved ? { ...DEFAULT_SETTINGS, ...saved } : { ...DEFAULT_SETTINGS };
  if (modeOverride && (modeOverride === "ADVANCED" || modeOverride === "HYBRID" || modeOverride === "ROTATION")) {
    cfg.matchmakingMode = modeOverride as MatchmakingMode;
  }
  return cfg;
}

function extractFixedPairs(signups: any[]): [number, number][] {
  const pairGroups = new Map<number, number[]>();
  for (const s of signups) {
    const pgId = s.pairGroupId;
    if (pgId != null) {
      if (!pairGroups.has(pgId)) pairGroups.set(pgId, []);
      pairGroups.get(pgId)!.push(s.player.id);
    }
  }
  const pairs: [number, number][] = [];
  for (const [, playerIds] of pairGroups) {
    if (playerIds.length === 2) {
      pairs.push([playerIds[0], playerIds[1]]);
    }
  }
  return pairs;
}

