  app.get("/api/user/available-themes", requirePremium(clubIdFromSession), async (req, res) => {
    if (!req.isAuthenticated()) return res.sendStatus(401);
    try {
      const userId = req.user!.id;
      const user = await storage.getUser(userId);
      if (!user) return res.sendStatus(404);

      const standardThemes = [
        "light", "dark", "premium-gold", "ultra-premium", "green-glow",
        "sepia", "migraine", "high-contrast", "grayscale",
      ];
      const premiumThemes = [
        "obsidian-gold", "platinum-ice", "emerald-performance",
        "carbon-titanium", "amoled-black",
        "neon-circuit", "hologram-matrix", "cyber-pulse", "titanium-noir",
        "rose-gold-elite", "diamond-graphite",
        "obsidian-frost", "neon-apex", "sage-horizon", "prism-forge", "vector-legacy",
        "frosted-titanium", "midnight-voltage", "solstice-calm", "aurora-pulse", "atlas-grid",
      ];
      const eliteThemes = [
        "sapphire-velocity", "crimson-prestige", "arctic-blue",
        "aurora-borealis", "volcanic-ember", "deep-ocean", "jungle-vibe",
      ];
      const signatureThemes = [
        "royal-amethyst", "sunset-copper",
        "adrenaline-rush", "velocity-chrome", "circuit-court",
        "tropical-dawn", "savanna-breeze", "rainforest-canopy",
        "misty-bamboo", "tropical-lagoon", "sunset-savannah",
      ];
      const blackCardThemes = ["midnight-neon", "cosmic-elite", "phantom-luxe"];

      const unlockedThemes = [...standardThemes, ...premiumThemes];

      let userRank = "all";
      try {
        const allClubs = await storage.getClubs();
        for (const club of allClubs) {
          const leaderboard = await storage.getClubLeaderboard(club.id);
          const userIndex = leaderboard.findIndex(p => p.userId === userId);
          if (userIndex >= 0) {
            if (userIndex === 0 && leaderboard.length > 0) {
              userRank = "champion";
            } else if (userIndex < 10 && userRank !== "champion") {
              userRank = "top10";
            }
          }
        }
      } catch (e) {
        // ranking check failed, keep default
      }

      if (userRank === "top10" || userRank === "champion") {
        unlockedThemes.push(...eliteThemes);
      }
      if (userRank === "champion") {
        unlockedThemes.push(...signatureThemes);
      }

      const hasBlackCard = user.blackCardAccess === true;
      if (hasBlackCard) {
        unlockedThemes.push(...blackCardThemes);
      }

      const metallicCometThemes = ["obsidian-gold-ultra", "mint-prestige", "crystal-court", "phosphor-elite", "adaptive-pro", "royal-indigo"];
      const metallicCometCheck = await db.select({ id: userCards.id }).from(userCards).innerJoin(cards, eq(cards.id, userCards.cardId)).where(and(eq(userCards.userId, userId), eq(cards.name, "Metallic Comet"))).limit(1);
      const hasMetallicComet = metallicCometCheck.length > 0;
      if (hasMetallicComet) {
        unlockedThemes.push(...metallicCometThemes);
      }

      const royalDutyThemes = ["champagne-pearl", "coral-luxe", "arctic-frost", "retro-cream-tech", "lavender-opulence", "champagne-mint"];
      const royalDutyCheck = await db.select({ id: userCards.id }).from(userCards).innerJoin(cards, eq(cards.id, userCards.cardId)).where(and(eq(userCards.userId, userId), eq(cards.name, "Royal Duty"))).limit(1);
      const hasRoyalDuty = royalDutyCheck.length > 0;
      if (hasRoyalDuty) {
        unlockedThemes.push(...royalDutyThemes);
      }

      res.json({ unlockedThemes, userRank, hasBlackCard, hasMetallicComet, hasRoyalDuty });
    } catch (err: any) {
      res.status(500).json({ message: err.message || "Failed to get available themes" });
    }
  });

