  // Admin: Add club member to session waiting list
  app.post("/api/sessions/:sessionId/add-to-waiting-list", async (req, res) => {
    if (!req.isAuthenticated()) return res.sendStatus(401);
    const sessionId = Number(req.params.sessionId);
    const session = await storage.getSession(sessionId);
    if (!session) return res.status(404).json({ message: "Session not found" });

    const canAccess = await canManageSessions(req.user!.id, req.user!.role, session.clubId);
    if (!canAccess) return res.sendStatus(403);

    const { playerId } = req.body;
    if (!playerId) return res.status(400).json({ message: "playerId is required" });

    try {
      const allSignups = await storage.getSessionSignups(sessionId);
      const existingSignup = allSignups.find((s: any) => s.playerId === playerId);
      if (existingSignup) {
        return res.status(400).json({ message: "Player is already signed up for this session" });
      }

      const waitingPlayers = allSignups.filter((s: any) => s.signupStatus === "WAITING");
      const maxPos = waitingPlayers.reduce((max: number, s: any) => Math.max(max, s.waitingListPosition || 0), 0);

      let fee = session.sessionFee;
      if (fee == null) {
        const club = await storage.getClub(session.clubId);
        fee = club?.sessionFee ?? 0;
      }
      const playerProfile = await db.select({ userId: playerProfiles.userId }).from(playerProfiles).where(eq(playerProfiles.id, playerId)).limit(1);
      if (playerProfile.length > 0) {
        const [memberFee] = await db
          .select({ defaultSessionFee: membershipPlans.defaultSessionFee })
          .from(clubMemberships)
          .innerJoin(membershipPlans, eq(clubMemberships.planId, membershipPlans.id))
          .where(and(
            eq(clubMemberships.userId, playerProfile[0].userId),
            eq(clubMemberships.clubId, session.clubId),
            eq(clubMemberships.status, "ACTIVE")
          ))
          .limit(1);
        if (memberFee) {
          fee = memberFee.defaultSessionFee;
        }
      }

      const signup = await storage.createSessionSignupEnhanced({
        sessionId,
        playerId,
        fee,
        signupStatus: "WAITING",
        waitingListPosition: maxPos + 1,
        signedUpByUserId: req.user!.id,
      });

      res.json(signup);
    } catch (error) {
      console.error("Error adding player to waiting list:", error);
      res.status(500).json({ message: "Failed to add player to waiting list" });
    }
  });

  // Update session invitees - add/remove INVITED signups
  app.patch("/api/sessions/:sessionId/invitees", async (req, res) => {
    if (!req.isAuthenticated()) return res.sendStatus(401);
    const sessionId = Number(req.params.sessionId);
    const session = await storage.getSession(sessionId);
    if (!session) return res.status(404).json({ message: "Session not found" });

    const canAccess = await canManageSessions(req.user!.id, req.user!.role, session.clubId);
    if (!canAccess) return res.sendStatus(403);

    const { inviteePlayerIds } = req.body;
    if (!Array.isArray(inviteePlayerIds)) {
      return res.status(400).json({ message: "inviteePlayerIds must be an array" });
    }

    try {
      const currentSignups = await storage.getSessionSignups(sessionId);
      const currentInvited = currentSignups.filter((s: any) => s.signupStatus === "INVITED");
      const currentInvitedIds = new Set(currentInvited.map((s: any) => s.playerId));
      const desiredInvitedIds = new Set(inviteePlayerIds as number[]);
      
      const club = await storage.getClub(session.clubId);
      const clubName = club?.name || "your club";
      const baseFee = session.sessionFee ?? club?.sessionFee ?? 0;

      // Remove invitations for players no longer in the list
      for (const signup of currentInvited) {
        if (!desiredInvitedIds.has(signup.playerId)) {
          await db.delete(sessionSignups).where(eq(sessionSignups.id, signup.id));
        }
      }

      // Add new invitations for players not already invited/confirmed
      const allSignupPlayerIds = new Set(currentSignups.map((s: any) => s.playerId));
      const newInvitees: number[] = [];
      for (const playerId of inviteePlayerIds) {
        if (!allSignupPlayerIds.has(playerId)) {
          try {
            let inviteeFee = baseFee;
            const pp = await db.select({ userId: playerProfiles.userId }).from(playerProfiles).where(eq(playerProfiles.id, playerId)).limit(1);
            if (pp.length > 0) {
              const [mf] = await db
                .select({ defaultSessionFee: membershipPlans.defaultSessionFee })
                .from(clubMemberships)
                .innerJoin(membershipPlans, eq(clubMemberships.planId, membershipPlans.id))
                .where(and(
                  eq(clubMemberships.userId, pp[0].userId),
                  eq(clubMemberships.clubId, session.clubId),
                  eq(clubMemberships.status, "ACTIVE")
                ))
                .limit(1);
              if (mf) inviteeFee = mf.defaultSessionFee;
            }
            await storage.createSessionSignupEnhanced({
              sessionId,
              playerId,
              fee: inviteeFee,
              signupStatus: "INVITED",
              signedUpByUserId: req.user!.id,
            });
            newInvitees.push(playerId);
          } catch (signupErr) {
            continue;
          }
        }
      }

      // Send notifications to newly invited players
      if (newInvitees.length > 0) {
        const clubMembers = await storage.getClubMembers(session.clubId);
        for (const playerId of newInvitees) {
          const member = clubMembers.find(m => m.id === playerId);
          if (member && member.userId !== req.user!.id) {
            await storage.createNotification({
              userId: member.userId,
              type: "SESSION_INVITE",
              title: "Session Invitation",
              message: `You've been invited to "${session.title}" at ${clubName} on ${new Date(session.date).toLocaleDateString()}. Sign up now to confirm your spot!`,
              linkUrl: `/sessions/${session.id}`,
            });
          }
        }
      }

      res.json({ message: "Invitees updated successfully", added: newInvitees.length, removed: currentInvited.filter((s: any) => !desiredInvitedIds.has(s.playerId)).length });
    } catch (error) {
      console.error("[UPDATE INVITEES] Error:", error);
      res.status(500).json({ message: "Failed to update invitees" });
    }
  });

  // Admin: Promote from waiting list
  app.post("/api/sessions/:sessionId/promote-waiting", async (req, res) => {
    if (!req.isAuthenticated()) return res.sendStatus(401);
    const sessionId = Number(req.params.sessionId);
    const session = await storage.getSession(sessionId);
    if (!session) return res.status(404).json({ message: "Session not found" });

    const canAccess = await canManageSessions(req.user!.id, req.user!.role, session.clubId);
    if (!canAccess) return res.sendStatus(403);

    const signupId = Number(req.body?.signupId);
    if (!signupId) return res.status(400).json({ message: "signupId is required" });

    const allSignups = await storage.getSessionSignups(sessionId);
    const target = allSignups.find((s: any) => s.id === signupId);
    if (!target) return res.status(404).json({ message: "Signup not found in this session" });
    if (target.signupStatus !== "WAITING") {
      return res.status(400).json({ message: "Signup is not on the waiting list" });
    }
    const confirmedCount = allSignups.filter((s: any) => !s.signupStatus || s.signupStatus === "CONFIRMED").length;
    if (session.maxPlayers && confirmedCount >= session.maxPlayers) {
      return res.status(400).json({ message: "Session is full — cannot promote from waiting list" });
    }

    const updated = await storage.updateSessionSignupStatus(signupId, {
      signupStatus: "CONFIRMED",
      waitingListPosition: null,
    });
    res.json(updated);
  });

  app.patch(api.sessions.updateAttendance.path, async (req, res) => {
    if (!req.isAuthenticated()) return res.sendStatus(401); 
    
    const status = req.body;
    const signupId = Number(req.params.signupId);
    const updated = await storage.updateSignupStatus(signupId, status);

    if (status.attendanceStatus === "ATTENDED" && updated) {
      try {
        const signup = await db.select().from(sessionSignups).where(eq(sessionSignups.id, signupId)).then(r => r[0]);
        if (signup) {
          const session = await db.select().from(sessions).where(eq(sessions.id, signup.sessionId)).then(r => r[0]);
          if (session) {
            const clubId = session.clubId;
            const profile = await db.select().from(playerProfiles).where(
              and(eq(playerProfiles.id, signup.profileId))
            ).then(r => r[0]);
            if (profile) {
              const userId = profile.userId;
              const attendedCount = await db.select({ count: sql<number>`count(*)` })
                .from(sessionSignups)
                .innerJoin(sessions, eq(sessionSignups.sessionId, sessions.id))
                .innerJoin(playerProfiles, eq(sessionSignups.profileId, playerProfiles.id))
                .where(and(
                  eq(playerProfiles.userId, userId),
                  eq(sessions.clubId, clubId),
                  eq(sessions.status, "COMPLETED"),
                  inArray(sessionSignups.signupStatus, ["CONFIRMED"]),
                  sql`${sessionSignups.attendanceStatus} NOT IN ('NO_SHOW', 'JUSTIFIED_CANCELLATION', 'SICKNESS', 'EMERGENCY')`
                )).then(r => Number(r[0]?.count || 0));

              const activeRewards = await db.select().from(sessionAttendanceRewards).where(
                and(eq(sessionAttendanceRewards.clubId, clubId), eq(sessionAttendanceRewards.isActive, true))
              );

              for (const reward of activeRewards) {
                if (reward.sessionsRequired > 0 && attendedCount > 0 && attendedCount % reward.sessionsRequired === 0) {
                  const milestoneNum = Math.floor(attendedCount / reward.sessionsRequired);
                  const existingReward = await db.select().from(playerRewardLedger).where(
                    and(
                      eq(playerRewardLedger.playerId, userId),
                      eq(playerRewardLedger.clubId, clubId),
                      eq(playerRewardLedger.rewardType, "SESSION_ATTENDANCE"),
                      eq(playerRewardLedger.sourceId, reward.id),
                      eq(playerRewardLedger.sourceMilestone, milestoneNum)
                    )
                  ).then(r => r[0]);

                  if (!existingReward) {
                    const config = reward.rewardConfig as any;
                    await db.insert(playerRewardLedger).values({
                      playerId: userId,
                      clubId,
                      rewardType: "SESSION_ATTENDANCE",
                      sourceId: reward.id,
                      sourceMilestone: milestoneNum,
                      description: `Attended ${attendedCount} sessions (milestone ${milestoneNum})`,
                      credits: config.credits || 0,
                      gifts: config.gifts || null,
                      freeSessions: config.freeSessions || 0,
                      status: "AVAILABLE",
                    });

                    if (config.credits && config.credits > 0) {
                      await db.insert(creditLedger).values({
                        userId,
                        clubId,
                        amount: config.credits,
                        reason: `Session attendance reward: ${attendedCount} sessions milestone`,
                        createdById: req.user!.id,
                      });
                      ensureUserWallet(userId, clubId, config.credits, "Credit issued", req.user!.id).catch(() => {});
                    }
                    console.log(`[AUDIT] Attendance reward issued: user=${userId}, club=${clubId}, milestone=${milestoneNum}, sessions=${attendedCount}`);
                  }
                }
              }
            }
          }
        }
      } catch (err) {
        console.error("Error checking attendance milestones:", err);
      }
    }

    res.json(updated);
  });

