  // Update session settings (courts, max players, etc.)
  app.patch("/api/sessions/:id", async (req, res) => {
    if (!req.isAuthenticated()) return res.sendStatus(401);

    try {
      const sessionId = Number(req.params.id);
      const session = await storage.getSession(sessionId);
      if (!session) return res.status(404).json({ message: "Session not found" });

      // Check session edit access (Super Admin, Club Owner, Club Admin only)
      const canEdit = await canPerform({ id: req.user!.id, role: req.user!.role }, "EDIT_SESSIONS", session.clubId);
      if (!canEdit) {
        return res.sendStatus(403);
      }

      const { courtsAvailable, maxPlayers, matchMode, status, allowedCategories, courtNames, liveStreamUrl, clubId, autoGenerateActive, isPrivate, shuttleTubesUsed, title, date, startTime, durationMinutes, genderRestriction, sessionType, juniorAgeGroups, playersPerSide, matchGenderType, sessionFee, premiumFee, superPremiumFee, clubMemberFee, shuttlecockType, defaultPointsToPlayTo, venueId, queueTargetSize, publishAt, numberOfSets, sessionDetails, bannerMessage, bannerColor, customLinks, hallName, guestClubIds } = req.body;

      const updates: any = {};
      if (autoGenerateActive !== undefined) updates.autoGenerateActive = !!autoGenerateActive;
      if (isPrivate !== undefined) updates.isPrivate = !!isPrivate;
      if (shuttleTubesUsed !== undefined) updates.shuttleTubesUsed = Number(shuttleTubesUsed);
      if (clubId !== undefined && clubId !== session.clubId) {
        const canEditSource = await canPerform({ id: req.user!.id, role: req.user!.role }, "EDIT_SESSIONS", session.clubId);
        const canEditTarget = await canPerform({ id: req.user!.id, role: req.user!.role }, "EDIT_SESSIONS", clubId);
        if (!canEditSource || !canEditTarget) return res.status(403).json({ message: "You need admin access to both the current and target club to reassign a session" });
        const targetClub = await storage.getClub(clubId);
        if (!targetClub) return res.status(400).json({ message: "Target club not found" });
        updates.clubId = clubId;
      }
      if (courtsAvailable !== undefined) updates.courtsAvailable = courtsAvailable;
      if (maxPlayers !== undefined) updates.maxPlayers = maxPlayers;
      if (matchMode !== undefined) updates.matchMode = matchMode;
      if (status !== undefined) updates.status = status;
      if (liveStreamUrl !== undefined) updates.liveStreamUrl = liveStreamUrl || null;
      if (title !== undefined) updates.title = title.trim();
      if (date !== undefined) updates.date = new Date(date);
      if (startTime !== undefined) updates.startTime = startTime;
      if (durationMinutes !== undefined) updates.durationMinutes = Number(durationMinutes);
      if (genderRestriction !== undefined) updates.genderRestriction = genderRestriction;
      if (sessionType !== undefined) updates.sessionType = sessionType;
      if (juniorAgeGroups !== undefined) updates.juniorAgeGroups = juniorAgeGroups;
      if (playersPerSide !== undefined) updates.playersPerSide = Number(playersPerSide);
      if (matchGenderType !== undefined) updates.matchGenderType = matchGenderType;
      if (sessionFee !== undefined) updates.sessionFee = sessionFee !== null ? Number(sessionFee) : null;
      if (premiumFee !== undefined) updates.premiumFee = premiumFee !== null ? Number(premiumFee) : null;
      if (superPremiumFee !== undefined) updates.superPremiumFee = superPremiumFee !== null ? Number(superPremiumFee) : null;
      if (clubMemberFee !== undefined) updates.clubMemberFee = clubMemberFee !== null ? Number(clubMemberFee) : null;
      if (shuttlecockType !== undefined) updates.shuttlecockType = shuttlecockType || null;
      if (defaultPointsToPlayTo !== undefined) updates.defaultPointsToPlayTo = Number(defaultPointsToPlayTo);
      if (queueTargetSize !== undefined) updates.queueTargetSize = Number(queueTargetSize);
      if (venueId !== undefined) updates.venueId = venueId !== null ? Number(venueId) : null;
      if (numberOfSets !== undefined) updates.numberOfSets = Number(numberOfSets);
      if (courtNames !== undefined) {
        if (courtNames === null || (Array.isArray(courtNames) && courtNames.length === 0)) {
          updates.courtNames = null;
        } else if (Array.isArray(courtNames) && courtNames.every((n: any) => typeof n === "string" && n.trim().length > 0)) {
          updates.courtNames = courtNames.map((n: string) => n.trim());
        } else {
          return res.status(400).json({ message: "Court names must be an array of non-empty strings" });
        }
      }
      if (hallName !== undefined) updates.hallName = hallName || null;
      if (allowedCategories !== undefined) {
        const validCategories = ["D", "C3", "C2", "C1", "B3", "B2", "B1", "A3", "A2", "A1"];
        if (!Array.isArray(allowedCategories)) {
          return res.status(400).json({ message: "Invalid categories: must be an array" });
        }
        const filtered = allowedCategories.filter((c: string) => validCategories.includes(c));
        if (filtered.length === 0) {
          return res.status(400).json({ message: "At least one valid category is required" });
        }
        updates.allowedCategories = filtered;
      }
      if (publishAt !== undefined) updates.publishAt = publishAt ? new Date(publishAt) : null;
      if (sessionDetails !== undefined) updates.sessionDetails = sessionDetails || null;
      if (bannerMessage !== undefined) updates.bannerMessage = bannerMessage ? String(bannerMessage).slice(0, 2000) : null;
      if (bannerColor !== undefined) {
        const allowedColors = ["red", "amber", "blue", "green", "purple", "pink"];
        updates.bannerColor = bannerColor && allowedColors.includes(bannerColor) ? bannerColor : null;
      }
      if (customLinks !== undefined) {
        if (customLinks === null || !Array.isArray(customLinks)) {
          updates.customLinks = [];
        } else {
          const cleaned = customLinks
            .filter((l: any) => l && typeof l.title === "string" && typeof l.url === "string" && l.title.trim() && l.url.trim())
            .slice(0, 10)
            .map((l: any) => {
              const rawUrl = String(l.url).trim().slice(0, 500);
              const withScheme = /^https?:\/\//i.test(rawUrl) ? rawUrl : `https://${rawUrl}`;
              let safeUrl = withScheme;
              try {
                const parsed = new URL(withScheme);
                if (parsed.protocol !== "http:" && parsed.protocol !== "https:") return null;
                safeUrl = parsed.toString();
              } catch {
                return null;
              }
              return {
                title: String(l.title).trim().slice(0, 60),
                url: safeUrl.slice(0, 500),
              };
            })
            .filter((l: any) => l !== null);
          updates.customLinks = cleaned;
        }
      }
      if (guestClubIds !== undefined) {
        if (req.user!.role !== "OWNER") {
          return res.status(403).json({ message: "Only super admins can set guest club access" });
        }
        updates.guestClubIds = Array.isArray(guestClubIds) && guestClubIds.length > 0 ? guestClubIds : null;
      }

      const updated = await storage.updateSession(sessionId, updates);
      console.log(`[AUDIT] SESSION_UPDATE: sessionId=${sessionId} clubId=${session.clubId} by userId=${req.user!.id} role=${req.user!.role} changes=${JSON.stringify(Object.keys(updates))} at ${new Date().toISOString()}`);
      res.json(updated);
    } catch (err: any) {
      console.error("Error updating session:", err);
      res.status(500).json({ message: err.message || "Failed to update session" });
    }
  });

