  app.patch("/api/recurring-events/:id/apply-to-series", async (req, res) => {
    if (!req.isAuthenticated()) return res.sendStatus(401);
    try {
      const recurringEventId = Number(req.params.id);
      const [event] = await db.select().from(recurringEvents).where(eq(recurringEvents.id, recurringEventId));
      if (!event) return res.status(404).json({ message: "Recurring event not found" });

      const canAccess = await canManageSessions(req.user!.id, req.user!.role, event.clubId);
      if (!canAccess) return res.sendStatus(403);

      const { fromDate, updates: rawUpdates } = req.body;
      if (!rawUpdates || typeof rawUpdates !== "object") {
        return res.status(400).json({ message: "Updates object is required" });
      }

      const linkedSessions = await db.select().from(sessions).where(eq(sessions.recurringEventId, recurringEventId));
      const fromDateObj = fromDate ? new Date(fromDate) : null;
      const sessionsToUpdate = fromDateObj
        ? linkedSessions.filter(s => new Date(s.date) >= fromDateObj)
        : linkedSessions;

      const allowedFields = [
        "title", "startTime", "durationMinutes", "courtsAvailable", "maxPlayers",
        "matchMode", "playersPerSide", "matchGenderType", "genderRestriction",
        "isPrivate", "sessionType", "juniorAgeGroups", "allowedCategories",
        "sessionFee", "shuttlecockType", "defaultPointsToPlayTo", "numberOfSets",
        "venueId", "liveStreamUrl", "shuttleTubesUsed", "publishAt", "sessionDetails",
        "bannerMessage", "bannerColor", "customLinks"
      ];
      const allowedBannerColors = ["red", "amber", "blue", "green", "purple", "pink"];

      const updates: any = {};
      for (const key of allowedFields) {
        if (rawUpdates[key] !== undefined) {
          if (key === "date") continue;
          if (key === "publishAt") {
            updates[key] = rawUpdates[key] ? new Date(rawUpdates[key]) : null;
          } else if (key === "sessionFee") {
            updates[key] = rawUpdates[key] !== null ? Number(rawUpdates[key]) : null;
          } else if (key === "venueId") {
            updates[key] = rawUpdates[key] !== null ? Number(rawUpdates[key]) : null;
          } else if (key === "bannerMessage") {
            updates[key] = rawUpdates[key] ? String(rawUpdates[key]).slice(0, 2000) : null;
          } else if (key === "bannerColor") {
            updates[key] = rawUpdates[key] && allowedBannerColors.includes(rawUpdates[key]) ? rawUpdates[key] : null;
          } else if (key === "customLinks") {
            const arr = rawUpdates[key];
            if (arr === null || !Array.isArray(arr)) {
              updates[key] = [];
            } else {
              updates[key] = arr
                .filter((l: any) => l && typeof l.title === "string" && typeof l.url === "string" && l.title.trim() && l.url.trim())
                .slice(0, 10)
                .map((l: any) => {
                  const rawUrl = String(l.url).trim().slice(0, 500);
                  const withScheme = /^https?:\/\//i.test(rawUrl) ? rawUrl : `https://${rawUrl}`;
                  let safeUrl = withScheme;
                  try {
                    const parsed = new URL(withScheme);
                    if (parsed.protocol !== "http:" && parsed.protocol !== "https:") return null;
                    safeUrl = parsed.toString();
                  } catch {
                    return null;
                  }
                  return {
                    title: String(l.title).trim().slice(0, 60),
                    url: safeUrl.slice(0, 500),
                  };
                })
                .filter((l: any) => l !== null);
            }
          } else {
            updates[key] = rawUpdates[key];
          }
        }
      }

      let updatedCount = 0;
      for (const session of sessionsToUpdate) {
        const sessionUpdates = { ...updates };
        if (rawUpdates.publishAt !== undefined && rawUpdates.scheduleWeeksBefore) {
          const weeks = Number(rawUpdates.scheduleWeeksBefore);
          const sessionDate = new Date(session.date);
          sessionDate.setDate(sessionDate.getDate() - weeks * 7);
          sessionUpdates.publishAt = sessionDate;
        }
        await storage.updateSession(session.id, sessionUpdates);
        updatedCount++;
      }

      console.log(`[AUDIT] RECURRING_SERIES_UPDATE: recurringEventId=${recurringEventId} updatedSessions=${updatedCount} by userId=${req.user!.id} at ${new Date().toISOString()}`);
      res.json({ updated: updatedCount, message: `Updated ${updatedCount} session(s)` });
    } catch (err: any) {
      console.error("Error updating recurring series:", err);
      res.status(500).json({ message: err.message || "Failed to update series" });
    }
  });

  app.post("/api/sessions/:id/restart", async (req, res) => {
    if (!req.isAuthenticated()) return res.sendStatus(401);

    try {
      const sessionId = Number(req.params.id);
      const session = await storage.getSession(sessionId);
      if (!session) return res.status(404).json({ message: "Session not found" });

      const canAccess = await canManageSessions(req.user!.id, req.user!.role, session.clubId);
      if (!canAccess) {
        return res.status(403).json({ message: "Only admins and organisers can restart sessions" });
      }
      console.log(`[AUDIT] SESSION_RESTART: sessionId=${sessionId} clubId=${session.clubId} by userId=${req.user!.id} role=${req.user!.role} at ${new Date().toISOString()}`);

      const sessionMatches = await storage.getSessionMatches(sessionId);
      for (const match of sessionMatches) {
        await db.update(matches).set({ deletedAt: new Date() }).where(eq(matches.id, match.id));
      }

      const signups = await storage.getSessionSignups(sessionId);
      for (const signup of signups) {
        await storage.updateSignupStatus(signup.id, { attendanceStatus: "NOT_ATTENDED" });
        if (signup.isPaused) {
          await db.update(sessionSignups).set({ isPaused: false }).where(eq(sessionSignups.id, signup.id));
        }
        if (signup.pairGroupId) {
          await db.update(sessionSignups).set({ pairGroupId: null }).where(eq(sessionSignups.id, signup.id));
        }
      }

      const updated = await storage.updateSession(sessionId, { status: "ACTIVE", autoGenerateActive: false });
      res.json({ message: "Session restarted", matchesDeleted: sessionMatches.length, signupsReset: signups.length, session: updated });
    } catch (err: any) {
      console.error("Error restarting session:", err);
      res.status(500).json({ message: err.message || "Failed to restart session" });
    }
  });

