  app.post("/api/admin/generate-reset", async (req, res) => {
    if (!req.isAuthenticated()) return res.sendStatus(401);
    const user = req.user!;
    const isSuperAdmin = user.role === "OWNER" || user.role === "ADMIN";

    const adminClubIds = isSuperAdmin ? null : await getUserAdminClubIds(user.id, user.role);
    if (!isSuperAdmin && (!adminClubIds || adminClubIds.length === 0)) return res.sendStatus(403);

    try {
      const { email } = req.body;
      if (!email) return res.status(400).json({ message: "Email is required" });

      const targetUser = await storage.getUserByUsername(email);
      if (!targetUser) return res.status(404).json({ message: "User not found" });

      if (!isSuperAdmin && adminClubIds) {
        if (targetUser.role === "OWNER" || targetUser.role === "ADMIN") {
          return res.status(403).json({ message: "You cannot reset passwords for platform administrators" });
        }
        const myClubIds = new Set(adminClubIds);
        const targetProfiles = await db.select({ clubId: playerProfiles.clubId }).from(playerProfiles)
          .where(eq(playerProfiles.userId, targetUser.id));
        const hasAccess = targetProfiles.some(p => myClubIds.has(p.clubId));
        if (!hasAccess) return res.status(403).json({ message: "You can only reset passwords for members in your club" });
      }

      const token = randomBytes(32).toString("hex");
      const expiry = new Date(Date.now() + 24 * 60 * 60 * 1000);

      await db.update(users)
        .set({ passwordResetToken: token, passwordResetExpiry: expiry })
        .where(eq(users.id, targetUser.id));

      res.json({ token, fullName: targetUser.fullName });
    } catch (err: any) {
      console.error("Error generating reset:", err);
      res.status(500).json({ message: "Failed to generate reset link" });
    }
  });

  app.post("/api/forgot-password", async (req, res) => {
    try {
      const { email } = req.body;
      if (!email || typeof email !== "string") return res.status(400).json({ message: "Email is required" });

      const [targetUser] = await db.select().from(users)
        .where(eq(users.email, email.trim().toLowerCase()))
        .limit(1);

      if (!targetUser) {
        return res.json({ message: "If an account exists, a reset link has been sent." });
      }

      const token = randomBytes(32).toString("hex");
      const expiry = new Date(Date.now() + 24 * 60 * 60 * 1000);
      await db.update(users)
        .set({ passwordResetToken: token, passwordResetExpiry: expiry })
        .where(eq(users.id, targetUser.id));

      const resetUrl = `${getAppBaseUrl()}/reset-password/${token}`;

      const profiles = await db.select({ clubId: playerProfiles.clubId }).from(playerProfiles).where(eq(playerProfiles.userId, targetUser.id)).limit(1);
      let clubName = "Club Master";
      if (profiles.length > 0) {
        const club = await storage.getClub(profiles[0].clubId);
        if (club) clubName = club.name;
      }

      const { sendPasswordResetEmail } = await import("./email");
      await sendPasswordResetEmail(targetUser.email, targetUser.fullName || "Player", clubName, resetUrl);

      res.json({ message: "If an account exists, a reset link has been sent." });
    } catch (err: any) {
      console.error("Error in forgot-password:", err);
      res.json({ message: "If an account exists, a reset link has been sent." });
    }
  });

  app.post("/api/reset-password", async (req, res) => {
    try {
      const { token, password } = req.body;
      if (!token || !password || typeof password !== "string") return res.status(400).json({ message: "Token and password are required" });
      if (password.length < 6) return res.status(400).json({ message: "Password must be at least 6 characters" });

      const [targetUser] = await db.select().from(users)
        .where(and(
          eq(users.passwordResetToken, token),
          gt(users.passwordResetExpiry!, new Date())
        ))
        .limit(1);

      if (!targetUser) {
        return res.status(400).json({ message: "Invalid or expired reset link. Please request a new one from your club admin." });
      }

      const hashedPassword = await hashPassword(password);
      await db.update(users)
        .set({ password: hashedPassword, passwordResetToken: null, passwordResetExpiry: null })
        .where(eq(users.id, targetUser.id));

      res.json({ message: "Password has been reset successfully. You can now sign in." });
    } catch (err: any) {
      console.error("Error resetting password via token:", err);
      res.status(500).json({ message: "Failed to reset password" });
    }
  });

