  // Apply credit from session (deduct credit when player signs up / uses credit)
  app.post("/api/credits/use", requirePremium(clubIdFromSession), async (req, res) => {
    if (!req.isAuthenticated()) return res.sendStatus(401);
    const admin = req.user!;

    const schema = z.object({
      userId: z.number(),
      clubId: z.number(),
      sessionId: z.number(),
      signupId: z.number(),
      amount: z.number().min(1),
    });

    const parsed = schema.safeParse(req.body);
    if (!parsed.success) return res.status(400).json({ message: parsed.error.message });

    const { userId, clubId, sessionId, signupId, amount } = parsed.data;

    try {
      const allowed = await canPerform({ id: admin.id, role: admin.role }, "MANAGE_CREDITS", clubId);
      if (!allowed) return res.sendStatus(403);

      const activeWallets = await db.select().from(wallets)
        .where(and(eq(wallets.userId, userId), eq(wallets.isActive, true)));
      const eligibleWallets = activeWallets.filter(w =>
        !w.allowedClubIds || w.allowedClubIds.length === 0 || w.allowedClubIds.includes(clubId)
      );
      const currentBalance = eligibleWallets.reduce((sum, w) => sum + (w.balance || 0), 0);
      if (currentBalance < amount) {
        return res.status(400).json({ message: "Insufficient credit balance" });
      }

      const result = await db.transaction(async (trx) => {
        const [entry] = await trx
          .insert(creditLedger)
          .values({
            userId,
            clubId,
            amount: -amount,
            reason: `Credit used for session`,
            linkedSessionId: sessionId,
            linkedSignupId: signupId,
            createdById: admin.id,
          })
          .returning();

        let remaining = amount;
        for (const w of eligibleWallets) {
          if (remaining <= 0) break;
          const deduct = Math.min(w.balance, remaining);
          if (deduct > 0) {
            await trx.update(wallets).set({ balance: sql`${wallets.balance} - ${deduct}`, updatedAt: new Date() }).where(eq(wallets.id, w.id));
            await trx.insert(walletTransactions).values({ walletId: w.id, userId, clubId, amount: -deduct, type: "DEBIT" as const, reason: "Credit used for session", createdById: admin.id });
            remaining -= deduct;
          }
        }
        return entry;
      });

      res.json(result);
    } catch (err: any) {
      console.error("Error using credit:", err);
      res.status(500).json({ message: "Failed to use credit" });
    }
  });

  app.post("/api/credits/apply", async (req, res) => {
    if (!req.isAuthenticated()) return res.sendStatus(401);
    const user = req.user!;

    const schema = z.object({
      clubId: z.number(),
      sessionId: z.number(),
      amount: z.number().min(1),
    });

    const parsed = schema.safeParse(req.body);
    if (!parsed.success) return res.status(400).json({ message: parsed.error.message });

    const { clubId, sessionId, amount } = parsed.data;

    try {
      const sessionData = await storage.getSession(sessionId);
      if (!sessionData) return res.status(404).json({ message: "Session not found" });
      if (sessionData.clubId !== clubId) return res.status(400).json({ message: "Club mismatch" });

      const userSignups = await db.select({ id: sessionSignups.id, fee: sessionSignups.fee })
        .from(sessionSignups)
        .where(and(eq(sessionSignups.sessionId, sessionId), eq(sessionSignups.userId, user.id), eq(sessionSignups.signupStatus, "CONFIRMED")));
      if (userSignups.length === 0) return res.status(400).json({ message: "No confirmed signup found for this session" });

      const totalFee = userSignups.reduce((s, su) => s + (su.fee || 0), 0);
      const cappedAmount = Math.min(amount, totalFee);
      if (cappedAmount <= 0) return res.status(400).json({ message: "No applicable fee to credit" });

      const activeWallets = await db.select().from(wallets)
        .where(and(eq(wallets.userId, user.id), eq(wallets.isActive, true)));
      const eligibleWallets = activeWallets.filter(w =>
        !w.allowedClubIds || w.allowedClubIds.length === 0 || w.allowedClubIds.includes(clubId)
      );
      const currentBalance = eligibleWallets.reduce((sum, w) => sum + (w.balance || 0), 0);
      if (currentBalance < cappedAmount) {
        return res.status(400).json({ message: "Insufficient credit balance" });
      }

      const [entry] = await db
        .insert(creditLedger)
        .values({
          userId: user.id,
          clubId,
          amount: -cappedAmount,
          reason: `Credit applied to session: ${sessionData.title}`,
          linkedSessionId: sessionId,
          linkedSignupId: userSignups[0].id,
          createdById: user.id,
        })
        .returning();

      let remaining = cappedAmount;
      for (const w of eligibleWallets) {
        if (remaining <= 0) break;
        const deduct = Math.min(w.balance, remaining);
        if (deduct > 0) {
          await db.update(wallets).set({ balance: sql`${wallets.balance} - ${deduct}`, updatedAt: new Date() }).where(eq(wallets.id, w.id));
          await db.insert(walletTransactions).values({ walletId: w.id, userId: user.id, clubId, amount: -deduct, type: "DEBIT" as const, reason: `Credit applied to session: ${sessionData.title}`, createdById: user.id });
          remaining -= deduct;
        }
      }

      const coversFullFee = cappedAmount >= totalFee;
      for (const su of userSignups) {
        await db.update(sessionSignups)
          .set({
            paymentStatus: coversFullFee ? "PAID" : "PENDING",
            paymentMethod: "MEMBERSHIP_CREDIT",
          })
          .where(eq(sessionSignups.id, su.id));
      }

      const updatedWallets = await db.select().from(wallets)
        .where(and(eq(wallets.userId, user.id), eq(wallets.isActive, true)));
      const updatedEligible = updatedWallets.filter(w =>
        !w.allowedClubIds || w.allowedClubIds.length === 0 || w.allowedClubIds.includes(clubId)
      );
      const newBalance = updatedEligible.reduce((sum, w) => sum + (w.balance || 0), 0);

      const club = await storage.getClub(clubId);
      const adminProfiles = await db
        .select({ userId: playerProfiles.userId })
        .from(playerProfiles)
        .where(and(
          eq(playerProfiles.clubId, clubId),
          inArray(playerProfiles.clubRole, ["OWNER", "ADMIN"])
        ));

      for (const admin of adminProfiles) {
        await db.insert(notifications).values({
          userId: admin.userId,
          type: "credit_used",
          title: "Credit Applied to Session",
          message: `${user.fullName} applied £${(cappedAmount / 100).toFixed(2)} credit to session "${sessionData.title}". Remaining balance: £${(newBalance / 100).toFixed(2)}`,
          linkUrl: `/sessions/${sessionId}`,
        });
      }

      res.json({ entry, newBalance });
    } catch (err: any) {
      console.error("Error applying credit:", err);
      res.status(500).json({ message: "Failed to apply credit" });
    }
  });

  // Get all credit balances the current user has across clubs (for profile view)
  app.get("/api/my-credits", async (req, res) => {
    if (!req.isAuthenticated()) return res.sendStatus(401);
    const user = req.user!;

    try {
      const query = sql`
        SELECT "clubId", "clubName", COALESCE(SUM(amount), 0) AS balance FROM (
          SELECT cl.club_id AS "clubId", c.name AS "clubName", cl.amount
          FROM credit_ledger cl
          INNER JOIN clubs c ON cl.club_id = c.id
          WHERE cl.user_id = ${user.id}

          UNION ALL

          SELECT rl.club_id AS "clubId", c.name AS "clubName", rl.credits AS amount
          FROM player_reward_ledger rl
          INNER JOIN clubs c ON rl.club_id = c.id
          WHERE rl.player_id = ${user.id} AND rl.credits > 0 AND rl.status = 'AVAILABLE'
        ) combined
        GROUP BY "clubId", "clubName"`;

      const result = await db.execute(query);
      res.json(result.rows);
    } catch (err: any) {
      console.error("Error fetching user credits:", err);
      res.status(500).json({ message: "Failed to fetch credits" });
    }
  });

  // Get outstanding (unpaid) session fees for the current user across all clubs
  app.get("/api/my-outstanding-payments", async (req, res) => {
    if (!req.isAuthenticated()) return res.sendStatus(401);
    const user = req.user!;

    try {
      const profiles = await db
        .select({ id: playerProfiles.id, clubId: playerProfiles.clubId })
        .from(playerProfiles)
        .where(eq(playerProfiles.userId, user.id));

      if (profiles.length === 0) return res.json([]);

      const profileIds = profiles.map(p => p.id);
      const unpaidSignups = await db
        .select({
          signupId: sessionSignups.id,
          sessionId: sessionSignups.sessionId,
          playerId: sessionSignups.playerId,
          fee: sessionSignups.fee,
          paymentStatus: sessionSignups.paymentStatus,
          paymentMethod: sessionSignups.paymentMethod,
          paymentNotes: sessionSignups.paymentNotes,
          signupStatus: sessionSignups.signupStatus,
          signupTime: sessionSignups.signupTime,
          sessionTitle: sessions.title,
          sessionDate: sessions.date,
          clubId: sessions.clubId,
          clubName: clubs.name,
        })
        .from(sessionSignups)
        .innerJoin(sessions, eq(sessionSignups.sessionId, sessions.id))
        .innerJoin(clubs, eq(sessions.clubId, clubs.id))
        .where(
          and(
            inArray(sessionSignups.playerId, profileIds),
            eq(sessionSignups.paymentStatus, "UNPAID"),
            inArray(sessionSignups.signupStatus, ["CONFIRMED", "WAITING"])
          )
        )
        .orderBy(desc(sessions.date));

      res.json(unpaidSignups);
    } catch (err: any) {
      console.error("Error fetching outstanding payments:", err);
      res.status(500).json({ message: "Failed to fetch outstanding payments" });
    }
  });

  // Player confirms they've made payment for an outstanding session
  app.post("/api/my-payment-confirmation", requirePremium(clubIdFromSession), async (req, res) => {
    if (!req.isAuthenticated()) return res.sendStatus(401);
    const user = req.user!;
    const { signupId, paymentDate, paymentMethod } = req.body;

    if (!signupId || !paymentDate || !paymentMethod) {
      return res.status(400).json({ message: "signupId, paymentDate, and paymentMethod are required" });
    }

    try {
      const [signup] = await db.select({
        id: sessionSignups.id,
        playerId: sessionSignups.playerId,
        fee: sessionSignups.fee,
        paymentStatus: sessionSignups.paymentStatus,
        sessionId: sessionSignups.sessionId,
      }).from(sessionSignups).where(eq(sessionSignups.id, signupId));

      if (!signup) return res.status(404).json({ message: "Signup not found" });

      const [profile] = await db.select().from(playerProfiles).where(eq(playerProfiles.id, signup.playerId));
      if (!profile || profile.userId !== user.id) {
        return res.status(403).json({ message: "This signup does not belong to you" });
      }

      if (signup.paymentStatus === "PAID") {
        return res.status(400).json({ message: "This session has already been marked as paid" });
      }

      const [session] = await db.select().from(sessions).where(eq(sessions.id, signup.sessionId));
      const [club] = session ? await db.select().from(clubs).where(eq(clubs.id, session.clubId)) : [null];
      const sessionTitle = session?.title || `Session #${signup.sessionId}`;
      const sessionDate = session ? new Date(session.date).toLocaleDateString("en-GB") : "Unknown";
      const amount = (signup.fee / 100).toFixed(2);

      await db.update(sessionSignups).set({
        paymentNotes: `Player confirmed payment on ${paymentDate} via ${paymentMethod}. Awaiting admin verification.`,
      }).where(eq(sessionSignups.id, signupId));

      const ticketNumber = randomBytes(4).toString("hex").toUpperCase();
      const ticketSubject = `Payment Confirmation - ${sessionTitle} - ${sessionDate}`;
      const ticketDesc = `${user.fullName} confirmed payment of £${amount} for ${sessionTitle} on ${sessionDate}.\n\nPayment Date: ${paymentDate}\nPayment Method: ${paymentMethod}\n\nPlease verify this payment has been received.`;

      await db.insert(tickets).values({
        ticketNumber: `TK-${ticketNumber}`,
        clubId: session?.clubId || profile.clubId,
        createdByUserId: user.id,
        subject: ticketSubject,
        description: ticketDesc,
        category: "GENERAL",
        priority: "MEDIUM",
        status: "SUBMITTED",
        autoCloseAt: new Date(Date.now() + 30 * 24 * 60 * 60 * 1000),
      });

      const clubAdmins = await db.select().from(playerProfiles).where(and(
        eq(playerProfiles.clubId, session?.clubId || profile.clubId),
        eq(playerProfiles.membershipStatus, "APPROVED"),
        or(eq(playerProfiles.clubRole, "OWNER"), eq(playerProfiles.clubRole, "ADMIN"))
      ));
      const superAdmins = await storage.getUsersByRole("OWNER");
      const notifyIds = new Set([...clubAdmins.map(a => a.userId), ...superAdmins.map(s => s.id)]);

      for (const adminId of notifyIds) {
        await db.insert(notifications).values({
          userId: adminId,
          type: "PAYMENT_CONFIRMATION",
          title: "Payment Confirmation Received",
          message: `${user.fullName} confirmed payment of £${amount} for ${sessionTitle} (${sessionDate}) via ${paymentMethod}.`,
          linkUrl: `/admin/financials`,
        });

        await db.insert(internalMessages).values({
          senderId: user.id,
          recipientId: adminId,
          subject: `Payment Confirmation - ${sessionTitle}`,
          body: `Hi, I've confirmed my payment of £${amount} for ${sessionTitle} on ${sessionDate}.\n\nPayment Date: ${paymentDate}\nPayment Method: ${paymentMethod}\n\nPlease verify and mark as received. Thank you.`,
          clubId: session?.clubId || profile.clubId,
          messageCategory: "PAYMENT",
        });
      }

      res.json({ message: "Payment confirmation submitted. An admin will verify your payment." });
    } catch (err: any) {
      console.error("Error confirming payment:", err);
      res.status(500).json({ message: err.message || "Failed to confirm payment" });
    }
  });

  // Player requests credit to be applied to their next session
  app.post("/api/my-credit-request", requirePremium(clubIdFromSession), async (req, res) => {
    if (!req.isAuthenticated()) return res.sendStatus(401);
    const user = req.user!;
    const { clubId, sessionId, sessionDescription, amount } = req.body;

    if (!clubId || !amount || amount <= 0) {
      return res.status(400).json({ message: "clubId and a positive amount are required" });
    }
    if (!sessionId && !sessionDescription) {
      return res.status(400).json({ message: "Either select a session or provide a session description" });
    }

    try {
      const [profile] = await db.select().from(playerProfiles).where(and(
        eq(playerProfiles.userId, user.id),
        eq(playerProfiles.clubId, clubId),
        eq(playerProfiles.membershipStatus, "APPROVED")
      ));
      if (!profile) {
        return res.status(403).json({ message: "You are not an approved member of this club" });
      }

      let sessionTitle = sessionDescription || "";
      let sessionDateStr = "";
      if (sessionId) {
        const [sess] = await db.select().from(sessions).where(and(
          eq(sessions.id, sessionId),
          eq(sessions.clubId, clubId)
        ));
        if (!sess) {
          return res.status(400).json({ message: "Session not found in this club" });
        }
        sessionTitle = sess.title || `Session #${sessionId}`;
        sessionDateStr = new Date(sess.date).toLocaleDateString("en-GB");
      }

      const [balanceResult] = await db.select({
        total: sql<number>`COALESCE(SUM(${creditLedger.amount}), 0)::int`
      }).from(creditLedger).where(and(
        eq(creditLedger.userId, user.id),
        eq(creditLedger.clubId, clubId)
      ));

      const currentBalance = balanceResult.total || 0;
      if (amount > currentBalance) {
        return res.status(400).json({ message: `Insufficient credit balance. Available: £${(currentBalance / 100).toFixed(2)}` });
      }

      const [club] = await db.select().from(clubs).where(eq(clubs.id, clubId));
      const clubName = club?.name || "Unknown Club";
      const amountDisplay = (amount / 100).toFixed(2);
      const firstName = user.fullName?.split(" ")[0] || user.fullName;
      const paymentRef = `${user.fullName}, ${sessionDateStr || "Next Session"}, CR`;

      await db.insert(creditLedger).values({
        userId: user.id,
        clubId: clubId,
        amount: -amount,
        reason: `Credit request for ${sessionTitle || "next session"} - Ref: ${paymentRef}`,
        linkedSessionId: sessionId || null,
        createdById: user.id,
      });

      const ticketNumber2 = randomBytes(4).toString("hex").toUpperCase();
      await db.insert(tickets).values({
        ticketNumber: `TK-${ticketNumber2}`,
        clubId: clubId,
        createdByUserId: user.id,
        subject: `Credit Request - £${amountDisplay} - ${sessionTitle || "Next Session"}`,
        description: `${user.fullName} has requested £${amountDisplay} credit to be applied to ${sessionTitle || "their next session"}.\n\nClub: ${clubName}\nSession: ${sessionTitle || sessionDescription}\nDate: ${sessionDateStr || "TBC"}\nPayment Reference: ${paymentRef}\n\nPlease deduct this credit from their session fee payment.`,
        category: "CREDIT_CLAIM",
        priority: "MEDIUM",
        status: "SUBMITTED",
        creditAmount: amount,
        linkedSessionId: sessionId || null,
        autoCloseAt: new Date(Date.now() + 30 * 24 * 60 * 60 * 1000),
      });

      const clubAdmins = await db.select().from(playerProfiles).where(and(
        eq(playerProfiles.clubId, clubId),
        eq(playerProfiles.membershipStatus, "APPROVED"),
        or(eq(playerProfiles.clubRole, "OWNER"), eq(playerProfiles.clubRole, "ADMIN"))
      ));
      const superAdmins = await storage.getUsersByRole("OWNER");
      const notifyIds = new Set([...clubAdmins.map(a => a.userId), ...superAdmins.map(s => s.id)]);

      for (const adminId of notifyIds) {
        await db.insert(notifications).values({
          userId: adminId,
          type: "CREDIT_REQUEST",
          title: "Credit Request Received",
          message: `${user.fullName} requested £${amountDisplay} credit for ${sessionTitle || "next session"} at ${clubName}. Ref: ${paymentRef}`,
          linkUrl: `/admin/financials`,
        });

        await db.insert(internalMessages).values({
          senderId: user.id,
          recipientId: adminId,
          subject: `Credit Request - £${amountDisplay}`,
          body: `Hi, I'd like to use £${amountDisplay} of my credit balance for ${sessionTitle || "my next session"}.\n\nPayment Reference: ${paymentRef}\n\nPlease deduct this from my session fee. Thank you.`,
          clubId: clubId,
          messageCategory: "PAYMENT",
        });
      }

      await db.insert(notifications).values({
        userId: user.id,
        type: "CREDIT_REQUEST",
        title: "Credit Request Submitted",
        message: `Your credit request of £${amountDisplay} for ${sessionTitle || "next session"} has been submitted. Payment Reference: ${paymentRef}. Please deduct this from your session fee payment.`,
        linkUrl: `/profile`,
      });

      const [newBalance] = await db.select({
        total: sql<number>`COALESCE(SUM(${creditLedger.amount}), 0)::int`
      }).from(creditLedger).where(and(
        eq(creditLedger.userId, user.id),
        eq(creditLedger.clubId, clubId)
      ));

      res.json({
        message: `Credit request of £${amountDisplay} submitted successfully.`,
        paymentReference: paymentRef,
        newBalance: newBalance.total || 0,
      });
    } catch (err: any) {
      console.error("Error requesting credit:", err);
      res.status(500).json({ message: err.message || "Failed to submit credit request" });
    }
  });

  // Get sessions user is signed up for (for credit request dropdown)
