  app.put("/api/clubs/:clubId/birthday-settings", async (req, res) => {
    if (!req.isAuthenticated()) return res.status(401).json({ message: "Not authenticated" });
    try {
      const clubId = Number(req.params.clubId);
      const user = req.user as any;
      const canAccess = await hasAdminAccess(user.id, user.role, clubId);
      if (!canAccess) return res.status(403).json({ message: "Admin access required" });

      const bodySchema = z.object({
        isActive: z.boolean().optional(),
        credits: z.number().int().min(0).optional(),
        gifts: z.string().nullable().optional(),
        message: z.string().optional(),
      });
      const parsed = bodySchema.safeParse(req.body);
      if (!parsed.success) return res.status(400).json({ message: "Invalid data", errors: parsed.error.errors });
      const { isActive, credits, gifts, message } = parsed.data;

      const [existing] = await db.select().from(clubBirthdaySettings).where(eq(clubBirthdaySettings.clubId, clubId));

      if (existing) {
        const [updated] = await db.update(clubBirthdaySettings)
          .set({ isActive: isActive ?? existing.isActive, credits: credits ?? existing.credits, gifts: gifts !== undefined ? gifts : existing.gifts, message: message ?? existing.message, updatedAt: new Date() })
          .where(eq(clubBirthdaySettings.id, existing.id))
          .returning();
        console.log(`[AUDIT] Birthday settings updated: club=${clubId}, by user=${user.id}`);
        res.json(updated);
      } else {
        const [created] = await db.insert(clubBirthdaySettings).values({
          clubId,
          isActive: isActive ?? false,
          credits: credits ?? 0,
          gifts: gifts || null,
          message: message || "Happy Birthday! Enjoy your special day with us.",
        }).returning();
        console.log(`[AUDIT] Birthday settings created: club=${clubId}, by user=${user.id}`);
        res.json(created);
      }
    } catch (err: any) {
      res.status(500).json({ message: err.message });
    }
  });

  // GET /api/my-birthday-reward-info - Get birthday reward info for current user
  app.get("/api/my-birthday-reward-info", requirePremium(clubIdFromSession), async (req, res) => {
    if (!req.isAuthenticated()) return res.status(401).json({ message: "Not authenticated" });
    try {
      const sessionUser = req.user as any;
      const [freshUser] = await db.select().from(users).where(eq(users.id, sessionUser.id));
      if (!freshUser) return res.status(404).json({ message: "User not found" });
      const profiles = await db.select().from(playerProfiles).where(eq(playerProfiles.userId, freshUser.id));
      const results: any[] = [];

      for (const profile of profiles) {
        const clubId = profile.clubId;
        const [settings] = await db.select().from(clubBirthdaySettings).where(
          and(eq(clubBirthdaySettings.clubId, clubId), eq(clubBirthdaySettings.isActive, true))
        );

        const hasDob = !!freshUser.dateOfBirth;
        let daysUntilBirthday: number | null = null;
        let nextBirthdayDate: string | null = null;
        let birthdayToday = false;

        if (hasDob) {
          const birth = new Date(freshUser.dateOfBirth!);
          const now = new Date();
          const thisYearBirthday = new Date(now.getFullYear(), birth.getMonth(), birth.getDate());
          if (thisYearBirthday < now) {
            thisYearBirthday.setFullYear(now.getFullYear() + 1);
          }
          const diffMs = thisYearBirthday.getTime() - now.getTime();
          daysUntilBirthday = Math.ceil(diffMs / (1000 * 60 * 60 * 24));
          nextBirthdayDate = thisYearBirthday.toISOString().split("T")[0];
          const todayStr = now.toISOString().split("T")[0];
          const birthStr = `${now.getFullYear()}-${String(birth.getMonth() + 1).padStart(2, "0")}-${String(birth.getDate()).padStart(2, "0")}`;
          birthdayToday = todayStr === birthStr;
          if (daysUntilBirthday === 365 || daysUntilBirthday === 366) {
            daysUntilBirthday = 0;
            birthdayToday = true;
          }
        }

        const [clubRow] = await db.select({ name: clubs.name }).from(clubs).where(eq(clubs.id, clubId));

        results.push({
          clubId,
          clubName: clubRow?.name || "Unknown Club",
          hasDob,
          daysUntilBirthday,
          nextBirthdayDate,
          birthdayToday,
          hasRewards: !!settings,
          credits: settings?.credits || 0,
          gifts: settings?.gifts || null,
          message: settings?.message || null,
        });
      }

      res.json(results);
    } catch (err: any) {
      res.status(500).json({ message: err.message });
    }
  });

  // GET /api/my-anniversary-info - Get anniversary countdown for current user
  app.get("/api/my-anniversary-info", async (req, res) => {
    if (!req.isAuthenticated()) return res.status(401).json({ message: "Not authenticated" });
    try {
      const user = req.user as any;
      const profiles = await db.select({
        profile: playerProfiles,
        clubName: clubs.name,
      }).from(playerProfiles)
        .leftJoin(clubs, eq(playerProfiles.clubId, clubs.id))
        .where(eq(playerProfiles.userId, user.id));

      const results = [];
      for (const { profile, clubName } of profiles) {
        if (!profile.joinedAt) continue;
        const joinDate = new Date(profile.joinedAt);
        const now = new Date();

        // Calculate next anniversary
        let nextAnniversary = new Date(joinDate);
        nextAnniversary.setFullYear(now.getFullYear());
        if (nextAnniversary <= now) {
          nextAnniversary.setFullYear(now.getFullYear() + 1);
        }

        // Calculate years of membership
        const yearsSinceJoined = now.getFullYear() - joinDate.getFullYear();
        const upcomingYear = nextAnniversary.getFullYear() - joinDate.getFullYear();

        // Calculate progress through current year
        const prevAnniversary = new Date(nextAnniversary);
        prevAnniversary.setFullYear(nextAnniversary.getFullYear() - 1);
        const totalMs = nextAnniversary.getTime() - prevAnniversary.getTime();
        const elapsedMs = now.getTime() - prevAnniversary.getTime();
        const progress = Math.min(Math.max(elapsedMs / totalMs, 0), 1);

        // Get anniversary settings for this club
        const [settings] = await db.select().from(clubAnniversarySettings).where(
          and(eq(clubAnniversarySettings.clubId, profile.clubId), eq(clubAnniversarySettings.isActive, true))
        );

        results.push({
          clubId: profile.clubId,
          clubName,
          joinedAt: profile.joinedAt,
          nextAnniversary: nextAnniversary.toISOString(),
          upcomingYear,
          progress,
          hasReward: !!settings,
          rewardCredits: settings?.credits || 0,
          rewardGifts: settings?.gifts || null,
          rewardMessage: settings?.message || null,
        });
      }
      res.json(results);
    } catch (err: any) {
      res.status(500).json({ message: err.message });
    }
  });

  // GET /api/admin/player-search - Search players by name or email (ADMIN/OWNER only)
  app.get("/api/admin/player-search", async (req, res) => {
    if (!req.isAuthenticated()) return res.status(401).json({ message: "Not authenticated" });
    const currentUser = req.user as any;
    const isOwner = currentUser.role === "OWNER";
    const adminProfiles = (currentUser.playerProfiles || []).filter((p: any) => p.clubRole === "ADMIN" || p.clubRole === "OWNER");
    if (!isOwner && adminProfiles.length === 0) return res.status(403).json({ message: "Admin access required" });
    try {
      const q = (req.query.q as string || "").trim().toLowerCase();
      const filterClubId = req.query.clubId ? Number(req.query.clubId) : undefined;
      const fetchAll = q === "*";
      if (!fetchAll && q.length < 2) return res.json([]);

      if (filterClubId && !isOwner) {
        const adminClubIds = adminProfiles.map((p: any) => p.clubId);
        if (!adminClubIds.includes(filterClubId)) return res.status(403).json({ message: "No admin access to this club" });
      }

      let allUsers: { id: number; fullName: string; email: string; profileId?: number }[];
      if (filterClubId) {
        const baseConditions = fetchAll ? [] : [
          or(
            sql`lower(${users.fullName}) LIKE ${`%${q}%`}`,
            sql`lower(${users.email}) LIKE ${`%${q}%`}`
          )
        ];
        const rows = await db.select({
          id: users.id,
          fullName: users.fullName,
          email: users.email,
          profileId: playerProfiles.id,
        }).from(users)
          .innerJoin(playerProfiles, and(
            eq(playerProfiles.userId, users.id),
            eq(playerProfiles.clubId, filterClubId)
          ))
          .where(baseConditions.length > 0 ? and(...baseConditions) : undefined)
          .limit(fetchAll ? 2000 : 20);
        allUsers = rows;
        res.json(allUsers);
        return;
      }

      if (fetchAll) {
        const rows = await db.select({
          id: users.id,
          fullName: users.fullName,
          email: users.email,
        }).from(users).limit(2000);
        allUsers = rows;
      } else {
        const rows = await db.select({
          id: users.id,
          fullName: users.fullName,
          email: users.email,
        }).from(users)
          .where(or(
            sql`lower(${users.fullName}) LIKE ${`%${q}%`}`,
            sql`lower(${users.email}) LIKE ${`%${q}%`}`
          ))
          .limit(20);
        allUsers = rows;
      }

      let result = allUsers;
      if (!isOwner) {
        const adminClubIds = adminProfiles.map((p: any) => p.clubId);
        const filtered: typeof allUsers = [];
        for (const u of allUsers) {
          const profiles = await db.select().from(playerProfiles).where(
            and(eq(playerProfiles.userId, u.id), inArray(playerProfiles.clubId, adminClubIds))
          );
          if (profiles.length > 0) filtered.push(u);
        }
        result = filtered;
      }

      const withProfiles = await Promise.all(
        result.map(async (u) => {
          const profiles = await db.select({ id: playerProfiles.id }).from(playerProfiles).where(eq(playerProfiles.userId, u.id)).limit(1);
          return { ...u, profileId: profiles[0]?.id || undefined };
        })
      );
      res.json(withProfiles);
    } catch (err: any) {
      res.status(500).json({ message: err.message });
    }
  });

  app.get("/api/admin/player-credits/:userId", requirePremium(clubIdFromSession), async (req, res) => {
    if (!req.isAuthenticated()) return res.status(401).json({ message: "Not authenticated" });
    const currentUser = req.user as any;
    const isOwner = currentUser.role === "OWNER";
    const adminProfiles = (currentUser.playerProfiles || []).filter((p: any) => p.clubRole === "ADMIN" || p.clubRole === "OWNER");
    if (!isOwner && adminProfiles.length === 0) return res.status(403).json({ message: "Admin access required" });

    const userId = Number(req.params.userId);
    if (isNaN(userId)) return res.status(400).json({ message: "Invalid user ID" });

    try {
      const profiles = await db
        .select({
          clubId: playerProfiles.clubId,
          clubName: clubs.name,
        })
        .from(playerProfiles)
        .innerJoin(clubs, eq(playerProfiles.clubId, clubs.id))
        .where(eq(playerProfiles.userId, userId));

      if (!isOwner) {
        const adminClubIds = adminProfiles.map((p: any) => p.clubId);
        const filtered = profiles.filter((p) => adminClubIds.includes(p.clubId));
        const balances = await Promise.all(filtered.map(async (p) => {
          const [bal] = await db
            .select({ balance: sql<number>`COALESCE(SUM(${creditLedger.amount}), 0)` })
            .from(creditLedger)
            .where(and(eq(creditLedger.userId, userId), eq(creditLedger.clubId, p.clubId)));
          return { ...p, balance: Number(bal?.balance || 0) };
        }));
        return res.json(balances);
      }

      const balances = await Promise.all(profiles.map(async (p) => {
        const [bal] = await db
          .select({ balance: sql<number>`COALESCE(SUM(${creditLedger.amount}), 0)` })
          .from(creditLedger)
          .where(and(eq(creditLedger.userId, userId), eq(creditLedger.clubId, p.clubId)));
        return { ...p, balance: Number(bal?.balance || 0) };
      }));
      res.json(balances);
    } catch (err: any) {
      res.status(500).json({ message: err.message });
    }
  });

  // GET /api/admin/player-rewards/:userId - Get all rewards data for a specific user (ADMIN/OWNER only)
  app.get("/api/admin/player-rewards/:userId", requirePremium(clubIdFromSession), async (req, res) => {
    if (!req.isAuthenticated()) return res.status(401).json({ message: "Not authenticated" });
    const currentUser = req.user as any;
    const isOwner = currentUser.role === "OWNER";
    const adminProfiles = (currentUser.playerProfiles || []).filter((p: any) => p.clubRole === "ADMIN" || p.clubRole === "OWNER");
    if (!isOwner && adminProfiles.length === 0) return res.status(403).json({ message: "Admin access required" });

    const targetUserId = Number(req.params.userId);
    if (!targetUserId) return res.status(400).json({ message: "Invalid userId" });

    try {
      const [targetUser] = await db.select().from(users).where(eq(users.id, targetUserId));
      if (!targetUser) return res.status(404).json({ message: "User not found" });

      const targetProfiles = await db.select({
        profile: playerProfiles,
        clubName: clubs.name,
      }).from(playerProfiles)
        .leftJoin(clubs, eq(playerProfiles.clubId, clubs.id))
        .where(eq(playerProfiles.userId, targetUserId));

      const adminClubIds = isOwner ? null : adminProfiles.map((p: any) => p.clubId);
      const visibleProfiles = adminClubIds
        ? targetProfiles.filter(p => adminClubIds.includes(p.profile.clubId))
        : targetProfiles;

      if (visibleProfiles.length === 0 && !isOwner) {
        return res.status(403).json({ message: "This player is not in your clubs" });
      }

      const visibleClubIds = visibleProfiles.map(p => p.profile.clubId);

      // Rewards ledger (scoped by club for non-owners)
      const rewardsQuery = db.select({
        reward: playerRewardLedger,
        clubName: clubs.name,
      }).from(playerRewardLedger)
        .leftJoin(clubs, eq(playerRewardLedger.clubId, clubs.id));
      const rewardsData = isOwner
        ? await rewardsQuery.where(eq(playerRewardLedger.playerId, targetUserId)).orderBy(desc(playerRewardLedger.createdAt))
        : await rewardsQuery.where(and(eq(playerRewardLedger.playerId, targetUserId), inArray(playerRewardLedger.clubId, visibleClubIds))).orderBy(desc(playerRewardLedger.createdAt));
      const rewards = rewardsData.map(r => ({ ...r.reward, clubName: r.clubName }));

      // Summary (computed from scoped rewards)
      const available = rewards.filter(r => r.status === "AVAILABLE");
      const used = rewards.filter(r => r.status === "USED");
      const requested = rewards.filter(r => r.status === "REQUESTED");
      const summary = {
        totalCredits: available.reduce((sum, r) => sum + r.credits, 0),
        totalFreeSessions: available.reduce((sum, r) => sum + r.freeSessions, 0),
        totalGifts: available.filter(r => r.gifts).length,
        usedCredits: used.reduce((sum, r) => sum + r.credits, 0),
        usedFreeSessions: used.reduce((sum, r) => sum + r.freeSessions, 0),
        requestedCount: requested.length,
        totalRewards: rewards.length,
      };

      // Referrals (scoped by club for non-owners)
      const referralsQuery = db.select({
        id: referrals.id,
        code: referrals.code,
        referredName: referrals.referredName,
        referredEmail: referrals.referredEmail,
        clubId: referrals.clubId,
        status: referrals.status,
        creditAwarded: referrals.creditAwarded,
        expiresAt: referrals.expiresAt,
        createdAt: referrals.createdAt,
        clubName: clubs.name,
      }).from(referrals)
        .leftJoin(clubs, eq(referrals.clubId, clubs.id));
      const myReferrals = isOwner
        ? await referralsQuery.where(eq(referrals.referrerId, targetUserId)).orderBy(desc(referrals.createdAt))
        : await referralsQuery.where(and(eq(referrals.referrerId, targetUserId), inArray(referrals.clubId, visibleClubIds))).orderBy(desc(referrals.createdAt));

      const clubIds = [...new Set(myReferrals.map(r => r.clubId).filter(Boolean))] as number[];
      const perClubStatsMap: Record<number, any> = {};
      for (const cid of clubIds) {
        const clubRefs = myReferrals.filter(r => r.clubId === cid);
        perClubStatsMap[cid] = {
          clubId: cid,
          clubName: clubRefs[0]?.clubName || "Unknown",
          totalReferrals: clubRefs.length,
          approvedReferrals: clubRefs.filter(r => r.status === "APPROVED").length,
          pendingReferrals: clubRefs.filter(r => r.status === "ACTIVE").length,
        };
      }
      const referralStats = {
        stats: {
          totalReferrals: myReferrals.length,
          approvedReferrals: myReferrals.filter(r => r.status === "APPROVED").length,
          pendingReferrals: myReferrals.filter(r => r.status === "ACTIVE").length,
        },
        perClubStats: Object.values(perClubStatsMap),
      };

      // Attendance progress — only past sessions where the player actually played matches
      const attendanceResults: any[] = [];
      for (const { profile, clubName } of visibleProfiles) {
        const attendedCount = await db.select({ count: sql<number>`count(DISTINCT ${sessions.id})` })
          .from(sessionSignups)
          .innerJoin(sessions, eq(sessionSignups.sessionId, sessions.id))
          .innerJoin(matches, sql`${sessions.id} = ${matches.sessionId} AND (${matches.teamAPlayer1Id} = ${profile.id} OR ${matches.teamAPlayer2Id} = ${profile.id} OR ${matches.teamBPlayer1Id} = ${profile.id} OR ${matches.teamBPlayer2Id} = ${profile.id})`)
          .where(and(
            eq(sessionSignups.playerId, profile.id),
            eq(sessions.clubId, profile.clubId),
            eq(sessions.status, "COMPLETED"),
            sql`${sessions.date}::date < CURRENT_DATE`,
            inArray(sessionSignups.signupStatus, ["CONFIRMED"]),
            sql`${sessionSignups.attendanceStatus} NOT IN ('NO_SHOW', 'JUSTIFIED_CANCELLATION', 'SICKNESS', 'EMERGENCY')`
          )).then(r => Number(r[0]?.count || 0));

        const activeRewards = await db.select().from(sessionAttendanceRewards).where(
          and(eq(sessionAttendanceRewards.clubId, profile.clubId), eq(sessionAttendanceRewards.isActive, true))
        ).orderBy(sessionAttendanceRewards.sessionsRequired);

        const existingAttRewards = await db.select().from(playerRewardLedger).where(
          and(
            eq(playerRewardLedger.playerId, targetUserId),
            eq(playerRewardLedger.clubId, profile.clubId),
            eq(playerRewardLedger.rewardType, "SESSION_ATTENDANCE")
          )
        );

        const milestones = [];
        for (const reward of activeRewards.filter(r => r.sessionsRequired > 0)) {
          const config = reward.rewardConfig as any;
          const milestonesCompleted = Math.floor(attendedCount / reward.sessionsRequired);

          const alreadyCredited = existingAttRewards.filter(r => r.sourceId === reward.id);
          const creditsDue = milestonesCompleted - alreadyCredited.length;

          if (creditsDue > 0) {
            const creditAmount = config?.credits || 0;
            const freeSessionsAmount = config?.freeSessions || 0;
            const giftText = config?.gift || null;
            for (let i = 0; i < creditsDue; i++) {
              const milestoneNum = alreadyCredited.length + i + 1;
              await db.insert(playerRewardLedger).values({
                playerId: targetUserId,
                clubId: profile.clubId,
                rewardType: "SESSION_ATTENDANCE",
                sourceId: reward.id,
                sourceMilestone: milestoneNum,
                description: `Attendance milestone: ${milestoneNum * reward.sessionsRequired} sessions attended`,
                credits: creditAmount,
                freeSessions: freeSessionsAmount,
                gifts: giftText,
                status: "AVAILABLE",
              });
            }
            console.log(`[ATTENDANCE REWARD] Auto-credited ${creditsDue} milestone(s) for user ${targetUserId}, club ${profile.clubId}, reward ${reward.id}`);
          }

          milestones.push({
            rewardId: reward.id,
            sessionsRequired: reward.sessionsRequired,
            currentCount: attendedCount,
            milestonesCompleted,
            rewardConfig: config,
          });
        }

        attendanceResults.push({
          clubId: profile.clubId,
          clubName,
          totalAttended: attendedCount,
          milestones,
        });
      }

      // Anniversary info
      const anniversaryResults: any[] = [];
      for (const { profile, clubName } of visibleProfiles) {
        if (!profile.joinedAt) continue;
        const joinDate = new Date(profile.joinedAt);
        const now = new Date();
        let nextAnniversary = new Date(joinDate);
        nextAnniversary.setFullYear(now.getFullYear());
        if (nextAnniversary <= now) nextAnniversary.setFullYear(now.getFullYear() + 1);
        const upcomingYear = nextAnniversary.getFullYear() - joinDate.getFullYear();
        const prevAnniversary = new Date(nextAnniversary);
        prevAnniversary.setFullYear(nextAnniversary.getFullYear() - 1);
        const totalMs = nextAnniversary.getTime() - prevAnniversary.getTime();
        const elapsedMs = now.getTime() - prevAnniversary.getTime();
        const progress = Math.min(Math.max(elapsedMs / totalMs, 0), 1);
        const [settings] = await db.select().from(clubAnniversarySettings).where(
          and(eq(clubAnniversarySettings.clubId, profile.clubId), eq(clubAnniversarySettings.isActive, true))
        );
        anniversaryResults.push({ clubId: profile.clubId, clubName, joinedAt: profile.joinedAt, nextAnniversary: nextAnniversary.toISOString(), upcomingYear, progress, hasReward: !!settings });
      }

      // Birthday info
      const birthdayResults: any[] = [];
      const hasDob = !!targetUser.dateOfBirth;
      for (const { profile, clubName } of visibleProfiles) {
        const [settings] = await db.select().from(clubBirthdaySettings).where(
          and(eq(clubBirthdaySettings.clubId, profile.clubId), eq(clubBirthdaySettings.isActive, true))
        );
        if (!settings) continue;
        let daysUntilBirthday: number | null = null;
        let nextBirthdayDate: string | null = null;
        let birthdayToday = false;
        if (hasDob) {
          const birth = new Date(targetUser.dateOfBirth!);
          const now = new Date();
          const thisYearBirthday = new Date(now.getFullYear(), birth.getMonth(), birth.getDate());
          if (thisYearBirthday < now) thisYearBirthday.setFullYear(now.getFullYear() + 1);
          daysUntilBirthday = Math.ceil((thisYearBirthday.getTime() - now.getTime()) / 86400000);
          nextBirthdayDate = thisYearBirthday.toISOString().split("T")[0];
          const todayStr = now.toISOString().split("T")[0];
          const birthStr = `${now.getFullYear()}-${String(birth.getMonth() + 1).padStart(2, "0")}-${String(birth.getDate()).padStart(2, "0")}`;
          birthdayToday = todayStr === birthStr;
          if (daysUntilBirthday === 365 || daysUntilBirthday === 366) { daysUntilBirthday = 0; birthdayToday = true; }
        }
        birthdayResults.push({ clubId: profile.clubId, clubName, hasDob, daysUntilBirthday, nextBirthdayDate, birthdayToday, credits: settings.credits, gifts: settings.gifts });
      }

      // Points milestone progress for target player
      const pointsResults: any[] = [];
      for (const { profile, clubName } of visibleProfiles) {
        const leaderboard = await storage.getDynamicClubLeaderboard(profile.clubId);
        const entry = leaderboard.find((e: any) => e.id === profile.id);
        const currentPoints = entry ? (entry.matchesWon * 3) + (entry.matchesLost * 1) : 0;

        const activeMilestones = await db.select().from(pointsMilestoneRewards).where(
          and(eq(pointsMilestoneRewards.clubId, profile.clubId), eq(pointsMilestoneRewards.isActive, true))
        ).orderBy(pointsMilestoneRewards.pointsRequired);

        const milestones = activeMilestones.map(milestone => {
          const reached = currentPoints >= milestone.pointsRequired;
          const pointsUntil = Math.max(milestone.pointsRequired - currentPoints, 0);
          const progressPercent = milestone.pointsRequired > 0 ? Math.min((currentPoints / milestone.pointsRequired) * 100, 100) : 0;
          const isRepeating = milestone.isRepeating && milestone.milestoneType === "STANDARD";
          const timesEarned = isRepeating && milestone.pointsRequired > 0
            ? Math.floor(currentPoints / milestone.pointsRequired)
            : (reached ? 1 : 0);
          const nextThreshold = isRepeating && milestone.pointsRequired > 0
            ? (timesEarned + 1) * milestone.pointsRequired
            : milestone.pointsRequired;
          const pointsUntilNext = Math.max(nextThreshold - currentPoints, 0);
          const repeatProgress = isRepeating && milestone.pointsRequired > 0
            ? Math.min(((currentPoints % milestone.pointsRequired) / milestone.pointsRequired) * 100, 100)
            : progressPercent;
          return {
            rewardId: milestone.id,
            pointsRequired: milestone.pointsRequired,
            currentPoints,
            reached,
            pointsUntil,
            pointsUntilNext,
            progressPercent: isRepeating ? repeatProgress : progressPercent,
            rewardConfig: milestone.rewardConfig,
            isRepeating,
            milestoneType: milestone.milestoneType || "STANDARD",
            timesEarned,
            nextThreshold,
          };
        });

        const nextUnreached = milestones.find(m => !m.reached);
        const highestReached = [...milestones].reverse().find(m => m.reached);

        pointsResults.push({
          clubId: profile.clubId,
          clubName,
          currentPoints,
          milestones,
          nextMilestone: nextUnreached || null,
          highestReached: highestReached || null,
        });
      }

      // Badge progress for target player
      const BADGE_DEFS_ADMIN = [
        { id: "first_win", name: "First Win", criteria: "Win your first match", icon: "zap", color: "#22c55e", check: (s: any) => s.won >= 1 },
        { id: "5_wins", name: "5+ Wins", criteria: "Win 5 or more matches", icon: "flame", color: "#f97316", check: (s: any) => s.won >= 5 },
        { id: "10_matches", name: "10+ Matches", criteria: "Play 10 or more matches", icon: "star", color: "#eab308", check: (s: any) => s.played >= 10 },
        { id: "rising_star", name: "Rising Star", criteria: "3+ wins with 60%+ win rate", icon: "sparkles", color: "#ec4899", check: (s: any) => s.won >= 3 && s.played > 0 && (s.won / s.played) * 100 >= 60 },
        { id: "top_performer", name: "Top Performer", criteria: "75%+ win rate (4+ matches)", icon: "medal", color: "#a855f7", check: (s: any) => s.played >= 4 && (s.won / s.played) * 100 >= 75 },
        { id: "undefeated", name: "Undefeated", criteria: "10 consecutive wins", icon: "trophy", color: "#d97706", check: (s: any) => (s.winStreak || 0) >= 10 },
        { id: "iron_player", name: "Iron Player", criteria: "Play 20+ matches", icon: "shield", color: "#3b82f6", check: (s: any) => s.played >= 20 },
        { id: "champion", name: "Champion", criteria: "15+ wins with 70%+ win rate", icon: "crown", color: "#f59e0b", check: (s: any) => s.won >= 15 && s.played > 0 && (s.won / s.played) * 100 >= 70 },
      ];
      const badgeResults: any[] = [];
      for (const { profile, clubName } of visibleProfiles) {
        const leaderboard = await storage.getDynamicClubLeaderboard(profile.clubId);
        const entry = leaderboard.find((e: any) => e.id === profile.id);
        const played = entry?.matchesPlayed || 0;
        const won = entry?.matchesWon || 0;
        const pStats = { played, won };
        const winRate = played > 0 ? Math.round((won / played) * 100) : 0;

        const badges = BADGE_DEFS_ADMIN.map(bd => ({
          id: bd.id,
          name: bd.name,
          criteria: bd.criteria,
          icon: bd.icon,
          color: bd.color,
          earned: bd.check(pStats),
        }));

        const earnedCount = badges.filter(b => b.earned).length;
        const highestEarnedIndex = badges.reduce((max, b, idx) => b.earned ? idx : max, -1);

        badgeResults.push({
          clubId: profile.clubId,
          clubName,
          matchesPlayed: played,
          matchesWon: won,
          winRate,
          badges,
          earnedCount,
          totalBadges: badges.length,
          highestEarnedIndex,
          grade: profile.grade || null,
        });
      }

      res.json({
        player: { id: targetUser.id, fullName: targetUser.fullName, email: targetUser.email },
        rewards,
        summary,
        referralStats,
        attendanceProgress: attendanceResults,
        anniversaryData: anniversaryResults,
        birthdayData: birthdayResults,
        pointsProgress: pointsResults,
        badgeProgress: badgeResults,
      });
    } catch (err: any) {
      console.error("Error fetching player rewards:", err);
      res.status(500).json({ message: err.message });
    }
  });

  // POST /api/check-anniversaries - Check and process anniversaries (called by scheduler or manually)
  app.post("/api/check-anniversaries", async (req, res) => {
    if (!req.isAuthenticated()) return res.status(401).json({ message: "Not authenticated" });
    const user = req.user as any;
    if (user.role !== "OWNER") return res.status(403).json({ message: "Super admin only" });
    try {
      const allSettings = await db.select().from(clubAnniversarySettings).where(eq(clubAnniversarySettings.isActive, true));
      let processed = 0;

      for (const settings of allSettings) {
        const profiles = await db.select().from(playerProfiles).where(eq(playerProfiles.clubId, settings.clubId));

        for (const profile of profiles) {
          if (!profile.joinedAt || !profile.userId) continue;
          const joinDate = new Date(profile.joinedAt);
          const now = new Date();
          const today = new Date(now.getFullYear(), now.getMonth(), now.getDate());
          const anniversaryThisYear = new Date(joinDate);
          anniversaryThisYear.setFullYear(now.getFullYear());
          const annivDay = new Date(anniversaryThisYear.getFullYear(), anniversaryThisYear.getMonth(), anniversaryThisYear.getDate());

          if (annivDay.getTime() === today.getTime() && now.getFullYear() > joinDate.getFullYear()) {
            const yearNum = now.getFullYear() - joinDate.getFullYear();
            // Check for duplicate
            const existing = await db.select().from(playerRewardLedger).where(
              and(
                eq(playerRewardLedger.playerId, profile.userId),
                eq(playerRewardLedger.clubId, settings.clubId),
                eq(playerRewardLedger.rewardType, "ANNIVERSARY"),
                eq(playerRewardLedger.sourceMilestone, yearNum)
              )
            ).then(r => r[0]);

            if (!existing) {
              const clubData = await db.select().from(clubs).where(eq(clubs.id, settings.clubId)).then(r => r[0]);
              const clubName = clubData?.name || "your club";

              await db.insert(playerRewardLedger).values({
                playerId: profile.userId,
                clubId: settings.clubId,
                rewardType: "ANNIVERSARY",
                sourceMilestone: yearNum,
                description: `${yearNum} year anniversary at ${clubName}`,
                credits: settings.credits || 0,
                gifts: settings.gifts || null,
                freeSessions: 0,
                status: "AVAILABLE",
              });

              if (settings.credits > 0) {
                await db.insert(creditLedger).values({
                  userId: profile.userId,
                  clubId: settings.clubId,
                  amount: settings.credits,
                  reason: `Club anniversary reward: ${yearNum} year(s) at ${clubName}`,
                  createdById: user.id,
                });
                ensureUserWallet(profile.userId, settings.clubId, settings.credits, "Credit issued", user.id).catch(() => {});
              }

              // Send notification
              await db.insert(notifications).values({
                userId: profile.userId,
                type: "ANNIVERSARY",
                title: `Happy ${yearNum} Year Anniversary!`,
                message: settings.message || `Happy ${yearNum} year anniversary at ${clubName}! ${settings.credits > 0 ? `You've earned £${(settings.credits / 100).toFixed(2)} credit.` : ""}${settings.gifts ? ` Gift: ${settings.gifts}` : ""}`,
              });

              // Send internal message
              await db.insert(internalMessages).values({
                senderId: user.id,
                recipientId: profile.userId,
                content: `🎉 ${settings.message || `Happy ${yearNum} year anniversary at ${clubName}!`}\n\n${settings.credits > 0 ? `You've been awarded £${(settings.credits / 100).toFixed(2)} in club credits.` : ""}${settings.gifts ? `\nGift: ${settings.gifts}` : ""}`,
              });

              console.log(`[AUDIT] Anniversary reward issued: user=${profile.userId}, club=${settings.clubId}, year=${yearNum}, credits=${settings.credits}`);
              processed++;
            }
          }
        }
      }

      res.json({ message: `Processed ${processed} anniversary rewards` });
    } catch (err: any) {
      res.status(500).json({ message: err.message });
    }
  });

  // === ATTENDANCE ANALYTICS & INACTIVE MEMBERS ===

  app.get("/api/admin/attendance-analytics", requirePremium(clubIdFromSession), async (req, res) => {
    if (!req.isAuthenticated()) return res.sendStatus(401);
    try {
      const user = req.user!;
      const adminClubIds = await getUserAdminClubIds(user.id, user.role);
      if (adminClubIds.length === 0) return res.json({ kpis: { totalSessions: 0, totalAttendances: 0, uniqueMembers: 0, avgAttendance: 0, growthPercent: 0, noShowRate: 0, noShowCount: 0, previousPeriodAttendances: 0 }, topMembers: [], distribution: [], overTime: [], sessionPerformance: [] });

      const { dateFrom, dateTo, clubId, sessionType, membershipStatus } = req.query;
      const now = new Date();
      const fromDate = dateFrom ? new Date(dateFrom as string) : new Date(now.getTime() - 30 * 24 * 60 * 60 * 1000);
      const toDate = dateTo ? new Date(dateTo as string) : now;
      const periodMs = toDate.getTime() - fromDate.getTime();
      const prevFrom = new Date(fromDate.getTime() - periodMs);
      const prevTo = new Date(fromDate.getTime());

      let filteredClubIds = adminClubIds;
      if (clubId) {
        const cid = Number(clubId);
        if (adminClubIds.includes(cid)) filteredClubIds = [cid];
        else return res.status(403).json({ message: "Access denied to this club" });
      }

      const allSessions = await db.select().from(sessions)
        .where(and(
          inArray(sessions.clubId, filteredClubIds),
          gte(sessions.date, fromDate),
          lte(sessions.date, toDate),
          sql`${sessions.status} != 'CANCELLED'`,
          ...(sessionType ? [eq(sessions.sessionType, sessionType as any)] : [])
        ));

      const sessionIds = allSessions.map(s => s.id);
      if (sessionIds.length === 0) return res.json({ kpis: { totalSessions: 0, totalAttendances: 0, uniqueMembers: 0, avgAttendance: 0, growthPercent: 0, noShowRate: 0, noShowCount: 0, previousPeriodAttendances: 0 }, topMembers: [], distribution: [], overTime: [], sessionPerformance: [] });

      const allSignups = await db.select().from(sessionSignups)
        .where(inArray(sessionSignups.sessionId, sessionIds));

      let filteredSignups = allSignups;
      if (membershipStatus) {
        const profilesForFilter = await db.select({ id: playerProfiles.id })
          .from(playerProfiles)
          .where(eq(playerProfiles.membershipStatus, membershipStatus as any));
        const profileIds = new Set(profilesForFilter.map(p => p.id));
        filteredSignups = allSignups.filter(s => profileIds.has(s.playerId));
      }

      const explicitAttendedStatuses = ["ATTENDED", "PARTIAL_ATTENDANCE", "LATE_ARRIVAL"];
      const explicitAbsentStatuses = ["NO_SHOW", "JUSTIFIED_CANCELLATION"];
      const sessionMap = new Map(allSessions.map(s => [s.id, s]));

      const isConsideredAttended = (signup: any) => {
        if (explicitAttendedStatuses.includes(signup.attendanceStatus)) return true;
        if (explicitAbsentStatuses.includes(signup.attendanceStatus)) return false;
        const sess = sessionMap.get(signup.sessionId);
        if (sess && sess.date < now && signup.signupStatus === "CONFIRMED") return true;
        return false;
      };

      const attended = filteredSignups.filter(isConsideredAttended);
      const totalSessions = allSessions.length;
      const totalAttendances = attended.length;
      const uniqueMemberIds = new Set(attended.map(s => s.playerId));
      const uniqueMembers = uniqueMemberIds.size;
      const avgAttendance = totalSessions > 0 ? Math.round((totalAttendances / totalSessions) * 10) / 10 : 0;

      const prevSessions = await db.select({ id: sessions.id, date: sessions.date }).from(sessions)
        .where(and(
          inArray(sessions.clubId, filteredClubIds),
          gte(sessions.date, prevFrom),
          lte(sessions.date, prevTo),
          sql`${sessions.status} != 'CANCELLED'`
        ));
      const prevSessionIds = prevSessions.map(s => s.id);
      const prevSessionMap = new Map(prevSessions.map(s => [s.id, s]));
      let previousPeriodAttendances = 0;
      if (prevSessionIds.length > 0) {
        const prevSignups = await db.select().from(sessionSignups)
          .where(inArray(sessionSignups.sessionId, prevSessionIds));
        previousPeriodAttendances = prevSignups.filter(s => {
          if (explicitAttendedStatuses.includes(s.attendanceStatus)) return true;
          if (explicitAbsentStatuses.includes(s.attendanceStatus)) return false;
          const sess = prevSessionMap.get(s.sessionId);
          return sess && sess.date < now && s.signupStatus === "CONFIRMED";
        }).length;
      }
      const growthPercent = previousPeriodAttendances > 0
        ? Math.round(((totalAttendances - previousPeriodAttendances) / previousPeriodAttendances) * 100)
        : totalAttendances > 0 ? 100 : 0;

      const noShows = filteredSignups.filter(s => {
        const sess = sessionMap.get(s.sessionId);
        return sess && sess.date < now && s.signupStatus === "CONFIRMED" &&
          explicitAbsentStatuses.includes(s.attendanceStatus);
      });
      const noShowCount = noShows.length;
      const confirmedPast = filteredSignups.filter(s => {
        const sess = sessionMap.get(s.sessionId);
        return s.signupStatus === "CONFIRMED" && sess && sess.date < now;
      });
      const noShowRate = confirmedPast.length > 0 ? Math.round((noShowCount / confirmedPast.length) * 100) : 0;

      const memberAttendanceCounts = new Map<number, { attended: number; total: number }>();
      for (const s of filteredSignups) {
        if (!memberAttendanceCounts.has(s.playerId)) memberAttendanceCounts.set(s.playerId, { attended: 0, total: 0 });
        const entry = memberAttendanceCounts.get(s.playerId)!;
        entry.total++;
        if (isConsideredAttended(s)) entry.attended++;
      }

      const topPlayerIds = Array.from(memberAttendanceCounts.entries())
        .sort((a, b) => b[1].attended - a[1].attended)
        .slice(0, 20)
        .map(([id]) => id);

      let topMembers: any[] = [];
      if (topPlayerIds.length > 0) {
        const profileData = await db.select({
          id: playerProfiles.id,
          userId: playerProfiles.userId,
          clubId: playerProfiles.clubId,
        }).from(playerProfiles).where(inArray(playerProfiles.id, topPlayerIds));

        const userIds = profileData.map(p => p.userId);
        const userData = userIds.length > 0 ? await db.select({ id: users.id, fullName: users.fullName }).from(users).where(inArray(users.id, userIds)) : [];
        const clubData = await db.select({ id: clubs.id, name: clubs.name }).from(clubs).where(inArray(clubs.id, filteredClubIds));

        const userMap = new Map(userData.map(u => [u.id, u]));
        const clubMap = new Map(clubData.map(c => [c.id, c]));
        const profileMap = new Map(profileData.map(p => [p.id, p]));

        topMembers = topPlayerIds.map(pid => {
          const stats = memberAttendanceCounts.get(pid)!;
          const profile = profileMap.get(pid);
          const u = profile ? userMap.get(profile.userId) : null;
          const c = profile ? clubMap.get(profile.clubId) : null;
          return {
            profileId: pid,
            name: u?.fullName || "Unknown",
            clubName: c?.name || "Unknown",
            totalAttendances: stats.attended,
            totalBookings: stats.total,
            attendanceRate: stats.total > 0 ? Math.round((stats.attended / stats.total) * 100) : 0,
          };
        });
      }

      const buckets = [
        { label: "1-2", min: 1, max: 2 },
        { label: "3-5", min: 3, max: 5 },
        { label: "6-10", min: 6, max: 10 },
        { label: "11+", min: 11, max: Infinity },
      ];
      const distribution = buckets.map(b => {
        const count = Array.from(memberAttendanceCounts.values()).filter(v => v.attended >= b.min && v.attended <= b.max).length;
        return { bucket: b.label, count };
      });

      const dateMap = new Map<string, { attendances: number; sessions: Set<number>; members: Set<number> }>();
      for (const sess of allSessions) {
        const dateKey = sess.date.toISOString().split("T")[0];
        if (!dateMap.has(dateKey)) dateMap.set(dateKey, { attendances: 0, sessions: new Set(), members: new Set() });
        dateMap.get(dateKey)!.sessions.add(sess.id);
      }
      for (const s of attended) {
        const sess = allSessions.find(ss => ss.id === s.sessionId);
        if (sess) {
          const dateKey = sess.date.toISOString().split("T")[0];
          const entry = dateMap.get(dateKey)!;
          entry.attendances++;
          entry.members.add(s.playerId);
        }
      }
      const overTime = Array.from(dateMap.entries())
        .sort(([a], [b]) => a.localeCompare(b))
        .map(([date, data]) => ({
          date,
          attendances: data.attendances,
          sessions: data.sessions.size,
          uniqueMembers: data.members.size,
        }));

      const modeMap = new Map<string, { sessions: any[]; attended: number; signups: any[] }>();
      for (const sess of allSessions) {
        const mode = sess.matchMode;
        if (!modeMap.has(mode)) modeMap.set(mode, { sessions: [], attended: 0, signups: [] });
        modeMap.get(mode)!.sessions.push(sess);
      }
      for (const s of filteredSignups) {
        const sess = sessionMap.get(s.sessionId);
        if (sess) {
          const entry = modeMap.get(sess.matchMode)!;
          entry.signups.push(s);
          if (isConsideredAttended(s)) entry.attended++;
        }
      }

      const firstAttendanceMap = new Map<number, string>();
      for (const s of attended) {
        const sess = allSessions.find(ss => ss.id === s.sessionId);
        if (sess) {
          const dateKey = sess.date.toISOString().split("T")[0];
          if (!firstAttendanceMap.has(s.playerId) || dateKey < firstAttendanceMap.get(s.playerId)!) {
            firstAttendanceMap.set(s.playerId, dateKey);
          }
        }
      }

      const sessionPerformance = Array.from(modeMap.entries()).map(([mode, data]) => {
        const totalMaxPlayers = data.sessions.reduce((sum: number, s: any) => sum + (s.maxPlayers || 0), 0);
        const avgAtt = data.sessions.length > 0 ? Math.round(data.attended / data.sessions.length * 10) / 10 : 0;
        const fillRate = totalMaxPlayers > 0 ? Math.round((data.attended / totalMaxPlayers) * 100) : 0;

        const attendedPlayerIds = new Set<number>();
        const firstTimerIds = new Set<number>();
        const repeatIds = new Set<number>();
        for (const s of data.signups) {
          if (isConsideredAttended(s)) {
            if (attendedPlayerIds.has(s.playerId)) {
              repeatIds.add(s.playerId);
            } else {
              attendedPlayerIds.add(s.playerId);
            }
            const firstDate = firstAttendanceMap.get(s.playerId);
            const sess = sessionMap.get(s.sessionId);
            if (firstDate && sess && sess.date.toISOString().split("T")[0] === firstDate) {
              firstTimerIds.add(s.playerId);
            }
          }
        }

        return {
          sessionType: mode,
          totalSessions: data.sessions.length,
          avgAttendance: avgAtt,
          fillRate,
          repeatPercent: attendedPlayerIds.size > 0 ? Math.round((repeatIds.size / attendedPlayerIds.size) * 100) : 0,
          firstTimerPercent: attendedPlayerIds.size > 0 ? Math.round((firstTimerIds.size / attendedPlayerIds.size) * 100) : 0,
        };
      });

      res.json({
        kpis: { totalSessions, totalAttendances, uniqueMembers, avgAttendance, growthPercent, noShowRate, noShowCount, previousPeriodAttendances },
        topMembers,
        distribution,
        overTime,
        sessionPerformance,
      });
    } catch (err: any) {
      console.error("Error in attendance analytics:", err);
      res.status(500).json({ message: err.message || "Failed to fetch attendance analytics" });
    }
  });

  app.get("/api/admin/attendance-analytics/kpi-detail/:metric", requirePremium(clubIdFromSession), async (req, res) => {
    if (!req.isAuthenticated()) return res.sendStatus(401);
    try {
      const user = req.user!;
      const adminClubIds = await getUserAdminClubIds(user.id, user.role);
      if (adminClubIds.length === 0) return res.json([]);

      const { dateFrom, dateTo, clubId } = req.query;
      const now = new Date();
      const fromDate = dateFrom ? new Date(dateFrom as string) : new Date(now.getTime() - 30 * 24 * 60 * 60 * 1000);
      const toDate = dateTo ? new Date(dateTo as string) : now;
      let filteredClubIds = adminClubIds;
      if (clubId) {
        const cid = Number(clubId);
        if (adminClubIds.includes(cid)) filteredClubIds = [cid];
        else return res.status(403).json({ message: "Access denied" });
      }

      const metric = req.params.metric;
      const allSessions = await db.select().from(sessions)
        .where(and(
          inArray(sessions.clubId, filteredClubIds),
          gte(sessions.date, fromDate),
          lte(sessions.date, toDate),
          sql`${sessions.status} != 'CANCELLED'`
        ));
      const sessionIds = allSessions.map(s => s.id);
      const clubData = await db.select({ id: clubs.id, name: clubs.name }).from(clubs).where(inArray(clubs.id, filteredClubIds));
      const clubMap = new Map(clubData.map(c => [c.id, c]));

      if (metric === "totalSessions") {
        const result = allSessions.map(s => ({
          id: s.id,
          title: s.title,
          date: s.date,
          clubName: clubMap.get(s.clubId)?.name || "Unknown",
          maxPlayers: s.maxPlayers,
          matchMode: s.matchMode,
        }));
        return res.json(result);
      }

      if (sessionIds.length === 0) return res.json([]);
      const allSignups = await db.select().from(sessionSignups).where(inArray(sessionSignups.sessionId, sessionIds));
      const explicitAttendedStatuses2 = ["ATTENDED", "PARTIAL_ATTENDANCE", "LATE_ARRIVAL"];
      const explicitAbsentStatuses2 = ["NO_SHOW", "JUSTIFIED_CANCELLATION"];
      const sessionMap2 = new Map(allSessions.map(s => [s.id, s]));
      const isConsideredAttended2 = (signup: any) => {
        if (explicitAttendedStatuses2.includes(signup.attendanceStatus)) return true;
        if (explicitAbsentStatuses2.includes(signup.attendanceStatus)) return false;
        const sess = sessionMap2.get(signup.sessionId);
        if (sess && sess.date < now && signup.signupStatus === "CONFIRMED") return true;
        return false;
      };

      if (metric === "totalAttendances") {
        const attended = allSignups.filter(isConsideredAttended2);
        const playerIds = [...new Set(attended.map(s => s.playerId))];
        const profileData = playerIds.length > 0 ? await db.select({ id: playerProfiles.id, userId: playerProfiles.userId, clubId: playerProfiles.clubId }).from(playerProfiles).where(inArray(playerProfiles.id, playerIds)) : [];
        const userIds = profileData.map(p => p.userId);
        const userData = userIds.length > 0 ? await db.select({ id: users.id, fullName: users.fullName }).from(users).where(inArray(users.id, userIds)) : [];
        const userMap = new Map(userData.map(u => [u.id, u]));
        const profileMap = new Map(profileData.map(p => [p.id, p]));

        const grouped = new Map<number, number>();
        for (const s of attended) {
          grouped.set(s.playerId, (grouped.get(s.playerId) || 0) + 1);
        }
        const result = Array.from(grouped.entries()).map(([pid, count]) => {
          const profile = profileMap.get(pid);
          const u = profile ? userMap.get(profile.userId) : null;
          return { profileId: pid, name: u?.fullName || "Unknown", totalAttendances: count, clubName: profile ? clubMap.get(profile.clubId)?.name || "Unknown" : "Unknown" };
        }).sort((a, b) => b.totalAttendances - a.totalAttendances);
        return res.json(result);
      }

      if (metric === "uniqueMembers") {
        const attended = allSignups.filter(isConsideredAttended2);
        const uniquePlayerIds = [...new Set(attended.map(s => s.playerId))];
        const profileData = uniquePlayerIds.length > 0 ? await db.select({ id: playerProfiles.id, userId: playerProfiles.userId, clubId: playerProfiles.clubId }).from(playerProfiles).where(inArray(playerProfiles.id, uniquePlayerIds)) : [];
        const userIds = profileData.map(p => p.userId);
        const userData = userIds.length > 0 ? await db.select({ id: users.id, fullName: users.fullName, email: users.email }).from(users).where(inArray(users.id, userIds)) : [];
        const userMap = new Map(userData.map(u => [u.id, u]));
        const profileMap = new Map(profileData.map(p => [p.id, p]));

        const result = uniquePlayerIds.map(pid => {
          const profile = profileMap.get(pid);
          const u = profile ? userMap.get(profile.userId) : null;
          return { profileId: pid, name: u?.fullName || "Unknown", email: u?.email || "", clubName: profile ? clubMap.get(profile.clubId)?.name || "Unknown" : "Unknown" };
        });
        return res.json(result);
      }

      if (metric === "noShows") {
        const noShows = allSignups.filter(s => {
          const sess = sessionMap2.get(s.sessionId);
          return s.signupStatus === "CONFIRMED" && explicitAbsentStatuses2.includes(s.attendanceStatus) && sess && sess.date < now;
        });
        const playerIds = [...new Set(noShows.map(s => s.playerId))];
        const profileData = playerIds.length > 0 ? await db.select({ id: playerProfiles.id, userId: playerProfiles.userId, clubId: playerProfiles.clubId }).from(playerProfiles).where(inArray(playerProfiles.id, playerIds)) : [];
        const userIds = profileData.map(p => p.userId);
        const userData = userIds.length > 0 ? await db.select({ id: users.id, fullName: users.fullName }).from(users).where(inArray(users.id, userIds)) : [];
        const userMap = new Map(userData.map(u => [u.id, u]));
        const profileMap = new Map(profileData.map(p => [p.id, p]));

        const result = noShows.map(s => {
          const sess = allSessions.find(ss => ss.id === s.sessionId);
          const profile = profileMap.get(s.playerId);
          const u = profile ? userMap.get(profile.userId) : null;
          return {
            signupId: s.id,
            profileId: s.playerId,
            name: u?.fullName || "Unknown",
            sessionTitle: sess?.title || "Unknown",
            sessionDate: sess?.date,
            attendanceStatus: s.attendanceStatus,
            clubName: profile ? clubMap.get(profile.clubId)?.name || "Unknown" : "Unknown",
          };
        });
        return res.json(result);
      }

      res.status(400).json({ message: "Invalid metric" });
    } catch (err: any) {
      console.error("Error in KPI detail:", err);
      res.status(500).json({ message: err.message || "Failed to fetch KPI detail" });
    }
  });

  app.get("/api/admin/attendance-analytics/member/:profileId", requirePremium(clubIdFromSession), async (req, res) => {
    if (!req.isAuthenticated()) return res.sendStatus(401);
    try {
      const user = req.user!;
      const adminClubIds = await getUserAdminClubIds(user.id, user.role);
      if (adminClubIds.length === 0) return res.status(403).json({ message: "Access denied" });

      const profileId = Number(req.params.profileId);
      const [profile] = await db.select().from(playerProfiles).where(eq(playerProfiles.id, profileId));
      if (!profile || !adminClubIds.includes(profile.clubId)) return res.status(404).json({ message: "Profile not found" });

      const [memberUser] = await db.select({ id: users.id, fullName: users.fullName, email: users.email }).from(users).where(eq(users.id, profile.userId));

      const memberSessions = await db.select().from(sessions).where(and(
        eq(sessions.clubId, profile.clubId),
        sql`${sessions.status} != 'CANCELLED'`
      ));
      const memberSessionIds = memberSessions.map(s => s.id);

      let signups: any[] = [];
      if (memberSessionIds.length > 0) {
        signups = await db.select().from(sessionSignups).where(and(
          eq(sessionSignups.playerId, profileId),
          inArray(sessionSignups.sessionId, memberSessionIds)
        ));
      }

      const now3 = new Date();
      const memberSessionMap = new Map(memberSessions.map(s => [s.id, s]));
      const isAttended3 = (s: any) => {
        if (["ATTENDED", "PARTIAL_ATTENDANCE", "LATE_ARRIVAL"].includes(s.attendanceStatus)) return true;
        if (["NO_SHOW", "JUSTIFIED_CANCELLATION"].includes(s.attendanceStatus)) return false;
        const sess = memberSessionMap.get(s.sessionId);
        return sess && sess.date < now3 && s.signupStatus === "CONFIRMED";
      };
      const attendedSignups = signups.filter(isAttended3);
      const totalAttendances = attendedSignups.length;
      const totalBookings = signups.length;
      const attendanceRate = totalBookings > 0 ? Math.round((totalAttendances / totalBookings) * 100) : 0;
      const noShowCount = signups.filter(s => s.signupStatus === "CONFIRMED" && ["NO_SHOW", "JUSTIFIED_CANCELLATION"].includes(s.attendanceStatus) && memberSessionMap.get(s.sessionId)?.date! < now3).length;

      const sessionTypeCount = new Map<string, number>();
      for (const s of attendedSignups) {
        const sess = memberSessions.find(ss => ss.id === s.sessionId);
        if (sess) {
          sessionTypeCount.set(sess.matchMode, (sessionTypeCount.get(sess.matchMode) || 0) + 1);
        }
      }
      const mostFrequentSessionType = sessionTypeCount.size > 0 ? Array.from(sessionTypeCount.entries()).sort((a, b) => b[1] - a[1])[0][0] : null;

      const attendedDates = attendedSignups.map(s => {
        const sess = memberSessions.find(ss => ss.id === s.sessionId);
        return sess?.date;
      }).filter(Boolean).sort((a, b) => a!.getTime() - b!.getTime());

      const firstAttendance = attendedDates.length > 0 ? attendedDates[0] : null;
      const lastAttendance = attendedDates.length > 0 ? attendedDates[attendedDates.length - 1] : null;
      const daysSinceLastAttendance = lastAttendance ? Math.floor((Date.now() - lastAttendance!.getTime()) / (1000 * 60 * 60 * 24)) : null;

      let engagementScore = 0;
      if (totalAttendances > 0) {
        const frequencyScore = Math.min(totalAttendances / 20, 1) * 40;
        const recencyScore = daysSinceLastAttendance !== null ? Math.max(0, 1 - daysSinceLastAttendance / 90) * 30 : 0;
        const consistencyScore = attendanceRate / 100 * 30;
        engagementScore = Math.round(frequencyScore + recencyScore + consistencyScore);
      }

      res.json({
        profileId,
        name: memberUser?.fullName || "Unknown",
        email: memberUser?.email || "",
        totalAttendances,
        totalBookings,
        attendanceRate,
        noShowCount,
        mostFrequentSessionType,
        firstAttendance,
        lastAttendance,
        daysSinceLastAttendance,
        engagementScore,
      });
    } catch (err: any) {
      console.error("Error in member analytics:", err);
      res.status(500).json({ message: err.message || "Failed to fetch member analytics" });
    }
  });

  app.get("/api/admin/attendance-analytics/date-detail/:date", requirePremium(clubIdFromSession), async (req, res) => {
    if (!req.isAuthenticated()) return res.sendStatus(401);
    try {
      const user = req.user!;
      const adminClubIds = await getUserAdminClubIds(user.id, user.role);
      if (adminClubIds.length === 0) return res.json([]);

      const dateStr = req.params.date;
      const startOfDay = new Date(dateStr + "T00:00:00.000Z");
      const endOfDay = new Date(dateStr + "T23:59:59.999Z");

      const daySessions = await db.select().from(sessions).where(and(
        inArray(sessions.clubId, adminClubIds),
        gte(sessions.date, startOfDay),
        lte(sessions.date, endOfDay),
        sql`${sessions.status} != 'CANCELLED'`
      ));

      const sessionIds = daySessions.map(s => s.id);
      if (sessionIds.length === 0) return res.json([]);

      const signups = await db.select().from(sessionSignups).where(inArray(sessionSignups.sessionId, sessionIds));
      const clubData = await db.select({ id: clubs.id, name: clubs.name }).from(clubs).where(inArray(clubs.id, adminClubIds));
      const clubMap = new Map(clubData.map(c => [c.id, c]));

      const now4 = new Date();
      const daySessionMap = new Map(daySessions.map(s => [s.id, s]));
      const isAttended4 = (su: any) => {
        if (["ATTENDED", "PARTIAL_ATTENDANCE", "LATE_ARRIVAL"].includes(su.attendanceStatus)) return true;
        if (["NO_SHOW", "JUSTIFIED_CANCELLATION"].includes(su.attendanceStatus)) return false;
        const sess = daySessionMap.get(su.sessionId);
        return sess && sess.date < now4 && su.signupStatus === "CONFIRMED";
      };
      const result = daySessions.map(s => {
        const sessSignups = signups.filter(su => su.sessionId === s.id);
        const attendedCount = sessSignups.filter(isAttended4).length;
        return {
          id: s.id,
          title: s.title,
          date: s.date,
          startTime: s.startTime,
          maxPlayers: s.maxPlayers,
          matchMode: s.matchMode,
          clubName: clubMap.get(s.clubId)?.name || "Unknown",
          totalSignups: sessSignups.length,
          totalAttended: attendedCount,
          fillRate: s.maxPlayers > 0 ? Math.round((attendedCount / s.maxPlayers) * 100) : 0,
        };
      });

      res.json(result);
    } catch (err: any) {
      console.error("Error in date detail:", err);
      res.status(500).json({ message: err.message || "Failed to fetch date detail" });
    }
  });

  app.get("/api/admin/attendance-analytics/distribution/:bucket", requirePremium(clubIdFromSession), async (req, res) => {
    if (!req.isAuthenticated()) return res.sendStatus(401);
    try {
      const user = req.user!;
      const adminClubIds = await getUserAdminClubIds(user.id, user.role);
      if (adminClubIds.length === 0) return res.json([]);

      const { dateFrom, dateTo } = req.query;
      const now = new Date();
      const fromDate = dateFrom ? new Date(dateFrom as string) : new Date(now.getTime() - 30 * 24 * 60 * 60 * 1000);
      const toDate = dateTo ? new Date(dateTo as string) : now;

      const allSessions = await db.select().from(sessions).where(and(
        inArray(sessions.clubId, adminClubIds),
        gte(sessions.date, fromDate),
        lte(sessions.date, toDate),
        sql`${sessions.status} != 'CANCELLED'`
      ));
      const sessionIds = allSessions.map(s => s.id);
      if (sessionIds.length === 0) return res.json([]);

      const allSignups = await db.select().from(sessionSignups).where(inArray(sessionSignups.sessionId, sessionIds));
      const now5 = new Date();
      const distSessionMap = new Map(allSessions.map(s => [s.id, s]));
      const isAttended5 = (s: any) => {
        if (["ATTENDED", "PARTIAL_ATTENDANCE", "LATE_ARRIVAL"].includes(s.attendanceStatus)) return true;
        if (["NO_SHOW", "JUSTIFIED_CANCELLATION"].includes(s.attendanceStatus)) return false;
        const sess = distSessionMap.get(s.sessionId);
        return sess && sess.date < now5 && s.signupStatus === "CONFIRMED";
      };

      const memberCounts = new Map<number, number>();
      for (const s of allSignups) {
        if (isAttended5(s)) {
          memberCounts.set(s.playerId, (memberCounts.get(s.playerId) || 0) + 1);
        }
      }

      const bucket = req.params.bucket;
      const bucketRanges: Record<string, [number, number]> = {
        "1-2": [1, 2],
        "3-5": [3, 5],
        "6-10": [6, 10],
        "11+": [11, Infinity],
      };
      const range = bucketRanges[bucket];
      if (!range) return res.status(400).json({ message: "Invalid bucket" });

      const matchingPlayerIds = Array.from(memberCounts.entries())
        .filter(([, count]) => count >= range[0] && count <= range[1])
        .map(([id]) => id);

      if (matchingPlayerIds.length === 0) return res.json([]);

      const profileData = await db.select({ id: playerProfiles.id, userId: playerProfiles.userId, clubId: playerProfiles.clubId }).from(playerProfiles).where(inArray(playerProfiles.id, matchingPlayerIds));
      const userIds = profileData.map(p => p.userId);
      const userData = userIds.length > 0 ? await db.select({ id: users.id, fullName: users.fullName, email: users.email }).from(users).where(inArray(users.id, userIds)) : [];
      const userMap = new Map(userData.map(u => [u.id, u]));
      const clubData = await db.select({ id: clubs.id, name: clubs.name }).from(clubs).where(inArray(clubs.id, adminClubIds));
      const clubMap = new Map(clubData.map(c => [c.id, c]));

      const result = profileData.map(p => {
        const u = userMap.get(p.userId);
        return {
          profileId: p.id,
          name: u?.fullName || "Unknown",
          email: u?.email || "",
          clubName: clubMap.get(p.clubId)?.name || "Unknown",
          totalAttendances: memberCounts.get(p.id) || 0,
        };
      }).sort((a, b) => b.totalAttendances - a.totalAttendances);

      res.json(result);
    } catch (err: any) {
      console.error("Error in distribution detail:", err);
      res.status(500).json({ message: err.message || "Failed to fetch distribution detail" });
    }
  });

