  async function computeJuniorMatchStats(userId: number) {
    const juniorProfs = await db.select().from(playerProfiles).where(eq(playerProfiles.userId, userId));
    const profileIds = juniorProfs.map(p => p.id);
    if (profileIds.length === 0) return { sessionsAttended: 0, totalSessions: 0, attendancePercent: 0, matchesPlayed: 0, matchesWon: 0, matchesLost: 0, winPercent: 0, setsWon: 0, pointsWon: 0 };

    const signups = await db.select({
      id: sessionSignups.id,
      sessionId: sessionSignups.sessionId,
      playerId: sessionSignups.playerId,
      attendanceStatus: sessionSignups.attendanceStatus,
      signupStatus: sessionSignups.signupStatus,
    }).from(sessionSignups).where(inArray(sessionSignups.playerId, profileIds));

    const confirmedSignups = signups.filter(s => s.signupStatus === "CONFIRMED");

    const sessionMatchCounts = new Map<number, boolean>();
    for (const su of confirmedSignups) {
      if (sessionMatchCounts.has(su.sessionId)) continue;
      const [mc] = await db.select({ count: sql<number>`count(*)::int` }).from(matches).where(
        and(
          eq(matches.sessionId, su.sessionId),
          or(
            eq(matches.teamAPlayer1Id, su.playerId),
            eq(matches.teamAPlayer2Id, su.playerId),
            eq(matches.teamBPlayer1Id, su.playerId),
            eq(matches.teamBPlayer2Id, su.playerId),
          )
        )
      );
      sessionMatchCounts.set(su.sessionId, (mc.count || 0) > 0);
    }

    const attended = confirmedSignups.filter(s =>
      ["ATTENDED", "PARTIAL_ATTENDANCE", "LATE_ARRIVAL"].includes(s.attendanceStatus) ||
      sessionMatchCounts.get(s.sessionId) === true
    ).length;
    const totalSessions = confirmedSignups.length;
    const attendancePercent = totalSessions > 0 ? Math.round((attended / totalSessions) * 100) : 0;

    const allMatches = profileIds.length > 0
      ? await db.select().from(matches).where(
          and(
            eq(matches.isCompleted, true),
            isNull(matches.deletedAt),
            or(
              inArray(matches.teamAPlayer1Id, profileIds),
              inArray(matches.teamAPlayer2Id, profileIds),
              inArray(matches.teamBPlayer1Id, profileIds),
              inArray(matches.teamBPlayer2Id, profileIds),
            )
          )
        )
      : [];

    let matchesPlayed = 0, matchesWon = 0, setsWon = 0, pointsWon = 0;
    const pidSet = new Set(profileIds);
    for (const match of allMatches) {
      if (match.status !== "COMPLETED") continue;
      const hasMultiSets = (match.numberOfSets || 1) > 1 && (match.setsWonA || 0) + (match.setsWonB || 0) > 0;
      const teamAWon = hasMultiSets ? (match.setsWonA || 0) > (match.setsWonB || 0) : (match.scoreA ?? 0) > (match.scoreB ?? 0);
      const isTeamA = pidSet.has(match.teamAPlayer1Id) || (match.teamAPlayer2Id !== null && pidSet.has(match.teamAPlayer2Id));
      matchesPlayed++;
      if ((isTeamA && teamAWon) || (!isTeamA && !teamAWon)) matchesWon++;
      const setScoresArr = (match.setScores as { scoreA: number; scoreB: number }[] | null) || [];
      if (setScoresArr.length > 0) {
        for (const ss of setScoresArr) {
          if (isTeamA) { pointsWon += ss.scoreA; if (ss.scoreA > ss.scoreB) setsWon++; }
          else { pointsWon += ss.scoreB; if (ss.scoreB > ss.scoreA) setsWon++; }
        }
      } else {
        pointsWon += isTeamA ? (match.scoreA ?? 0) : (match.scoreB ?? 0);
        if ((isTeamA && teamAWon) || (!isTeamA && !teamAWon)) setsWon++;
      }
    }

    return {
      sessionsAttended: attended,
      totalSessions,
      attendancePercent,
      matchesPlayed,
      matchesWon,
      matchesLost: matchesPlayed - matchesWon,
      winPercent: matchesPlayed > 0 ? Math.round((matchesWon / matchesPlayed) * 100) : 0,
      setsWon,
      pointsWon,
    };
  }

  async function recalculateJuniorOverall(userId: number) {
    const allSkills = await db.select().from(juniorSkills);
    const progress = await db.select().from(juniorSkillProgress).where(eq(juniorSkillProgress.childId, userId));

    if (allSkills.length === 0) return;
    const totalPercentage = progress.reduce((sum, p) => sum + p.percentage, 0);
    const overallPercent = Math.round(totalPercentage / allSkills.length);

    const profiles = await db.select().from(juniorProfiles).where(eq(juniorProfiles.userId, userId));
    for (const profile of profiles) {
      await db.update(juniorProfiles).set({
        overallSkillPercentage: overallPercent,
        updatedAt: new Date(),
      }).where(eq(juniorProfiles.id, profile.id));
    }
  }

  app.get("/api/junior-session-history/:userId", async (req, res) => {
    if (!req.isAuthenticated()) return res.status(401).json({ message: "Not authenticated" });
    try {
      const userId = Number(req.params.userId);
      const currentUser = req.user as any;
      const targetUser = await db.select().from(users).where(eq(users.id, userId)).then(r => r[0]);
      if (!targetUser) return res.status(404).json({ message: "User not found" });

      const isOwner = currentUser.role === "OWNER";
      const isParent = targetUser.parentUserId === currentUser.id;
      const isSelf = currentUser.id === userId;
      const adminClubs = await db.select({ clubId: playerProfiles.clubId }).from(playerProfiles).where(and(eq(playerProfiles.userId, currentUser.id), inArray(playerProfiles.clubRole, ["ADMIN", "OWNER"])));
      const adminClubIds = new Set(adminClubs.map(c => c.clubId));
      if (!isOwner && !isParent && !isSelf && adminClubIds.size === 0) return res.status(403).json({ message: "Forbidden" });

      const juniorProfs = await db.select().from(playerProfiles).where(eq(playerProfiles.userId, userId));
      const profileIds = juniorProfs.map(p => p.id);
      if (profileIds.length === 0) return res.json([]);

      const signupRows = await db.select({
        signupId: sessionSignups.id,
        sessionId: sessionSignups.sessionId,
        signupStatus: sessionSignups.signupStatus,
        attendanceStatus: sessionSignups.attendanceStatus,
        playerId: sessionSignups.playerId,
      }).from(sessionSignups).where(inArray(sessionSignups.playerId, profileIds));

      const sessionIds = [...new Set(signupRows.map(s => s.sessionId))];
      if (sessionIds.length === 0) return res.json([]);

      const sessionRows = await db.select({
        id: sessions.id, title: sessions.title, date: sessions.date, startTime: sessions.startTime,
        durationMinutes: sessions.durationMinutes, status: sessions.status, clubId: sessions.clubId,
        sessionType: sessions.sessionType, courtsAvailable: sessions.courtsAvailable,
      }).from(sessions).where(inArray(sessions.id, sessionIds));

      const clubIds = [...new Set(sessionRows.map(s => s.clubId))];
      const clubRows = await db.select({ id: clubs.id, name: clubs.name }).from(clubs).where(inArray(clubs.id, clubIds));
      const clubMap = Object.fromEntries(clubRows.map(c => [c.id, c.name]));

      const allMatches = await db.select().from(matches).where(
        and(
          inArray(matches.sessionId, sessionIds),
          eq(matches.isCompleted, true),
          isNull(matches.deletedAt),
          or(
            inArray(matches.teamAPlayer1Id, profileIds),
            inArray(matches.teamAPlayer2Id, profileIds),
            inArray(matches.teamBPlayer1Id, profileIds),
            inArray(matches.teamBPlayer2Id, profileIds),
          )
        )
      );

      const partnerIds = new Set<number>();
      for (const m of allMatches) {
        [m.teamAPlayer1Id, m.teamAPlayer2Id, m.teamBPlayer1Id, m.teamBPlayer2Id].forEach(pid => {
          if (pid && !new Set(profileIds).has(pid)) partnerIds.add(pid);
        });
      }
      let partnerProfileMap: Record<number, { fullName: string }> = {};
      if (partnerIds.size > 0) {
        const partnerProfiles = await db.select({ id: playerProfiles.id, userId: playerProfiles.userId }).from(playerProfiles).where(inArray(playerProfiles.id, [...partnerIds]));
        const partnerUserIds = partnerProfiles.map(p => p.userId);
        if (partnerUserIds.length > 0) {
          const partnerUsers = await db.select({ id: users.id, fullName: users.fullName }).from(users).where(inArray(users.id, partnerUserIds));
          const userMap = Object.fromEntries(partnerUsers.map(u => [u.id, u.fullName]));
          for (const pp of partnerProfiles) {
            partnerProfileMap[pp.id] = { fullName: userMap[pp.userId] || "Unknown" };
          }
        }
      }

      const pidSet = new Set(profileIds);
      const matchesBySession: Record<number, any[]> = {};
      for (const m of allMatches) {
        const isTeamA = pidSet.has(m.teamAPlayer1Id) || (m.teamAPlayer2Id !== null && pidSet.has(m.teamAPlayer2Id));
        const hasMultiSets = (m.numberOfSets || 1) > 1 && (m.setsWonA || 0) + (m.setsWonB || 0) > 0;
        const teamAWon = hasMultiSets ? (m.setsWonA || 0) > (m.setsWonB || 0) : (m.scoreA ?? 0) > (m.scoreB ?? 0);
        const won = (isTeamA && teamAWon) || (!isTeamA && !teamAWon);
        const partnerId = isTeamA
          ? (pidSet.has(m.teamAPlayer1Id) ? m.teamAPlayer2Id : m.teamAPlayer1Id)
          : (pidSet.has(m.teamBPlayer1Id) ? m.teamBPlayer2Id : m.teamBPlayer1Id);
        const opp1 = isTeamA ? m.teamBPlayer1Id : m.teamAPlayer1Id;
        const opp2 = isTeamA ? m.teamBPlayer2Id : m.teamAPlayer2Id;
        if (!matchesBySession[m.sessionId]) matchesBySession[m.sessionId] = [];
        matchesBySession[m.sessionId].push({
          id: m.id,
          won,
          scoreA: m.scoreA, scoreB: m.scoreB,
          setsWonA: m.setsWonA, setsWonB: m.setsWonB,
          setScores: m.setScores,
          isTeamA,
          partner: partnerId ? partnerProfileMap[partnerId]?.fullName || null : null,
          opponents: [opp1 ? partnerProfileMap[opp1]?.fullName || "Player" : null, opp2 ? partnerProfileMap[opp2]?.fullName || null : null].filter(Boolean),
          completedAt: m.completedAt,
        });
      }

      const signupBySession: Record<number, any> = {};
      for (const s of signupRows) {
        signupBySession[s.sessionId] = s;
      }

      const result = sessionRows
        .sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime())
        .map(s => {
          const signup = signupBySession[s.id];
          const sessionMatches = matchesBySession[s.id] || [];
          const wins = sessionMatches.filter((m: any) => m.won).length;
          const losses = sessionMatches.length - wins;
          return {
            sessionId: s.id,
            title: s.title,
            date: s.date,
            startTime: s.startTime,
            durationMinutes: s.durationMinutes,
            status: s.status,
            clubName: clubMap[s.clubId] || "Unknown",
            attendanceStatus: signup?.attendanceStatus || "NOT_ATTENDED",
            signupStatus: signup?.signupStatus || "CONFIRMED",
            matchesPlayed: sessionMatches.length,
            wins,
            losses,
            matches: sessionMatches,
          };
        });

      res.json(result);
    } catch (err: any) {
      res.status(500).json({ message: err.message });
    }
  });

  app.get("/api/junior-rankings/:clubId", async (req, res) => {
    if (!req.isAuthenticated()) return res.status(401).json({ message: "Not authenticated" });
    try {
      const clubId = Number(req.params.clubId);

      const allJuniorUsers = await db.select({ id: users.id, fullName: users.fullName, profilePictureUrl: users.profilePictureUrl }).from(users).where(eq(users.isJunior, true));
      if (allJuniorUsers.length === 0) return res.json([]);
      const juniorUserIds = allJuniorUsers.map(u => u.id);
      const userMap = Object.fromEntries(allJuniorUsers.map(u => [u.id, u]));

      const clubPlayerProfs = await db.select().from(playerProfiles).where(
        and(eq(playerProfiles.clubId, clubId), inArray(playerProfiles.userId, juniorUserIds))
      );
      const playerProfileIdMap = Object.fromEntries(clubPlayerProfs.map(p => [p.userId, p.id]));
      const juniorProfilesList = await db.select().from(juniorProfiles).where(eq(juniorProfiles.clubId, clubId));
      const juniorProfileMap = Object.fromEntries(juniorProfilesList.map(p => [p.userId, p]));

      const juniorIdsInClub = new Set<number>();
      for (const pp of clubPlayerProfs) juniorIdsInClub.add(pp.userId);
      for (const jp of juniorProfilesList) juniorIdsInClub.add(jp.userId);

      const targetUserIds = Array.from(juniorIdsInClub);
      if (targetUserIds.length === 0) return res.json([]);

      const allAchievements = await db.select().from(juniorAchievements).where(inArray(juniorAchievements.userId, targetUserIds));
      const achievementsMap: Record<number, any[]> = {};
      for (const ach of allAchievements) {
        if (!achievementsMap[ach.userId]) achievementsMap[ach.userId] = [];
        achievementsMap[ach.userId].push(ach);
      }

      const statsResults = await Promise.all(targetUserIds.map(async (uid) => ({ userId: uid, stats: await computeJuniorMatchStats(uid) })));
      const matchStatsMap: Record<number, any> = {};
      for (const { userId: uid, stats } of statsResults) matchStatsMap[uid] = stats;

      const existingRankings = await db.select().from(juniorRankings).where(eq(juniorRankings.clubId, clubId));
      const existingMap = Object.fromEntries(existingRankings.map(r => [r.userId, r]));

      const scored = targetUserIds.map(uid => {
        const jp = juniorProfileMap[uid];
        const ms = matchStatsMap[uid] || { attendancePercent: 0, winPercent: 0, matchesPlayed: 0, totalSessions: 0 };
        const skillPct = jp?.overallSkillPercentage || 0;
        const attendPct = ms.totalSessions > 0 ? ms.attendancePercent : (jp?.attendancePercentage || 0);
        const effort = jp?.effortRating || 0;
        const coach = jp?.coachRating || 0;
        const score = (skillPct * 0.5) + (attendPct * 0.2) + (effort * 4) + (coach * 2)
          + (ms.matchesPlayed > 0 ? ms.winPercent * 0.15 : 0) + Math.min(ms.matchesPlayed * 0.5, 10);
        return { userId: uid, skillPct, attendPct, effort, score };
      }).sort((a, b) => b.score - a.score);

      const result = scored.map((s, i) => ({
        id: existingMap[s.userId]?.id || i + 1,
        userId: s.userId,
        clubId,
        playerProfileId: playerProfileIdMap[s.userId] || null,
        overallSkillPercent: s.skillPct,
        attendancePercent: s.attendPct,
        effortRating: s.effort,
        consistencyScore: matchStatsMap[s.userId]?.matchesPlayed || 0,
        rankPosition: i + 1,
        previousPosition: existingMap[s.userId]?.rankPosition || 0,
        user: userMap[s.userId] || null,
        achievements: achievementsMap[s.userId] || [],
        matchStats: matchStatsMap[s.userId] || null,
      }));

      res.json(result);
    } catch (err: any) {
      res.status(500).json({ message: err.message });
    }
  });

  app.post("/api/junior-rankings/recalculate/:clubId", async (req, res) => {
    if (!req.isAuthenticated()) return res.status(401).json({ message: "Not authenticated" });
    try {
      const isAdmin = req.user!.role === "OWNER" || req.user!.role === "ADMIN";
      if (!isAdmin) return res.status(403).json({ message: "Admin access required" });

      const clubId = Number(req.params.clubId);
      const profiles = await db.select().from(juniorProfiles).where(eq(juniorProfiles.clubId, clubId));

      const scoredPromises = profiles.map(async (p) => {
        const realStats = await computeJuniorMatchStats(p.userId);
        const attendPct = realStats.totalSessions > 0 ? realStats.attendancePercent : p.attendancePercentage;
        const winBonus = realStats.matchesPlayed > 0 ? realStats.winPercent * 0.15 : 0;
        const matchVolume = Math.min(realStats.matchesPlayed * 0.5, 10);

        return {
          userId: p.userId,
          score: (p.overallSkillPercentage * 0.5) + (attendPct * 0.2) + (p.effortRating * 4) + (p.coachRating * 2) + winBonus + matchVolume,
          realStats,
          attendPct,
        };
      });
      const scored = (await Promise.all(scoredPromises)).sort((a, b) => b.score - a.score);

      for (let i = 0; i < scored.length; i++) {
        const { userId, realStats, attendPct } = scored[i];
        const profile = profiles.find(p => p.userId === userId)!;
        const [existing] = await db.select().from(juniorRankings).where(and(eq(juniorRankings.userId, userId), eq(juniorRankings.clubId, clubId)));

        const rankData = {
          overallSkillPercent: profile.overallSkillPercentage,
          attendancePercent: attendPct,
          effortRating: profile.effortRating,
          consistencyScore: realStats.matchesPlayed,
          rankPosition: i + 1,
          previousPosition: existing?.rankPosition || 0,
          updatedAt: new Date(),
        };

        if (existing) {
          await db.update(juniorRankings).set(rankData).where(eq(juniorRankings.id, existing.id));
        } else {
          await db.insert(juniorRankings).values({ userId, clubId, ...rankData });
        }
      }

      res.json({ success: true, count: scored.length });
    } catch (err: any) {
      res.status(500).json({ message: err.message });
    }
  });

