  app.post("/api/admin/ai-report/finances", requirePremium(clubIdFromSession), async (req, res) => {
    if (!req.isAuthenticated()) return res.sendStatus(401);
    try {
      const user = req.user!;
      const { clubId } = req.body;
      if (!clubId) return res.status(400).json({ message: "clubId required" });

      const accessibleClubs = await getCoachClubAccess(req);
      if (!accessibleClubs.includes(Number(clubId))) return res.status(403).json({ message: "Not authorized" });

      const now = new Date();
      const thirtyDaysAgo = new Date(now.getTime() - 30 * 24 * 60 * 60 * 1000);

      const allSessions = await db.select({ id: sessions.id, date: sessions.date, title: sessions.title })
        .from(sessions).where(and(eq(sessions.clubId, Number(clubId)), gte(sessions.date, thirtyDaysAgo), lte(sessions.date, now)));
      const sessionIds = allSessions.map(s => s.id);

      const signups = sessionIds.length > 0
        ? await db.select({ fee: sessionSignups.fee, paymentStatus: sessionSignups.paymentStatus }).from(sessionSignups).where(and(inArray(sessionSignups.sessionId, sessionIds), eq(sessionSignups.signupStatus, "CONFIRMED")))
        : [];

      const totalIncome = signups.reduce((s, r) => s + (r.fee || 0), 0);
      const paidAmount = signups.filter(r => r.paymentStatus === "PAID").reduce((s, r) => s + (r.fee || 0), 0);
      const pendingAmount = signups.filter(r => r.paymentStatus !== "PAID").reduce((s, r) => s + (r.fee || 0), 0);
      const collectionRate = totalIncome > 0 ? ((paidAmount / totalIncome) * 100).toFixed(1) : "0";

      const expensesAll = await db.select({ amount: expenses.amount }).from(expenses)
        .where(and(eq(expenses.clubId, Number(clubId)), gte(expenses.createdAt, thirtyDaysAgo)));
      const totalExpenses = expensesAll.reduce((s, e) => s + (e.amount || 0), 0);

      const creditEntries = await db.select({ amount: creditLedger.amount }).from(creditLedger)
        .where(and(eq(creditLedger.clubId, Number(clubId)), gte(creditLedger.createdAt, thirtyDaysAgo)));
      const creditsIssued = creditEntries.filter(c => c.amount > 0).reduce((s, c) => s + c.amount, 0);
      const creditsUsed = creditEntries.filter(c => c.amount < 0).reduce((s, c) => s + Math.abs(c.amount), 0);

      const donationsAll = await db.select({ amount: donations.amount, status: donations.status }).from(donations);
      const donationsReceived = donationsAll.filter(d => d.status === "RECEIVED").reduce((s, d) => s + d.amount, 0);

      let aiSummary = "";
      try {
        const OpenAI = (await import("openai")).default;
        const openai = new OpenAI({ apiKey: process.env.AI_INTEGRATIONS_OPENAI_API_KEY, baseURL: process.env.AI_INTEGRATIONS_OPENAI_BASE_URL });
        const prompt = `You are a financial analyst for a sports club. Analyze these financial metrics from the last 30 days and provide actionable insights.

Financial Data:
- Total Session Income: £${(totalIncome / 100).toFixed(2)}
- Collected (Paid): £${(paidAmount / 100).toFixed(2)}
- Outstanding (Unpaid): £${(pendingAmount / 100).toFixed(2)}
- Collection Rate: ${collectionRate}%
- Total Sessions: ${allSessions.length}
- Total Signups: ${signups.length}
- Average Fee per Player: £${signups.length > 0 ? ((totalIncome / signups.length) / 100).toFixed(2) : "0.00"}
- General Expenses: £${(totalExpenses / 100).toFixed(2)}
- Net Revenue: £${((totalIncome - totalExpenses) / 100).toFixed(2)}
- Credits Issued: £${(creditsIssued / 100).toFixed(2)}
- Credits Used: £${(creditsUsed / 100).toFixed(2)}
- Donations Received: £${(donationsReceived / 100).toFixed(2)}

Provide a concise report (200-250 words) covering:
1. **Financial Health Summary** — overall position
2. **Collection Performance** — how well payments are being collected, concerns
3. **Revenue Trends** — observations on session income vs expenses
4. **Recommendations** — 2-3 actionable steps to improve finances`;

        const completion = await openai.chat.completions.create({
          model: "gpt-4o-mini",
          messages: [{ role: "user", content: prompt }],
          max_tokens: 500,
        });
        aiSummary = completion.choices[0]?.message?.content || "Unable to generate financial report.";
      } catch (aiErr: any) {
        console.error("AI finance report error:", aiErr);
        aiSummary = `Financial Summary (Last 30 Days)\n\nTotal Income: £${(totalIncome / 100).toFixed(2)}\nCollected: £${(paidAmount / 100).toFixed(2)} (${collectionRate}%)\nOutstanding: £${(pendingAmount / 100).toFixed(2)}\nExpenses: £${(totalExpenses / 100).toFixed(2)}\nNet Revenue: £${((totalIncome - totalExpenses) / 100).toFixed(2)}\n\n${Number(collectionRate) < 80 ? "Warning: Collection rate is below 80%. Consider sending payment reminders." : "Collection rate is healthy."}`;
      }

      const [report] = await db.insert(generatedReports).values({
        createdBy: user.id, clubId: Number(clubId),
        dateRangeStart: thirtyDaysAgo, dateRangeEnd: now,
        squadFilter: "finances", aiSummary,
      }).returning();

      res.json({ report, stats: { totalIncome, paidAmount, pendingAmount, collectionRate, totalExpenses, netRevenue: totalIncome - totalExpenses, creditsIssued, creditsUsed, donationsReceived, sessionCount: allSessions.length, signupCount: signups.length } });
    } catch (err: any) {
      console.error("Error generating finance report:", err);
      res.status(500).json({ message: err.message });
    }
  });

  app.post("/api/admin/ai-report/matches", requirePremium(clubIdFromSession), async (req, res) => {
    if (!req.isAuthenticated()) return res.sendStatus(401);
    try {
      const user = req.user!;
      const { clubId } = req.body;
      if (!clubId) return res.status(400).json({ message: "clubId required" });

      const accessibleClubs = await getCoachClubAccess(req);
      if (!accessibleClubs.includes(Number(clubId))) return res.status(403).json({ message: "Not authorized" });

      const now = new Date();
      const thirtyDaysAgo = new Date(now.getTime() - 30 * 24 * 60 * 60 * 1000);

      const recentSessions = await db.select({ id: sessions.id, title: sessions.title, date: sessions.date })
        .from(sessions).where(and(eq(sessions.clubId, Number(clubId)), gte(sessions.date, thirtyDaysAgo), lte(sessions.date, now)));
      const sessionIds = recentSessions.map(s => s.id);

      const allMatches = sessionIds.length > 0
        ? await db.select().from(matches).where(inArray(matches.sessionId, sessionIds))
        : [];

      const completedMatches = allMatches.filter(m => m.status === "COMPLETED");
      const liveMatches = allMatches.filter(m => m.status === "LIVE");
      const queuedMatches = allMatches.filter(m => m.status === "QUEUED");

      const playerMatchCounts = new Map<number, number>();
      for (const m of completedMatches) {
        const playerIds = [m.teamAPlayer1Id, m.teamAPlayer2Id, m.teamBPlayer1Id, m.teamBPlayer2Id].filter(Boolean) as number[];
        for (const pid of playerIds) {
          playerMatchCounts.set(pid, (playerMatchCounts.get(pid) || 0) + 1);
        }
      }
      const uniquePlayers = playerMatchCounts.size;
      const topPlayersEntries = [...playerMatchCounts.entries()].sort((a, b) => b[1] - a[1]).slice(0, 5);
      const topPlayerIds = topPlayersEntries.map(e => e[0]);
      const topPlayerProfiles = topPlayerIds.length > 0
        ? await db.select({ id: playerProfiles.id, userId: playerProfiles.userId }).from(playerProfiles).where(inArray(playerProfiles.id, topPlayerIds))
        : [];
      const topUserIds = topPlayerProfiles.map(p => p.userId);
      const topPlayerUsers = topUserIds.length > 0 ? await db.select({ id: users.id, fullName: users.fullName }).from(users).where(inArray(users.id, topUserIds)) : [];
      const topPlayers = topPlayersEntries.map(([profileId, count]) => {
        const profile = topPlayerProfiles.find(p => p.id === profileId);
        const userName = profile ? topPlayerUsers.find(u => u.id === profile.userId)?.fullName : undefined;
        return { name: userName || "Unknown", matchCount: count };
      });

      const doublesMatches = completedMatches.filter(m => m.teamAPlayer2Id || m.teamBPlayer2Id).length;
      const singlesMatches = completedMatches.length - doublesMatches;
      const avgMatchesPerSession = recentSessions.length > 0 ? (completedMatches.length / recentSessions.length).toFixed(1) : "0";

      let aiSummary = "";
      try {
        const OpenAI = (await import("openai")).default;
        const openai = new OpenAI({ apiKey: process.env.AI_INTEGRATIONS_OPENAI_API_KEY, baseURL: process.env.AI_INTEGRATIONS_OPENAI_BASE_URL });
        const prompt = `You are a sports analytics coach for a racket sports club. Analyze these match statistics from the last 30 days and provide coaching insights.

Match Data:
- Total Matches Played: ${completedMatches.length}
- Currently Live: ${liveMatches.length}
- In Queue: ${queuedMatches.length}
- Sessions with Matches: ${recentSessions.length}
- Average Matches per Session: ${avgMatchesPerSession}
- Doubles Matches: ${doublesMatches}
- Singles Matches: ${singlesMatches}
- Unique Players: ${uniquePlayers}
- Most Active Players: ${topPlayers.map(p => `${p.name} (${p.matchCount} matches)`).join(", ")}

Provide a concise report (200-250 words) covering:
1. **Match Activity Summary** — volume and player engagement
2. **Player Participation** — how well-distributed match play is
3. **Match Format Analysis** — doubles vs singles balance
4. **Recommendations** — suggestions for improving match organisation and player experience`;

        const completion = await openai.chat.completions.create({
          model: "gpt-4o-mini",
          messages: [{ role: "user", content: prompt }],
          max_tokens: 500,
        });
        aiSummary = completion.choices[0]?.message?.content || "Unable to generate match report.";
      } catch (aiErr: any) {
        console.error("AI match report error:", aiErr);
        aiSummary = `Match Summary (Last 30 Days)\n\nTotal Completed: ${completedMatches.length}\nSessions: ${recentSessions.length}\nAvg per Session: ${avgMatchesPerSession}\nDoubles: ${doublesMatches} | Singles: ${singlesMatches}\nUnique Players: ${uniquePlayers}\n\nMost Active: ${topPlayers.map(p => `${p.name} (${p.matchCount})`).join(", ")}`;
      }

      const [report] = await db.insert(generatedReports).values({
        createdBy: user.id, clubId: Number(clubId),
        dateRangeStart: thirtyDaysAgo, dateRangeEnd: now,
        squadFilter: "matches", aiSummary,
      }).returning();

      res.json({ report, stats: { totalMatches: allMatches.length, completedMatches: completedMatches.length, liveMatches: liveMatches.length, queuedMatches: queuedMatches.length, doublesMatches, singlesMatches, uniquePlayers, avgMatchesPerSession, topPlayers, sessionCount: recentSessions.length } });
    } catch (err: any) {
      console.error("Error generating match report:", err);
      res.status(500).json({ message: err.message });
    }
  });

  app.post("/api/admin/ai-report/attendance", requirePremium(clubIdFromSession), async (req, res) => {
    if (!req.isAuthenticated()) return res.sendStatus(401);
    try {
      const user = req.user!;
      const { clubId } = req.body;
      if (!clubId) return res.status(400).json({ message: "clubId required" });

      const accessibleClubs = await getCoachClubAccess(req);
      if (!accessibleClubs.includes(Number(clubId))) return res.status(403).json({ message: "Not authorized" });

      const now = new Date();
      const thirtyDaysAgo = new Date(now.getTime() - 30 * 24 * 60 * 60 * 1000);

      const recentSessions = await db.select({ id: sessions.id, title: sessions.title, date: sessions.date, maxPlayers: sessions.maxPlayers })
        .from(sessions).where(and(eq(sessions.clubId, Number(clubId)), gte(sessions.date, thirtyDaysAgo), lte(sessions.date, now), sql`${sessions.status} != 'CANCELLED'`));
      const sessionIds = recentSessions.map(s => s.id);

      const allSignups = sessionIds.length > 0
        ? await db.select().from(sessionSignups).where(inArray(sessionSignups.sessionId, sessionIds))
        : [];

      const confirmedSignups = allSignups.filter(s => s.signupStatus === "CONFIRMED");
      const attended = allSignups.filter(s => ["ATTENDED", "PARTIAL_ATTENDANCE", "LATE_ARRIVAL"].includes(s.attendanceStatus || ""));
      const noShows = allSignups.filter(s => s.attendanceStatus === "NO_SHOW");
      const attendanceRate = confirmedSignups.length > 0 ? ((attended.length / confirmedSignups.length) * 100).toFixed(1) : "0";
      const noShowRate = confirmedSignups.length > 0 ? ((noShows.length / confirmedSignups.length) * 100).toFixed(1) : "0";

      const uniqueAttendees = new Set(attended.map(s => s.playerId)).size;
      const avgPerSession = recentSessions.length > 0 ? (confirmedSignups.length / recentSessions.length).toFixed(1) : "0";

      const totalCapacity = recentSessions.reduce((s, sess) => s + (sess.maxPlayers || 0), 0);
      const fillRate = totalCapacity > 0 ? ((confirmedSignups.length / totalCapacity) * 100).toFixed(1) : "0";

      const memberProfiles = await db.select({ userId: playerProfiles.userId }).from(playerProfiles)
        .where(and(eq(playerProfiles.clubId, Number(clubId)), eq(playerProfiles.membershipStatus, "APPROVED")));
      const totalMembers = memberProfiles.length;
      const activeMembers = new Set(confirmedSignups.map(s => s.playerId)).size;
      const inactivePercent = totalMembers > 0 ? (((totalMembers - activeMembers) / totalMembers) * 100).toFixed(1) : "0";

      let aiSummary = "";
      try {
        const OpenAI = (await import("openai")).default;
        const openai = new OpenAI({ apiKey: process.env.AI_INTEGRATIONS_OPENAI_API_KEY, baseURL: process.env.AI_INTEGRATIONS_OPENAI_BASE_URL });
        const prompt = `You are a club management analyst for a sports club. Analyze these attendance metrics from the last 30 days and provide insights.

Attendance Data:
- Total Sessions: ${recentSessions.length}
- Total Confirmed Signups: ${confirmedSignups.length}
- Attended: ${attended.length} (${attendanceRate}%)
- No-Shows: ${noShows.length} (${noShowRate}%)
- Unique Attendees: ${uniqueAttendees}
- Average Players per Session: ${avgPerSession}
- Session Fill Rate: ${fillRate}%
- Total Club Members: ${totalMembers}
- Active Members (attended ≥1 session): ${activeMembers}
- Inactive Members: ${totalMembers - activeMembers} (${inactivePercent}%)

Provide a concise report (200-250 words) covering:
1. **Attendance Health** — overall engagement levels
2. **No-Show Analysis** — impact and potential causes
3. **Member Activity** — active vs inactive ratio, re-engagement ideas
4. **Recommendations** — 2-3 actionable steps to improve attendance`;

        const completion = await openai.chat.completions.create({
          model: "gpt-4o-mini",
          messages: [{ role: "user", content: prompt }],
          max_tokens: 500,
        });
        aiSummary = completion.choices[0]?.message?.content || "Unable to generate attendance report.";
      } catch (aiErr: any) {
        console.error("AI attendance report error:", aiErr);
        aiSummary = `Attendance Summary (Last 30 Days)\n\nSessions: ${recentSessions.length}\nConfirmed: ${confirmedSignups.length}\nAttended: ${attended.length} (${attendanceRate}%)\nNo-Shows: ${noShows.length} (${noShowRate}%)\nFill Rate: ${fillRate}%\nActive Members: ${activeMembers}/${totalMembers}\nInactive: ${inactivePercent}%\n\n${Number(noShowRate) > 15 ? "Warning: No-show rate is above 15%. Consider implementing a no-show policy." : "No-show rate is acceptable."}`;
      }

      const [report] = await db.insert(generatedReports).values({
        createdBy: user.id, clubId: Number(clubId),
        dateRangeStart: thirtyDaysAgo, dateRangeEnd: now,
        squadFilter: "attendance", aiSummary,
      }).returning();

      res.json({ report, stats: { sessionCount: recentSessions.length, confirmedSignups: confirmedSignups.length, attended: attended.length, attendanceRate, noShows: noShows.length, noShowRate, uniqueAttendees, avgPerSession, fillRate, totalMembers, activeMembers, inactivePercent } });
    } catch (err: any) {
      console.error("Error generating attendance report:", err);
      res.status(500).json({ message: err.message });
    }
  });

  // === PARENT CHILD AI REPORT & PDF ===

  app.post("/api/juniors/:childId/report/generate", requirePremium(clubIdFromSession), async (req, res) => {
    if (!req.isAuthenticated()) return res.sendStatus(401);
    try {
      const childId = Number(req.params.childId);
      const user = req.user!;

      const [child] = await db.select().from(users).where(eq(users.id, childId));
      if (!child) return res.status(404).json({ message: "Child not found" });

      let profiles = await db.select().from(juniorProfiles).where(eq(juniorProfiles.userId, childId));
      let profile = profiles[0];

      if (!profile) {
        let autoClubId: number | null = null;
        if (child.parentUserId) {
          const parentClubs = await db.select({ clubId: playerProfiles.clubId }).from(playerProfiles)
            .where(and(eq(playerProfiles.userId, child.parentUserId), eq(playerProfiles.membershipStatus, "APPROVED")));
          if (parentClubs.length > 0) autoClubId = parentClubs[0].clubId;
        }
        if (!autoClubId) {
          const userClubs = await db.select({ clubId: playerProfiles.clubId }).from(playerProfiles)
            .where(and(eq(playerProfiles.userId, user.id), eq(playerProfiles.membershipStatus, "APPROVED")));
          if (userClubs.length > 0) autoClubId = userClubs[0].clubId;
        }
        if (!autoClubId) return res.status(404).json({ message: "No club found to create junior profile" });

        const [newProfile] = await db.insert(juniorProfiles).values({
          userId: childId,
          clubId: autoClubId,
          juniorLevel: "BEGINNER",
          overallSkillPercentage: 0,
          attendancePercentage: 0,
          effortRating: 0,
          coachRating: 0,
        }).returning();
        profile = newProfile;
      }

      if (child.parentUserId !== user.id && user.role !== "OWNER") {
        const adminProfiles = await db.select({ clubId: playerProfiles.clubId }).from(playerProfiles)
          .where(and(eq(playerProfiles.userId, user.id), eq(playerProfiles.clubId, profile.clubId), or(eq(playerProfiles.clubRole, "ADMIN"), eq(playerProfiles.clubRole, "OWNER"))));
        if (adminProfiles.length === 0) return res.status(403).json({ message: "Not authorized" });
      }

      const categories = await db.select().from(juniorSkillCategories).orderBy(juniorSkillCategories.displayOrder);
      const skills = await db.select().from(juniorSkills);
      const progress = await db.select().from(juniorSkillProgress).where(eq(juniorSkillProgress.childId, childId));
      const history = await db.select().from(juniorProgressHistory).where(eq(juniorProgressHistory.childId, childId)).orderBy(desc(juniorProgressHistory.createdAt)).limit(30);

      const categoryData = categories.map(cat => {
        const catSkills = skills.filter(s => s.categoryId === cat.id);
        const skillData = catSkills.map(sk => {
          const prog = progress.find(p => p.skillId === sk.id);
          return { name: sk.name, percentage: prog?.percentage || 0, priority: prog?.priority || false, comment: prog?.comment || null };
        });
        const avgScore = skillData.length > 0 ? Math.round(skillData.reduce((s, d) => s + d.percentage, 0) / skillData.length) : 0;
        return { category: cat.name, avgScore, skills: skillData };
      });

      const weakest3 = categoryData.flatMap(c => c.skills.map(s => ({ ...s, category: c.category })))
        .filter(s => s.percentage > 0).sort((a, b) => a.percentage - b.percentage).slice(0, 3);
      const strongest3 = categoryData.flatMap(c => c.skills.map(s => ({ ...s, category: c.category })))
        .filter(s => s.percentage > 0).sort((a, b) => b.percentage - a.percentage).slice(0, 3);
      const prioritySkills = categoryData.flatMap(c => c.skills.filter(s => s.priority).map(s => ({ ...s, category: c.category })));

      const coachNotes = categoryData.flatMap(c => c.skills.filter(s => s.comment).map(s => ({ skill: s.name, category: c.category, note: s.comment })));

      const recentImprovement = history.length >= 2
        ? history[0].newPercentage - history[history.length - 1].newPercentage
        : 0;

      let aiSummary = "";
      try {
        const OpenAI = (await import("openai")).default;
        const openai = new OpenAI({ apiKey: process.env.AI_INTEGRATIONS_OPENAI_API_KEY, baseURL: process.env.AI_INTEGRATIONS_OPENAI_BASE_URL });
        const prompt = `You are a friendly, encouraging sports coach writing a progress report for a parent about their child's sporting development. Write in a warm, professional tone that parents will appreciate.

Player: ${child.fullName}
Age: ${child.dateOfBirth ? Math.floor((Date.now() - new Date(child.dateOfBirth).getTime()) / (365.25 * 24 * 60 * 60 * 1000)) : "Unknown"}
Level: ${profile.juniorLevel.replace(/_/g, " ")}
Overall Skill: ${profile.overallSkillPercentage}%
Attendance: ${profile.attendancePercentage}%
Effort Rating: ${profile.effortRating}/10
Coach Rating: ${profile.coachRating}/10

Category Performance:
${categoryData.map(c => `  ${c.category}: ${c.avgScore}%`).join("\n")}

Strongest Skills: ${strongest3.map(s => `${s.name} (${s.category}): ${s.percentage}%`).join(", ")}
Weakest Skills: ${weakest3.map(s => `${s.name} (${s.category}): ${s.percentage}%`).join(", ")}
Priority Focus Areas: ${prioritySkills.length > 0 ? prioritySkills.map(s => `${s.name} (${s.category})`).join(", ") : "None set"}
Recent Progress Trend: ${recentImprovement > 0 ? `Improving (+${recentImprovement}%)` : recentImprovement < 0 ? `Needs attention (${recentImprovement}%)` : "Steady"}
${coachNotes.length > 0 ? `\nCoach Notes on Skills:\n${coachNotes.map(n => `  ${n.skill} (${n.category}): "${n.note}"`).join("\n")}` : ""}

Write a comprehensive report with these sections:
1. **Overall Summary** (2-3 sentences about where the player is in their journey)
2. **Strengths** (what they're doing well, be specific and encouraging)
3. **Areas for Development** (constructive, positive framing of weaknesses)
4. **Coach Recommendations** (2-3 specific things the player should focus on at home or in practice, incorporating any coach notes provided above)
5. **Next Steps** (what level they're working towards and what it takes to get there)

Keep it to about 300 words. Be encouraging but honest.`;

        const completion = await openai.chat.completions.create({
          model: "gpt-4o-mini",
          messages: [{ role: "user", content: prompt }],
          max_tokens: 600,
        });
        aiSummary = completion.choices[0]?.message?.content || "Unable to generate report.";
      } catch (aiErr: any) {
        console.error("AI generation error:", aiErr);
        aiSummary = `Progress Report for ${child.fullName}\n\nOverall skill level: ${profile.overallSkillPercentage}% (${profile.juniorLevel.replace(/_/g, " ")})\nAttendance: ${profile.attendancePercentage}%\nEffort: ${profile.effortRating}/10 | Coach Rating: ${profile.coachRating}/10\n\nStrongest areas: ${strongest3.map(s => `${s.name} (${s.percentage}%)`).join(", ")}.\nAreas to improve: ${weakest3.map(s => `${s.name} (${s.percentage}%)`).join(", ")}.\n\n${prioritySkills.length > 0 ? `Priority focus: ${prioritySkills.map(s => s.name).join(", ")}.` : ""}`;
      }

      const [report] = await db.insert(generatedReports).values({
        createdBy: user.id,
        clubId: profile.clubId,
        dateRangeStart: new Date(Date.now() - 30 * 24 * 60 * 60 * 1000),
        dateRangeEnd: new Date(),
        squadFilter: `child:${childId}`,
        aiSummary,
      }).returning();

      res.json({
        report,
        childName: child.fullName,
        profile: { juniorLevel: profile.juniorLevel, overallSkillPercentage: profile.overallSkillPercentage, attendancePercentage: profile.attendancePercentage, effortRating: profile.effortRating, coachRating: profile.coachRating },
        categories: categoryData,
        weakest: weakest3,
        strongest: strongest3,
        prioritySkills,
      });
    } catch (err: any) {
      console.error("Error generating child report:", err);
      res.status(500).json({ message: err.message });
    }
  });

  app.get("/api/juniors/:childId/report/:reportId/pdf", async (req, res) => {
    if (!req.isAuthenticated()) return res.sendStatus(401);
    try {
      const childId = Number(req.params.childId);
      const reportId = Number(req.params.reportId);
      const user = req.user!;

      const [child] = await db.select().from(users).where(eq(users.id, childId));
      if (!child) return res.status(404).json({ message: "Child not found" });

      let pdfProfiles = await db.select().from(juniorProfiles).where(eq(juniorProfiles.userId, childId));
      let profile = pdfProfiles[0];

      if (!profile) {
        let autoClubId: number | null = null;
        if (child.parentUserId) {
          const parentClubs = await db.select({ clubId: playerProfiles.clubId }).from(playerProfiles)
            .where(and(eq(playerProfiles.userId, child.parentUserId), eq(playerProfiles.membershipStatus, "APPROVED")));
          if (parentClubs.length > 0) autoClubId = parentClubs[0].clubId;
        }
        if (!autoClubId) {
          const userClubs = await db.select({ clubId: playerProfiles.clubId }).from(playerProfiles)
            .where(and(eq(playerProfiles.userId, user.id), eq(playerProfiles.membershipStatus, "APPROVED")));
          if (userClubs.length > 0) autoClubId = userClubs[0].clubId;
        }
        if (!autoClubId) return res.status(404).json({ message: "No club found for junior profile" });

        const [newProfile] = await db.insert(juniorProfiles).values({
          userId: childId,
          clubId: autoClubId,
          juniorLevel: "BEGINNER",
          overallSkillPercentage: 0,
          attendancePercentage: 0,
          effortRating: 0,
          coachRating: 0,
        }).returning();
        profile = newProfile;
      }

      if (child.parentUserId !== user.id && user.role !== "OWNER") {
        const adminProfiles = await db.select({ clubId: playerProfiles.clubId }).from(playerProfiles)
          .where(and(eq(playerProfiles.userId, user.id), eq(playerProfiles.clubId, profile.clubId), or(eq(playerProfiles.clubRole, "ADMIN"), eq(playerProfiles.clubRole, "OWNER"))));
        if (adminProfiles.length === 0) return res.status(403).json({ message: "Not authorized" });
      }

      const [report] = await db.select().from(generatedReports).where(eq(generatedReports.id, reportId));
      if (!report) return res.status(404).json({ message: "Report not found" });
      if (report.squadFilter !== `child:${childId}`) return res.status(403).json({ message: "Report does not belong to this child" });

      const [club] = await db.select().from(clubs).where(eq(clubs.id, profile.clubId));

      const categories = await db.select().from(juniorSkillCategories).orderBy(juniorSkillCategories.displayOrder);
      const skills = await db.select().from(juniorSkills);
      const progress = await db.select().from(juniorSkillProgress).where(eq(juniorSkillProgress.childId, childId));

      const categoryData = categories.map(cat => {
        const catSkills = skills.filter(s => s.categoryId === cat.id);
        const skillData = catSkills.map(sk => {
          const prog = progress.find(p => p.skillId === sk.id);
          return { name: sk.name, percentage: prog?.percentage || 0, priority: prog?.priority || false, comment: prog?.comment || null };
        });
        const avgScore = skillData.length > 0 ? Math.round(skillData.reduce((s, d) => s + d.percentage, 0) / skillData.length) : 0;
        return { category: cat.name, avgScore, skills: skillData };
      });

      const PDFDocument = (await import("pdfkit")).default;
      const doc = new PDFDocument({ size: "A4", margin: 50, bufferPages: true });

      res.setHeader("Content-Type", "application/pdf");
      res.setHeader("Content-Disposition", `attachment; filename="${child.fullName.replace(/[^a-zA-Z0-9]/g, "_")}_Report.pdf"`);
      doc.pipe(res);

      const gold = "#B8941E";
      const darkGray = "#333333";
      const midGray = "#666666";
      const lightGray = "#F5F5F0";
      const pageWidth = 495;

      doc.rect(0, 0, doc.page.width, 120).fill("#1A1A1A");
      doc.rect(0, 120, doc.page.width, 4).fill(gold);

      doc.fontSize(28).font("Helvetica-Bold").fillColor("#FFFFFF").text("Player Progress Report", 50, 35);
      doc.fontSize(12).font("Helvetica").fillColor("#CCCCCC").text(club?.name || "Sports Club", 50, 70);
      doc.fontSize(10).fillColor("#999999").text(`Generated: ${new Date().toLocaleDateString("en-GB", { day: "numeric", month: "long", year: "numeric" })}`, 50, 90);

      let y = 140;

      doc.rect(50, y, pageWidth, 70).fill(lightGray);
      doc.fontSize(20).font("Helvetica-Bold").fillColor(darkGray).text(child.fullName, 65, y + 12);

      const age = child.dateOfBirth ? Math.floor((Date.now() - new Date(child.dateOfBirth).getTime()) / (365.25 * 24 * 60 * 60 * 1000)) : null;
      const levelLabel = (profile?.juniorLevel || "BEGINNER").replace(/_/g, " ");
      doc.fontSize(10).font("Helvetica").fillColor(midGray).text(
        `${age ? `Age ${age}` : ""} ${age ? " | " : ""}Level: ${levelLabel}`,
        65, y + 38
      );
      doc.roundedRect(370, y + 10, 160, 50, 5).fill(gold);
      doc.fontSize(24).font("Helvetica-Bold").fillColor("#FFFFFF").text(`${profile?.overallSkillPercentage || 0}%`, 380, y + 14, { width: 140, align: "center" });
      doc.fontSize(8).font("Helvetica").text("OVERALL SKILL", 380, y + 42, { width: 140, align: "center" });

      y += 90;

      const statBoxW = (pageWidth - 30) / 4;
      const stats = [
        { label: "ATTENDANCE", value: `${profile?.attendancePercentage || 0}%`, color: "#22c55e" },
        { label: "EFFORT", value: `${profile?.effortRating || 0}/10`, color: "#3b82f6" },
        { label: "COACH RATING", value: `${profile?.coachRating || 0}/10`, color: "#a855f7" },
        { label: "SKILLS TRACKED", value: `${progress.length}`, color: "#f59e0b" },
      ];
      stats.forEach((stat, i) => {
        const x = 50 + i * (statBoxW + 10);
        doc.roundedRect(x, y, statBoxW, 55, 4).fillAndStroke("#FFFFFF", "#E5E5E5");
        doc.fontSize(16).font("Helvetica-Bold").fillColor(stat.color).text(stat.value, x + 5, y + 8, { width: statBoxW - 10, align: "center" });
        doc.fontSize(7).font("Helvetica").fillColor(midGray).text(stat.label, x + 5, y + 32, { width: statBoxW - 10, align: "center" });
      });
      y += 75;

      doc.fontSize(14).font("Helvetica-Bold").fillColor(darkGray).text("Category Performance", 50, y);
      doc.moveTo(50, y + 18).lineTo(50 + pageWidth, y + 18).strokeColor(gold).lineWidth(2).stroke();
      y += 28;

      for (const cat of categoryData) {
        if (y > 700) { doc.addPage(); y = 50; }
        doc.fontSize(10).font("Helvetica-Bold").fillColor(darkGray).text(cat.category, 50, y, { width: 160 });
        doc.fontSize(10).font("Helvetica-Bold").fillColor(gold).text(`${cat.avgScore}%`, 480, y, { width: 50, align: "right" });

        const barX = 220;
        const barW = 250;
        doc.roundedRect(barX, y + 1, barW, 12, 3).fill("#E5E5E5");
        if (cat.avgScore > 0) {
          const fillW = Math.max(6, (cat.avgScore / 100) * barW);
          const barColor = cat.avgScore >= 70 ? "#22c55e" : cat.avgScore >= 40 ? gold : "#ef4444";
          doc.roundedRect(barX, y + 1, fillW, 12, 3).fill(barColor);
        }
        y += 22;

        for (const sk of cat.skills) {
          const skNeeded = sk.comment ? 28 : 14;
          if (y + skNeeded > 720) { doc.addPage(); y = 50; }
          doc.fontSize(8).font("Helvetica").fillColor(midGray).text(
            `${sk.priority ? "★ " : "  "}${sk.name}`, 70, y, { width: 145 }
          );
          const skBarX = 220;
          const skBarW = 250;
          doc.roundedRect(skBarX, y + 1, skBarW, 8, 2).fill("#EEEEEE");
          if (sk.percentage > 0) {
            const skFillW = Math.max(4, (sk.percentage / 100) * skBarW);
            const skColor = sk.percentage >= 70 ? "#22c55e" : sk.percentage >= 40 ? "#D4AF37" : "#ef4444";
            doc.roundedRect(skBarX, y + 1, skFillW, 8, 2).fill(skColor);
          }
          doc.fontSize(8).font("Helvetica").fillColor(darkGray).text(`${sk.percentage}%`, 480, y, { width: 50, align: "right" });
          y += 14;
          if (sk.comment) {
            doc.fontSize(7).font("Helvetica-Oblique").fillColor("#888888").text(`Note: ${sk.comment}`, 80, y, { width: 430 });
            y += doc.heightOfString(`Note: ${sk.comment}`, { width: 430, fontSize: 7 }) + 4;
          }
        }
        y += 8;
      }

      const analysisHeight = doc.heightOfString(report.aiSummary.replace(/\*\*/g, ""), { width: pageWidth, fontSize: 9 }) + 50;
      if (y + Math.min(analysisHeight, 150) > 720) { doc.addPage(); y = 50; }

      doc.fontSize(14).font("Helvetica-Bold").fillColor(darkGray).text("Coach Analysis", 50, y);
      doc.moveTo(50, y + 18).lineTo(50 + pageWidth, y + 18).strokeColor(gold).lineWidth(2).stroke();
      y += 28;

      const reportLines = report.aiSummary.split("\n");
      for (const line of reportLines) {
        if (y > 720) { doc.addPage(); y = 50; }
        const trimmed = line.trim();
        if (trimmed.startsWith("**") && trimmed.endsWith("**")) {
          doc.fontSize(11).font("Helvetica-Bold").fillColor(darkGray).text(trimmed.replace(/\*\*/g, ""), 50, y, { width: pageWidth });
        } else if (trimmed.startsWith("- ") || trimmed.startsWith("• ")) {
          doc.fontSize(9).font("Helvetica").fillColor(midGray).text(`  •  ${trimmed.slice(2)}`, 60, y, { width: pageWidth - 10 });
        } else if (trimmed.length > 0) {
          doc.fontSize(9).font("Helvetica").fillColor(midGray).text(trimmed.replace(/\*\*/g, ""), 50, y, { width: pageWidth });
        }
        const lineFontSize = (trimmed.startsWith("**") && trimmed.endsWith("**")) ? 11 : 9;
        y += trimmed.length > 0 ? doc.heightOfString(trimmed.replace(/\*\*/g, ""), { width: pageWidth, fontSize: lineFontSize }) + 4 : 8;
      }

      const totalPages = doc.bufferedPageRange().count;
      for (let i = 0; i < totalPages; i++) {
        doc.switchToPage(i);
        doc.fontSize(7).font("Helvetica").fillColor("#AAAAAA")
          .text(`Page ${i + 1} of ${totalPages}  |  ${child.fullName}  |  ${club?.name || "Club"}  |  Confidential`, 50, doc.page.height - 30, { width: pageWidth, align: "center" });
      }

      doc.end();
    } catch (err: any) {
      console.error("Error generating PDF:", err);
      if (!res.headersSent) res.status(500).json({ message: err.message });
    }
  });

