  // POST /api/players/skill-review/request - Player requests coach feedback
  app.post("/api/players/skill-review/request", async (req, res) => {
    if (!req.isAuthenticated()) return res.sendStatus(401);
    const user = req.user!;
    try {
      const { playerId, clubId, paymentMethod } = req.body;
      if (!playerId || !clubId) return res.status(400).json({ message: "playerId and clubId are required" });
      const plan = await getClubPlanStatus(Number(clubId));
      if (!isClubPremium(plan.planStatus) && user.role !== "OWNER") {
        return res.status(403).json({ message: "This feature requires a Premium plan.", requiresPremium: true });
      }
      const profile = await storage.getPlayerProfileById(Number(playerId));
      if (!profile) return res.status(404).json({ message: "Player profile not found" });
      if (profile.userId !== user.id && user.role !== "OWNER") {
        const isAdmin = await hasAdminAccess(user.id, user.role, Number(clubId));
        if (!isAdmin) return res.status(403).json({ message: "You can only request reviews for yourself" });
      }
      const existing = await db.select().from(playerSkillReviewRequests)
        .where(and(
          eq(playerSkillReviewRequests.playerId, Number(playerId)),
          eq(playerSkillReviewRequests.clubId, Number(clubId)),
          or(
            eq(playerSkillReviewRequests.status, "PENDING"),
            eq(playerSkillReviewRequests.status, "ACCEPTED")
          )
        ));
      if (existing.length > 0) {
        return res.status(400).json({ message: "You already have an active review request" });
      }
      const [request] = await db.insert(playerSkillReviewRequests).values({
        playerId: Number(playerId),
        clubId: Number(clubId),
        status: "PENDING",
        paymentMethod: paymentMethod || null,
        paymentConfirmed: false,
      }).returning();

      const requestingUser = await storage.getUser(profile.userId);
      const requestingName = requestingUser?.fullName || "A player";
      const [clubInfo] = await db.select().from(clubs).where(eq(clubs.id, Number(clubId))).limit(1);
      const clubDisplayName = clubInfo?.name || "the club";

      const ticketNumber = "TK-" + randomBytes(4).toString("hex").toUpperCase();
      const ticketSubject = `Coach Review Request - ${requestingName}`;
      const ticketDescription = `${requestingName} has requested a coach skill review at ${clubDisplayName}.\n\nPlayer ID: ${playerId}\nClub: ${clubDisplayName}\nPayment Method: ${paymentMethod || "Not specified"}\n\nPlease review and evaluate this player's skills.`;

      const now = new Date();
      const autoCloseAt = new Date(now.getTime() + 30 * 24 * 60 * 60 * 1000);

      const [ticket] = await db.insert(tickets).values({
        ticketNumber,
        clubId: Number(clubId),
        createdByUserId: profile.userId,
        subject: ticketSubject,
        description: ticketDescription,
        category: "GENERAL",
        priority: "MEDIUM",
        isConfidential: false,
        autoCloseAt,
      }).returning();

      await db.insert(ticketAuditLogs).values({
        ticketId: ticket.id,
        actorUserId: profile.userId,
        action: "CREATED",
        toStatus: "SUBMITTED",
      });

      const [ownerUser] = await db.select().from(users).where(eq(users.role, "OWNER")).limit(1);
      if (ownerUser) {
        const msgBody = `📋 Coach Review Request\n\nHi, ${requestingName} from ${clubDisplayName} has requested a coach skill review.\n\nTicket: ${ticketNumber}\n\nPlease check the skill review requests to evaluate this player.\n\nThank you!`;

        await db.insert(internalMessages).values({
          senderId: profile.userId,
          recipientId: ownerUser.id,
          subject: "",
          body: msgBody,
          clubId: Number(clubId),
        });

        await storage.createNotification({
          userId: ownerUser.id,
          type: "TICKET_UPDATE",
          title: "New Coach Review Request",
          message: `${requestingName} has requested a coach skill review at ${clubDisplayName}. Ticket: ${ticketNumber}`,
          linkUrl: `/tickets/${ticket.id}`,
        });
      }

      res.json(request);
    } catch (err: any) {
      res.status(500).json({ message: err.message });
    }
  });

