  app.get("/api/trial-players/me", async (req, res) => {
    if (!req.isAuthenticated()) return res.sendStatus(401);
    try {
      const trial = await storage.getTrialPlayerByUserId(req.user!.id);
      if (!trial) return res.json(null);

      const userProfiles = await db.select({ id: playerProfiles.id }).from(playerProfiles)
        .where(and(eq(playerProfiles.userId, req.user!.id), eq(playerProfiles.membershipStatus, "APPROVED")))
        .limit(1);
      const activeClubMembership = await db.select({ id: clubMemberships.id }).from(clubMemberships)
        .where(and(eq(clubMemberships.userId, req.user!.id), eq(clubMemberships.status, "ACTIVE")))
        .limit(1);
      const hasClubAccess = userProfiles.length > 0 || activeClubMembership.length > 0;
      if (hasClubAccess && trial.status !== "APPROVED") {
        await storage.updateTrialPlayer(trial.id, { status: "APPROVED", finalDecision: "APPROVED", statusMessage: "Approved via club membership." } as any);
        return res.json(null);
      }
      if (hasClubAccess && trial.status === "APPROVED") {
        return res.json(null);
      }

      const club = await storage.getClub(trial.clubId);
      let sessionDetails = null;
      if (trial.assignedSessionId) {
        const [sess] = await db.select().from(sessions).where(eq(sessions.id, trial.assignedSessionId)).limit(1);
        if (sess) {
          const [venue] = sess.venueId ? await db.select().from(venues).where(eq(venues.id, sess.venueId)).limit(1) : [null];
          sessionDetails = {
            ...sess,
            venueName: venue?.name || null,
            venueAddress: venue?.address || null,
            venuePostcode: venue?.postcode || null,
          };
        }
      }
      let observerName = null;
      if (trial.observerUserId) {
        const [obs] = await db.select().from(users).where(eq(users.id, trial.observerUserId)).limit(1);
        observerName = obs?.fullName || null;
      }
      let evaluation = null;
      const ev = await storage.getTrialEvaluation(trial.id);
      if (ev) evaluation = ev;

      const exerciseRows = await db.select().from(juniorExercises)
        .where(and(eq(juniorExercises.isActive, true), inArray(juniorExercises.difficulty, ["EASY", "MEDIUM"])))
        .orderBy(sql`RANDOM()`)
        .limit(4);

      const exerciseIds = exerciseRows.map(e => e.id);
      let exerciseVideos: any[] = [];
      if (exerciseIds.length > 0) {
        exerciseVideos = await db.select().from(juniorExerciseVideos)
          .where(inArray(juniorExerciseVideos.exerciseId, exerciseIds));
      }

      const suggestedExercises = exerciseRows.map(ex => ({
        ...ex,
        videos: exerciseVideos.filter(v => v.exerciseId === ex.id),
      }));

      res.json({
        ...trial,
        clubName: club?.name || null,
        session: sessionDetails,
        observerName,
        evaluation,
        suggestedExercises,
      });
    } catch (err: any) {
      console.error("Error getting trial player:", err);
      res.status(500).json({ message: err.message });
    }
  });

