  app.patch("/api/admin/trial-players/:id/assign-session", async (req, res) => {
    if (!req.isAuthenticated()) return res.sendStatus(401);
    const user = req.user!;
    if (!(await isAnyClubAdmin(user.id, user.role))) return res.sendStatus(403);
    try {
      const { sessionId, observerUserId } = req.body;
      if (!sessionId) return res.status(400).json({ message: "Session is required" });

      const trial = await storage.getTrialPlayerById(parseInt(req.params.id));
      if (!trial) return res.status(404).json({ message: "Trial player not found" });

      let [profile] = await db.select().from(playerProfiles)
        .where(and(eq(playerProfiles.userId, trial.userId), eq(playerProfiles.clubId, trial.clubId)))
        .limit(1);

      if (!profile) {
        const [trialUser] = await db.select().from(users).where(eq(users.id, trial.userId)).limit(1);
        if (trialUser) {
          [profile] = await db.insert(playerProfiles).values({
            userId: trial.userId,
            clubId: trial.clubId,
            clubRole: "PLAYER" as any,
            membershipStatus: "PENDING" as any,
            playerStatus: "ACTIVE" as any,
            gender: trialUser.gender || null,
          } as any).returning();
        }
      }

      if (profile && trial.assignedSessionId && trial.assignedSessionId !== sessionId) {
        await db.delete(sessionSignups).where(
          and(eq(sessionSignups.sessionId, trial.assignedSessionId), eq(sessionSignups.playerId, profile.id))
        );
        try {
          await removeUserFromSessionChat(trial.assignedSessionId, trial.userId);
        } catch {}
      }

      const updated = await storage.updateTrialPlayer(trial.id, {
        assignedSessionId: sessionId,
        observerUserId: observerUserId || null,
        status: "SCHEDULED",
        statusMessage: "Your trial session has been scheduled. Check the details below.",
      } as any);

      const [sess] = await db.select().from(sessions).where(eq(sessions.id, sessionId)).limit(1);

      if (profile) {
        const existingSignup = await db.select().from(sessionSignups)
          .where(and(eq(sessionSignups.sessionId, sessionId), eq(sessionSignups.playerId, profile.id)))
          .limit(1);
        if (existingSignup.length === 0) {
          const fee = sess?.sessionFee ?? 0;
          await storage.createSessionSignupEnhanced({
            sessionId,
            playerId: profile.id,
            fee,
            paymentStatus: "UNPAID",
            signupStatus: "CONFIRMED",
            signedUpByUserId: user.id,
          });
          try {
            await addUserToSessionChat(sessionId, trial.userId);
          } catch (chatErr) {
            console.error("[TRIAL ASSIGN] Failed to add trial player to session chat:", chatErr);
          }
        }
      }

      await storage.createNotification({
        userId: trial.userId,
        type: "trial_scheduled",
        title: "Trial Session Scheduled",
        message: `Your trial session has been scheduled: ${sess?.title || "Session"} on ${sess?.date ? new Date(sess.date).toLocaleDateString() : "TBD"}.`,
        linkUrl: "/trial-dashboard",
      });

      res.json(updated);
    } catch (err: any) {
      console.error("Error assigning trial session:", err);
      res.status(500).json({ message: err.message });
    }
  });

  app.patch("/api/admin/trial-players/:id/mark-attended", async (req, res) => {
    if (!req.isAuthenticated()) return res.sendStatus(401);
    const user = req.user!;
    if (!(await isAnyClubAdmin(user.id, user.role))) return res.sendStatus(403);
    try {
      const trial = await storage.getTrialPlayerById(parseInt(req.params.id));
      if (!trial) return res.status(404).json({ message: "Trial player not found" });

      const updated = await storage.updateTrialPlayer(trial.id, {
        status: "ATTENDED",
        statusMessage: "You attended your trial session. Evaluation is in progress.",
      } as any);

      await storage.createNotification({
        userId: trial.userId,
        type: "trial_attended",
        title: "Trial Attended",
        message: "Your trial session has been marked as attended. Your evaluation is being prepared.",
        linkUrl: "/trial-dashboard",
      });

      res.json(updated);
    } catch (err: any) {
      console.error("Error marking trial attended:", err);
      res.status(500).json({ message: err.message });
    }
  });

  app.post("/api/admin/trial-players/:id/evaluate", async (req, res) => {
    if (!req.isAuthenticated()) return res.sendStatus(401);
    const user = req.user!;
    if (!(await isAnyClubAdmin(user.id, user.role))) return res.sendStatus(403);
    try {
      const trial = await storage.getTrialPlayerById(parseInt(req.params.id));
      if (!trial) return res.status(404).json({ message: "Trial player not found" });

      const { technicalLevel, tacticalUnderstanding, movementFootwork, matchAwareness, communicationAttitude, notes } = req.body;

      const scores = [technicalLevel, tacticalUnderstanding, movementFootwork, matchAwareness, communicationAttitude];
      if (scores.some((s: any) => typeof s !== "number" || s < 1 || s > 10)) {
        return res.status(400).json({ message: "All scores must be between 1 and 10" });
      }

      const avg = scores.reduce((a: number, b: number) => a + b, 0) / scores.length;
      const overallScore = avg.toFixed(1);

      let recommendation: string;
      if (avg >= 8) {
        recommendation = "Recommended for Dragon Badminton Club membership";
      } else if (avg >= 5) {
        recommendation = "Recommended for Badminton Performance Group training";
      } else {
        recommendation = "Not suitable for club sessions at this time";
      }

      const evaluation = await storage.createTrialEvaluation({
        trialPlayerId: trial.id,
        evaluatorUserId: user.id,
        technicalLevel,
        tacticalUnderstanding,
        movementFootwork,
        matchAwareness,
        communicationAttitude,
        overallScore,
        recommendation,
        notes: notes || null,
      });

      await storage.updateTrialPlayer(trial.id, {
        status: "EVALUATED",
        statusMessage: "Your trial evaluation is complete. Awaiting final decision.",
      } as any);

      await storage.createNotification({
        userId: trial.userId,
        type: "trial_evaluated",
        title: "Trial Evaluation Complete",
        message: "Your trial has been evaluated. A final decision will be communicated shortly.",
        linkUrl: "/trial-dashboard",
      });

      res.json(evaluation);
    } catch (err: any) {
      console.error("Error evaluating trial player:", err);
      res.status(500).json({ message: err.message });
    }
  });

  app.patch("/api/admin/trial-players/:id/decide", async (req, res) => {
    if (!req.isAuthenticated()) return res.sendStatus(401);
    const user = req.user!;
    if (!(await isAnyClubAdmin(user.id, user.role))) return res.sendStatus(403);
    try {
      const trial = await storage.getTrialPlayerById(parseInt(req.params.id));
      if (!trial) return res.status(404).json({ message: "Trial player not found" });

      const { decision, adminOverrideDecision, statusMessage: customMessage } = req.body;
      if (!["APPROVED", "REDIRECTED", "REJECTED"].includes(decision)) {
        return res.status(400).json({ message: "Decision must be APPROVED, REDIRECTED, or REJECTED" });
      }

      const statusMap: Record<string, string> = {
        APPROVED: "APPROVED",
        REDIRECTED: "REDIRECTED",
        REJECTED: "REJECTED",
      };

      let message = "";
      if (decision === "APPROVED") {
        message = customMessage || "Congratulations! You have been approved to join the club. Please confirm your membership below.";
      } else if (decision === "REDIRECTED") {
        message = customMessage || "Based on your evaluation, we recommend you join the Badminton Performance Group training sessions to develop your skills further.";
      } else {
        message = customMessage || "Thank you for attending the trial. Unfortunately, we are unable to offer you a place at this time.";
      }

      if (adminOverrideDecision) {
        const evaluation = await storage.getTrialEvaluation(trial.id);
        if (evaluation) {
          await db.update(trialEvaluations)
            .set({ adminOverrideDecision })
            .where(eq(trialEvaluations.id, evaluation.id));
        }
      }

      const updated = await storage.updateTrialPlayer(trial.id, {
        status: statusMap[decision] as any,
        finalDecision: decision,
        statusMessage: message,
      } as any);

      const notifTitle = decision === "APPROVED" ? "Trial Approved!" :
                         decision === "REDIRECTED" ? "Training Recommendation" : "Trial Result";

      await storage.createNotification({
        userId: trial.userId,
        type: "trial_decision",
        title: notifTitle,
        message,
        linkUrl: "/trial-dashboard",
      });

      if (decision === "APPROVED" && trial.finalDecision !== "APPROVED") {
        const existingCredit = await db.select().from(creditLedger)
          .where(and(
            eq(creditLedger.userId, trial.userId),
            eq(creditLedger.clubId, trial.clubId),
            eq(creditLedger.reason, "Welcome credit for passing trial"),
          )).limit(1);

        if (existingCredit.length === 0) {
        const welcomeCreditAmount = 400;
        await db.insert(creditLedger).values({
          userId: trial.userId,
          clubId: trial.clubId,
          amount: welcomeCreditAmount,
          reason: "Welcome credit for passing trial",
          createdById: user.id,
        });
        ensureUserWallet(trial.userId, trial.clubId, welcomeCreditAmount, "Credit issued", user.id).catch(() => {});

        const [club] = await db.select().from(clubs).where(eq(clubs.id, trial.clubId)).limit(1);
        const clubName = club?.name || "the club";
        const clubSessionFee = club?.sessionFee ? `£${(club.sessionFee / 100).toFixed(2)}` : "the standard rate";

        const annualPlans = await db.select().from(membershipPlans)
          .where(and(eq(membershipPlans.clubId, trial.clubId), eq(membershipPlans.isActive, true)));
        let membershipInfo = "";
        if (annualPlans.length > 0) {
          const plan = annualPlans[0];
          const planFee = plan.defaultSessionFee ? `£${(plan.defaultSessionFee / 100).toFixed(2)}` : clubSessionFee;
          const planPrice = plan.annualPrice ? `£${(plan.annualPrice / 100).toFixed(2)}` : "a yearly fee";
          membershipInfo = `\n\n💎 Annual Membership Benefits:\n• Reduced session fee of ${planFee} per session (instead of ${clubSessionFee})\n• Access to Player Intelligence & Analytics\n• Full access to all club features\n• Priority booking for sessions\n• Annual membership costs ${planPrice}/year\n\nConsider joining as an annual member to get the most out of your club experience!`;
        }

        const congratsBody = `🎉 Congratulations! You've passed your trial at ${clubName}!\n\n💰 Welcome Credit: £${(welcomeCreditAmount / 100).toFixed(2)} has been added to your wallet. This credit will be automatically applied towards your session fees.\n\nTo use your credit, simply sign up for a session and select "Use Credit" as your payment method.\n\n📋 Session Fee: The standard session fee at ${clubName} is ${clubSessionFee}. Your welcome credit covers your first session!${membershipInfo}\n\nWelcome to the club! We look forward to seeing you on court. 🏸`;

        const [ownerUser] = await db.select().from(users).where(eq(users.role, "OWNER")).limit(1);
        const systemSenderId = ownerUser?.id || user.id;

        await db.insert(internalMessages).values({
          senderId: systemSenderId,
          recipientId: trial.userId,
          subject: "",
          body: congratsBody,
          clubId: trial.clubId,
        });

        await storage.createNotification({
          userId: trial.userId,
          type: "GENERAL",
          title: "Welcome Credit Added!",
          message: `£${(welcomeCreditAmount / 100).toFixed(2)} welcome credit has been added to your wallet at ${clubName}. Check your messages for details!`,
          linkUrl: "/inbox",
        });
        }
      }

      res.json(updated);
    } catch (err: any) {
      console.error("Error deciding trial:", err);
      res.status(500).json({ message: err.message });
    }
  });

  app.post("/api/trial-players/confirm-join", async (req, res) => {
    if (!req.isAuthenticated()) return res.sendStatus(401);
    try {
      const trial = await storage.getTrialPlayerByUserId(req.user!.id);
      if (!trial) return res.status(404).json({ message: "No trial record found" });
      if (trial.finalDecision !== "APPROVED") return res.status(400).json({ message: "Trial not approved" });

      const existingProfile = await db.select().from(playerProfiles)
        .where(and(eq(playerProfiles.userId, req.user!.id), eq(playerProfiles.clubId, trial.clubId)))
        .limit(1);

      if (existingProfile.length === 0) {
        await db.insert(playerProfiles).values({
          userId: req.user!.id,
          clubId: trial.clubId,
          clubRole: "PLAYER",
          membershipStatus: "APPROVED",
          playerStatus: "ACTIVE",
          category: "D",
          grade: "C3",
          rankingPoints: 1000,
          matchesPlayed: 0,
          matchesWon: 0,
        } as any);
      } else {
        await db.update(playerProfiles)
          .set({ membershipStatus: "APPROVED", playerStatus: "ACTIVE" } as any)
          .where(eq(playerProfiles.id, existingProfile[0].id));
      }

      await storage.updateTrialPlayer(trial.id, {
        statusMessage: "Welcome! You are now a full member. Enjoy all club features.",
      } as any);

      if (trial.referralId) {
        await db.update(referrals).set({ status: "APPROVED" } as any).where(eq(referrals.id, trial.referralId));
      }

      const admins = await db.select().from(users).where(or(eq(users.role, "OWNER"), eq(users.role, "ADMIN")));
      for (const admin of admins) {
        await storage.createNotification({
          userId: admin.id,
          type: "trial_joined",
          title: "Trial Player Joined",
          message: `${req.user!.fullName} has confirmed their club membership after passing the trial.`,
          linkUrl: "/admin/trials",
        });
      }

      res.json({ success: true });
    } catch (err: any) {
      console.error("Error confirming trial join:", err);
      res.status(500).json({ message: err.message });
    }
  });

  app.get("/api/admin/trial-players/referral-funnel", async (req, res) => {
    if (!req.isAuthenticated()) return res.sendStatus(401);
    const user = req.user!;
    if (!(await isAnyClubAdmin(user.id, user.role))) return res.sendStatus(403);
    try {
      const allTrials = await storage.getAllTrialPlayers();
      const withReferral = allTrials.filter(t => t.referralId);
      const scheduled = allTrials.filter(t => ["SCHEDULED", "ATTENDED", "EVALUATED", "APPROVED", "REDIRECTED", "REJECTED"].includes(t.status));
      const completed = allTrials.filter(t => ["ATTENDED", "EVALUATED", "APPROVED", "REDIRECTED", "REJECTED"].includes(t.status));
      const passed = allTrials.filter(t => t.finalDecision === "APPROVED");
      const joined = allTrials.filter(t => t.finalDecision === "APPROVED" && t.statusMessage?.includes("full member"));

      const referrerStats: Record<string, { name: string; total: number; passed: number }> = {};
      for (const t of withReferral) {
        if (t.referralId) {
          const [ref] = await db.select().from(referrals).where(eq(referrals.id, t.referralId)).limit(1);
          if (ref && ref.referrerId) {
            const [referrer] = await db.select().from(users).where(eq(users.id, ref.referrerId)).limit(1);
            const key = String(ref.referrerId);
            if (!referrerStats[key]) referrerStats[key] = { name: referrer?.fullName || "Unknown", total: 0, passed: 0 };
            referrerStats[key].total++;
            if (t.finalDecision === "APPROVED") referrerStats[key].passed++;
          }
        }
      }

      res.json({
        funnel: {
          registered: allTrials.length,
          referralLinked: withReferral.length,
          scheduled: scheduled.length,
          completed: completed.length,
          passed: passed.length,
          joined: joined.length,
        },
        topReferrers: Object.values(referrerStats).sort((a, b) => b.passed - a.passed).slice(0, 10),
      });
    } catch (err: any) {
      console.error("Error getting referral funnel:", err);
      res.status(500).json({ message: err.message });
    }
  });

  app.get("/api/admin/trial-players/:id/session-recommendations", async (req, res) => {
    if (!req.isAuthenticated()) return res.sendStatus(401);
    const user = req.user!;
    if (!(await isAnyClubAdmin(user.id, user.role))) return res.sendStatus(403);
    try {
      const trial = await storage.getTrialPlayerById(parseInt(req.params.id));
      if (!trial) return res.status(404).json({ message: "Trial player not found" });

      const today = new Date();
      today.setHours(0, 0, 0, 0);
      const adminClubIds = await getUserAdminClubIds(user.id, user.role);
      const clubFilter = adminClubIds.length > 0 ? inArray(sessions.clubId, adminClubIds) : eq(sessions.clubId, trial.clubId);
      const upcomingSessions = await db.select({
        session: sessions,
        venue: venues,
        club: clubs,
      }).from(sessions)
        .leftJoin(venues, eq(sessions.venueId, venues.id))
        .innerJoin(clubs, eq(sessions.clubId, clubs.id))
        .where(and(
          clubFilter,
          gte(sessions.date, today),
        ))
        .orderBy(asc(sessions.date));

      const dayNames = ["SUNDAY", "MONDAY", "TUESDAY", "WEDNESDAY", "THURSDAY", "FRIDAY", "SATURDAY"];

      const scored = upcomingSessions.map(({ session: s, venue: v, club: c }) => {
        let score = 0;
        if (trial.preferredDays && trial.preferredDays.length > 0 && s.date) {
          const sessionDay = dayNames[new Date(s.date).getDay()];
          if (trial.preferredDays.map((d: string) => d.toUpperCase()).includes(sessionDay)) score += 3;
        }
        if (trial.selfAssessedLevel) {
          const level = trial.selfAssessedLevel.toUpperCase();
          const mode = s.matchMode;
          if (level === "BEGINNER" && mode === "SOCIAL") score += 2;
          if (level === "INTERMEDIATE" && mode === "SOCIAL") score += 1;
          if (level === "ADVANCED" && mode === "COMPETITIVE") score += 2;
          if (level === "COMPETITIVE" && mode === "COMPETITIVE") score += 2;
        }
        if (s.clubId === trial.clubId) score += 10;
        return {
          sessionId: s.id,
          title: s.title,
          date: s.date,
          startTime: s.startTime,
          matchMode: s.matchMode,
          venueName: v?.name || null,
          clubName: c.name,
          maxPlayers: s.maxPlayers,
          score,
        };
      });

      scored.sort((a, b) => {
        if (b.score !== a.score) return b.score - a.score;
        return new Date(a.date).getTime() - new Date(b.date).getTime();
      });
      res.json(scored);
    } catch (err: any) {
      console.error("Error getting session recommendations:", err);
      res.status(500).json({ message: err.message });
    }
  });

  app.get("/api/dashboard/analytics", async (req, res) => {
    if (!req.isAuthenticated()) return res.sendStatus(401);
    const user = req.user!;
    if (user.role !== "OWNER") return res.sendStatus(403);

    const accessibleClubIds = await getUserAdminClubIds(user.id, user.role);
    if (accessibleClubIds.length === 0) return res.json({ kpis: { totalSessions: 0, totalPlayers: 0, totalRevenue: 0, paidRevenue: 0, avgPlayersPerSession: 0, revenuePerSession: 0, revenuePerPlayer: 0, fillRate: 0, noShowRate: 0, noShows: 0, mostPopularClub: null, mostProfitableSession: null, totalMatches: 0, completedMatches: 0 }, attendanceTrend: [], sessionRankings: [], sessionStats: [], weekdayStats: [], timeOfDayStats: [], clubStats: [], capacityUtilization: [], playerRetention: { newPlayers: 0, returningPlayers: 0, frequentPlayers: 0 }, playerFrequency: { one: 0, twoToFive: 0, fiveToTen: 0, tenPlus: 0 }, noShowByWeekday: [], alerts: [], seasonalityData: [], churn: { churnedPlayers: 0, decliningPlayers: 0, loyalPlayers: 0 }, demandSuggestions: [], clubs: [], sessionList: [] });

    try {

      const { from, to, clubId, sessionId, timeOfDay, weekday } = req.query;

      const allClubsData = await db.select().from(clubs).where(inArray(clubs.id, accessibleClubIds));

      let sessionQuery = db.select().from(sessions).where(inArray(sessions.clubId, accessibleClubIds));
      const allSessions = await sessionQuery;

      let filteredSessions = allSessions.filter(s => s.status === "COMPLETED");
      if (from) filteredSessions = filteredSessions.filter(s => new Date(s.date) >= new Date(from as string));
      if (to) filteredSessions = filteredSessions.filter(s => new Date(s.date) <= new Date(to as string));
      if (clubId && clubId !== "all") filteredSessions = filteredSessions.filter(s => s.clubId === parseInt(clubId as string));
      if (sessionId && sessionId !== "all") filteredSessions = filteredSessions.filter(s => s.id === parseInt(sessionId as string));
      if (timeOfDay && timeOfDay !== "all") {
        filteredSessions = filteredSessions.filter(s => {
          const hour = parseInt(s.startTime?.split(":")[0] || "0");
          if (timeOfDay === "morning") return hour >= 6 && hour < 12;
          if (timeOfDay === "afternoon") return hour >= 12 && hour < 17;
          if (timeOfDay === "evening") return hour >= 17 && hour < 21;
          if (timeOfDay === "night") return hour >= 21 || hour < 6;
          return true;
        });
      }
      if (weekday && weekday !== "all") {
        const dayNum = parseInt(weekday as string);
        filteredSessions = filteredSessions.filter(s => new Date(s.date).getDay() === dayNum);
      }
      filteredSessions.sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());

      const filteredSessionIds = filteredSessions.map(s => s.id);

      let allSignups: any[] = [];
      if (filteredSessionIds.length > 0) {
        allSignups = await db.select({
          id: sessionSignups.id,
          sessionId: sessionSignups.sessionId,
          playerId: sessionSignups.playerId,
          fee: sessionSignups.fee,
          paymentStatus: sessionSignups.paymentStatus,
          signupStatus: sessionSignups.signupStatus,
          attendanceStatus: sessionSignups.attendanceStatus,
          signupTime: sessionSignups.signupTime,
        }).from(sessionSignups).where(inArray(sessionSignups.sessionId, filteredSessionIds));
      }

      const allPlayers = await db.select({
        id: playerProfiles.id,
        userId: playerProfiles.userId,
        clubId: playerProfiles.clubId,
        gender: playerProfiles.gender,
        grade: playerProfiles.grade,
        joinedAt: playerProfiles.joinedAt,
        playerStatus: playerProfiles.playerStatus,
      }).from(playerProfiles).where(inArray(playerProfiles.clubId, accessibleClubIds));

      const playerUserIds = [...new Set(allPlayers.map(p => p.userId))];
      let playerUsers: any[] = [];
      if (playerUserIds.length > 0) {
        playerUsers = await db.select({ id: users.id, fullName: users.fullName }).from(users).where(inArray(users.id, playerUserIds));
      }
      const userMap = new Map(playerUsers.map(u => [u.id, u.fullName]));

      let allMatchesData: any[] = [];
      if (filteredSessionIds.length > 0) {
        allMatchesData = await db.select({
          id: matches.id,
          sessionId: matches.sessionId,
          status: matches.status,
          isCompleted: matches.isCompleted,
        }).from(matches).where(inArray(matches.sessionId, filteredSessionIds));
      }

      const confirmedSignups = allSignups.filter(s => s.signupStatus === "CONFIRMED");
      const totalRevenue = confirmedSignups.reduce((sum, s) => sum + (s.fee || 0), 0);
      const paidRevenue = confirmedSignups.filter(s => s.paymentStatus === "PAID").reduce((sum, s) => sum + (s.fee || 0), 0);
      const totalPlayers = confirmedSignups.length;
      const totalSessionsCount = filteredSessions.length;
      const sessionsWithSignups = new Set(confirmedSignups.map(s => s.sessionId)).size;
      const avgPlayersPerSession = sessionsWithSignups > 0 ? Math.round((totalPlayers / sessionsWithSignups) * 10) / 10 : 0;
      const revenuePerSession = sessionsWithSignups > 0 ? Math.round(totalRevenue / sessionsWithSignups) : 0;
      const revenuePerPlayer = totalPlayers > 0 ? Math.round(totalRevenue / totalPlayers) : 0;
      const totalCapacity = filteredSessions.reduce((sum, s) => sum + (s.maxPlayers || 0), 0);
      const fillRate = totalCapacity > 0 ? Math.round((totalPlayers / totalCapacity) * 1000) / 10 : 0;
      const pastSessionIds = new Set(filteredSessions.filter(s => new Date(s.date) < new Date()).map(s => s.id));
      const pastConfirmedSignups = confirmedSignups.filter(s => pastSessionIds.has(s.sessionId));
      const noShows = pastConfirmedSignups.filter(s => s.attendanceStatus === "NOT_ATTENDED").length;
      const attendanceTracked = pastConfirmedSignups.filter(s => s.attendanceStatus === "ATTENDED" || s.attendanceStatus === "NOT_ATTENDED" || s.attendanceStatus === "PARTIAL_ATTENDANCE" || s.attendanceStatus === "JUSTIFIED_CANCELLATION").length;
      const noShowRate = attendanceTracked > 0 ? Math.round((noShows / attendanceTracked) * 1000) / 10 : 0;

      const clubStats = allClubsData.map(c => {
        const cSessions = filteredSessions.filter(s => s.clubId === c.id);
        const cIds = cSessions.map(s => s.id);
        const cSignups = confirmedSignups.filter(s => cIds.includes(s.sessionId));
        const cRev = cSignups.reduce((sum, s) => sum + (s.fee || 0), 0);
        const cCap = cSessions.reduce((sum, s) => sum + (s.maxPlayers || 0), 0);
        return {
          id: c.id, name: c.name,
          sessions: cSessions.length, players: cSignups.length,
          revenue: cRev, fillRate: cCap > 0 ? Math.round((cSignups.length / cCap) * 1000) / 10 : 0,
        };
      });

      const mostPopularClub = clubStats.sort((a, b) => b.players - a.players)[0];

      const sessionStats = filteredSessions.map(s => {
        const sSignups = confirmedSignups.filter(sg => sg.sessionId === s.id);
        const sRev = sSignups.reduce((sum, sg) => sum + (sg.fee || 0), 0);
        const sMatches = allMatchesData.filter(m => m.sessionId === s.id);
        const clubName = allClubsData.find(c => c.id === s.clubId)?.name || "Unknown";
        return {
          id: s.id, title: s.title, date: s.date, startTime: s.startTime,
          clubId: s.clubId, clubName,
          players: sSignups.length, maxPlayers: s.maxPlayers,
          fillRate: s.maxPlayers > 0 ? Math.round((sSignups.length / s.maxPlayers) * 1000) / 10 : 0,
          revenue: sRev, revenuePerPlayer: sSignups.length > 0 ? Math.round(sRev / sSignups.length) : 0,
          matches: sMatches.length, completedMatches: sMatches.filter(m => m.isCompleted).length,
          noShows: sSignups.filter(sg => sg.attendanceStatus === "NOT_ATTENDED").length,
          sessionFee: s.sessionFee, durationMinutes: s.durationMinutes,
        };
      });

      const sessionTitleMap = new Map<string, { players: number[]; revenue: number[]; fillRates: number[]; count: number }>();
      for (const s of sessionStats) {
        const key = s.title || "Untitled";
        if (!sessionTitleMap.has(key)) sessionTitleMap.set(key, { players: [], revenue: [], fillRates: [], count: 0 });
        const entry = sessionTitleMap.get(key)!;
        entry.players.push(s.players);
        entry.revenue.push(s.revenue);
        entry.fillRates.push(s.fillRate);
        entry.count++;
      }
      const sessionRankings = [...sessionTitleMap.entries()].map(([title, data]) => ({
        title, count: data.count,
        avgPlayers: Math.round((data.players.reduce((a, b) => a + b, 0) / data.count) * 10) / 10,
        totalRevenue: data.revenue.reduce((a, b) => a + b, 0),
        avgFillRate: Math.round((data.fillRates.reduce((a, b) => a + b, 0) / data.count) * 10) / 10,
      }));

      const mostProfitableSession = sessionRankings.sort((a, b) => b.totalRevenue - a.totalRevenue)[0];

      const attendanceByDate = new Map<string, { players: number; sessions: number; revenue: number }>();
      for (const s of sessionStats) {
        const dateKey = new Date(s.date).toISOString().split("T")[0];
        if (!attendanceByDate.has(dateKey)) attendanceByDate.set(dateKey, { players: 0, sessions: 0, revenue: 0 });
        const entry = attendanceByDate.get(dateKey)!;
        entry.players += s.players;
        entry.sessions += 1;
        entry.revenue += s.revenue;
      }
      const attendanceTrend = [...attendanceByDate.entries()].sort((a, b) => a[0].localeCompare(b[0])).map(([date, data]) => ({
        date, ...data,
      }));

      const weekdayStats = [0, 1, 2, 3, 4, 5, 6].map(day => {
        const daySessions = sessionStats.filter(s => new Date(s.date).getDay() === day);
        return {
          day, dayName: ["Sun", "Mon", "Tue", "Wed", "Thu", "Fri", "Sat"][day],
          sessions: daySessions.length,
          avgPlayers: daySessions.length > 0 ? Math.round((daySessions.reduce((sum, s) => sum + s.players, 0) / daySessions.length) * 10) / 10 : 0,
          totalRevenue: daySessions.reduce((sum, s) => sum + s.revenue, 0),
        };
      });

      const timeSlots = [
        { key: "morning", label: "Morning (6-12)", min: 6, max: 12 },
        { key: "afternoon", label: "Afternoon (12-17)", min: 12, max: 17 },
        { key: "evening", label: "Evening (17-21)", min: 17, max: 21 },
        { key: "night", label: "Night (21-6)", min: 21, max: 30 },
      ];
      const timeOfDayStats = timeSlots.map(slot => {
        const slotSessions = sessionStats.filter(s => {
          const hour = parseInt(s.startTime?.split(":")[0] || "0");
          if (slot.key === "night") return hour >= 21 || hour < 6;
          return hour >= slot.min && hour < slot.max;
        });
        return {
          ...slot, sessions: slotSessions.length,
          avgPlayers: slotSessions.length > 0 ? Math.round((slotSessions.reduce((sum, s) => sum + s.players, 0) / slotSessions.length) * 10) / 10 : 0,
          totalPlayers: slotSessions.reduce((sum, s) => sum + s.players, 0),
          totalRevenue: slotSessions.reduce((sum, s) => sum + s.revenue, 0),
        };
      });

      const fillRanges = [
        { label: "0-20%", min: 0, max: 20 },
        { label: "20-40%", min: 20, max: 40 },
        { label: "40-60%", min: 40, max: 60 },
        { label: "60-80%", min: 60, max: 80 },
        { label: "80-100%", min: 80, max: 101 },
      ];
      const capacityUtilization = fillRanges.map(range => ({
        ...range,
        count: sessionStats.filter(s => s.fillRate >= range.min && s.fillRate < range.max).length,
      }));

      const playerAttendance = new Map<number, { count: number; firstSeen: string; lastSeen: string }>();
      for (const su of confirmedSignups) {
        const sess = filteredSessions.find(s => s.id === su.sessionId);
        if (!sess) continue;
        const dateStr = new Date(sess.date).toISOString();
        if (!playerAttendance.has(su.playerId)) playerAttendance.set(su.playerId, { count: 0, firstSeen: dateStr, lastSeen: dateStr });
        const entry = playerAttendance.get(su.playerId)!;
        entry.count++;
        if (dateStr < entry.firstSeen) entry.firstSeen = dateStr;
        if (dateStr > entry.lastSeen) entry.lastSeen = dateStr;
      }

      const freqDist = { one: 0, twoToFive: 0, fiveToTen: 0, tenPlus: 0 };
      for (const [, data] of playerAttendance) {
        if (data.count === 1) freqDist.one++;
        else if (data.count <= 5) freqDist.twoToFive++;
        else if (data.count <= 10) freqDist.fiveToTen++;
        else freqDist.tenPlus++;
      }

      const now = new Date();
      const thirtyDaysAgo = new Date(now.getTime() - 30 * 86400000);
      const sixtyDaysAgo = new Date(now.getTime() - 60 * 86400000);
      let newPlayers = 0, returningPlayers = 0, frequentPlayers = 0;
      for (const [, data] of playerAttendance) {
        if (new Date(data.firstSeen) >= thirtyDaysAgo) newPlayers++;
        else if (data.count > 5) frequentPlayers++;
        else returningPlayers++;
      }

      const noShowByWeekday = [0, 1, 2, 3, 4, 5, 6].map(day => {
        const daySessions = sessionStats.filter(s => new Date(s.date).getDay() === day);
        return {
          day, dayName: ["Sun", "Mon", "Tue", "Wed", "Thu", "Fri", "Sat"][day],
          noShows: daySessions.reduce((sum, s) => sum + s.noShows, 0),
        };
      });

      const alerts: { type: string; severity: string; message: string }[] = [];
      const recentSessions = sessionStats.filter(s => new Date(s.date) >= thirtyDaysAgo);
      const prevSessions = sessionStats.filter(s => new Date(s.date) >= sixtyDaysAgo && new Date(s.date) < thirtyDaysAgo);

      if (recentSessions.length > 0 && prevSessions.length > 0) {
        const recentAvg = recentSessions.reduce((sum, s) => sum + s.players, 0) / recentSessions.length;
        const prevAvg = prevSessions.reduce((sum, s) => sum + s.players, 0) / prevSessions.length;
        if (prevAvg > 0 && ((prevAvg - recentAvg) / prevAvg) > 0.2) {
          alerts.push({ type: "attendance_drop", severity: "warning", message: `Attendance dropped ${Math.round(((prevAvg - recentAvg) / prevAvg) * 100)}% vs previous period` });
        }
        const recentRev = recentSessions.reduce((sum, s) => sum + s.revenue, 0);
        const prevRev = prevSessions.reduce((sum, s) => sum + s.revenue, 0);
        if (prevRev > 0 && ((prevRev - recentRev) / prevRev) > 0.2) {
          alerts.push({ type: "revenue_drop", severity: "warning", message: `Revenue decreased ${Math.round(((prevRev - recentRev) / prevRev) * 100)}% vs previous period` });
        }
      }

      const lowCapSessions = sessionRankings.filter(s => s.avgFillRate < 40);
      for (const s of lowCapSessions) {
        alerts.push({ type: "low_capacity", severity: "info", message: `"${s.title}" averages ${s.avgFillRate}% capacity` });
      }
      const overCapSessions = sessionRankings.filter(s => s.avgFillRate > 95);
      for (const s of overCapSessions) {
        alerts.push({ type: "over_capacity", severity: "info", message: `"${s.title}" is consistently at ${s.avgFillRate}% capacity` });
      }

      const monthlyTrend = new Map<string, { players: number; sessions: number; revenue: number }>();
      for (const s of sessionStats) {
        const monthKey = new Date(s.date).toISOString().slice(0, 7);
        if (!monthlyTrend.has(monthKey)) monthlyTrend.set(monthKey, { players: 0, sessions: 0, revenue: 0 });
        const entry = monthlyTrend.get(monthKey)!;
        entry.players += s.players;
        entry.sessions += 1;
        entry.revenue += s.revenue;
      }
      const seasonalityData = [...monthlyTrend.entries()].sort((a, b) => a[0].localeCompare(b[0])).map(([month, data]) => ({
        month, ...data,
      }));

      const churnThreshold = new Date(now.getTime() - 60 * 86400000);
      let churnedPlayers = 0, decliningPlayers = 0, loyalPlayers = 0;
      for (const [, data] of playerAttendance) {
        if (new Date(data.lastSeen) < churnThreshold && data.count > 1) churnedPlayers++;
        else if (data.count >= 10) loyalPlayers++;
        else if (data.count >= 2) decliningPlayers++;
      }

      const demandSuggestions: string[] = [];
      for (const s of sessionRankings) {
        if (s.avgFillRate > 90) demandSuggestions.push(`Increase capacity for "${s.title}" — running at ${s.avgFillRate}% average fill rate`);
        if (s.avgFillRate < 30 && s.count > 2) demandSuggestions.push(`Consider rescheduling "${s.title}" — only ${s.avgFillRate}% average fill rate`);
      }
      const bestTimeSlot = timeOfDayStats.sort((a, b) => b.avgPlayers - a.avgPlayers)[0];
      if (bestTimeSlot && bestTimeSlot.avgPlayers > 0) {
        demandSuggestions.push(`${bestTimeSlot.label} time slots attract the most players (avg ${bestTimeSlot.avgPlayers})`);
      }
      const bestWeekday = weekdayStats.sort((a, b) => b.avgPlayers - a.avgPlayers)[0];
      if (bestWeekday && bestWeekday.avgPlayers > 0) {
        demandSuggestions.push(`${bestWeekday.dayName} sessions have the highest average attendance (${bestWeekday.avgPlayers} players)`);
      }

      const playerStatsMap = new Map<number, { id: number; name: string; sessions: number; revenue: number; noShows: number; attended: number; clubs: Set<string>; sessionTitles: Set<string> }>();
      for (const su of confirmedSignups) {
        const sess = filteredSessions.find(s => s.id === su.sessionId);
        if (!sess) continue;
        const clubName = allClubsData.find(c => c.id === sess.clubId)?.name || "Unknown";
        if (!playerStatsMap.has(su.playerId)) {
          const player = allPlayers.find(p => p.id === su.playerId);
          const name = player ? (userMap.get(player.userId) || `Player ${su.playerId}`) : `Player ${su.playerId}`;
          playerStatsMap.set(su.playerId, { id: su.playerId, name, sessions: 0, revenue: 0, noShows: 0, attended: 0, clubs: new Set(), sessionTitles: new Set() });
        }
        const ps = playerStatsMap.get(su.playerId)!;
        ps.sessions++;
        ps.revenue += su.fee || 0;
        if (su.attendanceStatus === "NOT_ATTENDED") ps.noShows++;
        if (su.attendanceStatus === "ATTENDED" || su.attendanceStatus === "PARTIAL_ATTENDANCE") ps.attended++;
        ps.clubs.add(clubName);
        if (sess.title) ps.sessionTitles.add(sess.title);
      }
      const playerStats = [...playerStatsMap.values()].map(p => ({
        id: p.id, name: p.name, sessions: p.sessions, revenue: p.revenue,
        noShows: p.noShows, attended: p.attended,
        clubs: [...p.clubs], sessionTitles: [...p.sessionTitles],
        attendanceRate: p.sessions > 0 ? Math.round((p.attended / p.sessions) * 1000) / 10 : 0,
      })).sort((a, b) => b.sessions - a.sessions);

      const signupsForInteractive = confirmedSignups.map(su => {
        const sess = filteredSessions.find(s => s.id === su.sessionId);
        return {
          playerId: su.playerId, sessionId: su.sessionId, fee: su.fee || 0,
          attendance: su.attendanceStatus, payment: su.paymentStatus,
          date: sess ? new Date(sess.date).toISOString().split("T")[0] : null,
          clubId: sess?.clubId || null,
        };
      }).filter(s => s.date);

      res.json({
        kpis: {
          totalSessions: totalSessionsCount, totalPlayers, totalRevenue, paidRevenue,
          avgPlayersPerSession, revenuePerSession, revenuePerPlayer,
          fillRate, noShowRate, noShows,
          mostPopularClub: mostPopularClub ? { name: mostPopularClub.name, players: mostPopularClub.players } : null,
          mostProfitableSession: mostProfitableSession ? { title: mostProfitableSession.title, revenue: mostProfitableSession.totalRevenue } : null,
          totalMatches: allMatchesData.length,
          completedMatches: allMatchesData.filter(m => m.isCompleted).length,
        },
        attendanceTrend,
        sessionRankings,
        sessionStats,
        weekdayStats,
        timeOfDayStats,
        clubStats,
        capacityUtilization,
        playerRetention: { newPlayers, returningPlayers, frequentPlayers },
        playerFrequency: freqDist,
        noShowByWeekday,
        alerts,
        seasonalityData,
        churn: { churnedPlayers, decliningPlayers, loyalPlayers },
        demandSuggestions,
        clubs: allClubsData.map(c => ({ id: c.id, name: c.name })),
        sessionList: [...new Map(allSessions.map(s => [s.title, { id: s.id, title: s.title }])).values()],
        playerStats,
        signupsRaw: signupsForInteractive,
      });
    } catch (err: any) {
      console.error("Error fetching dashboard analytics:", err);
      res.status(500).json({ message: "Failed to fetch analytics data" });
    }
  });

  app.post("/api/dashboard/analytics/ai-insights", async (req, res) => {
    if (!req.isAuthenticated()) return res.sendStatus(401);
    const user = req.user!;
    if (user.role !== "OWNER") return res.sendStatus(403);

    try {
      const { kpis, topSessions, bottomSessions, weekdayStats, timeOfDayStats, clubStats, alerts, seasonality, churn, question } = req.body;

      const OpenAI = (await import("openai")).default;
      const openai = new OpenAI({ apiKey: process.env.AI_INTEGRATIONS_OPENAI_API_KEY, baseURL: process.env.AI_INTEGRATIONS_OPENAI_BASE_URL });

      let prompt = "";
      const analyticsData = { kpis, topSessions, bottomSessions, weekdayStats, timeOfDayStats, clubStats, alerts, seasonality, churn };
      const dataJson = JSON.stringify(analyticsData, null, 2);
      console.log("[AI Insights] Data being sent to AI:", dataJson.substring(0, 500));

      if (question) {
        prompt = `IMPORTANT: You MUST ONLY reference numbers that appear in the JSON data below. Do NOT make up any numbers.\n\nAnalytics data (all monetary values in £ GBP):\n${dataJson}\n\nUser question: ${question}\n\nAnswer using ONLY the exact figures from the data above. Use £ for all currency values.`;
      } else {
        prompt = `IMPORTANT: You MUST ONLY reference numbers that appear in the JSON data below. Do NOT make up or estimate any numbers. Every figure in your report must come directly from this data.\n\nAnalytics data (all monetary values in £ GBP, "totalUniquePlayerSignups" = total session signups not unique players):\n${dataJson}\n\nWrite a report with these sections:\n## Key Insights\n## Revenue Analysis\n## Attendance Patterns\n## Underperforming Sessions\n## Recommendations\n## Scheduling Improvements\n## Player Engagement Strategies\n\nUse £ for currency. Only quote numbers from the data. If data is limited, say so.`;
      }

      const completion = await openai.chat.completions.create({
        model: "gpt-4o-mini",
        messages: [
          { role: "system", content: "You are a data analyst. You MUST ONLY use the exact numbers provided in the data. NEVER invent, estimate, or hallucinate any figures. If a number is not in the data, say so. Every statistic you quote must come directly from the provided JSON. All monetary values are in British Pounds Sterling (£ GBP)." },
          { role: "user", content: prompt }
        ],
        max_tokens: 2000,
        temperature: 0.1,
      });

      res.json({ report: completion.choices[0]?.message?.content || "No insights available." });
    } catch (err: any) {
      console.error("Error generating AI insights:", err);
      res.status(500).json({ message: "Failed to generate AI insights" });
    }
  });

  app.post("/api/admin/seed-historical-sessions", async (req, res) => {
    if (!req.isAuthenticated()) return res.sendStatus(401);
    const user = req.user as any;
    if (user.role !== "OWNER" && user.role !== "ADMIN") return res.sendStatus(403);

    try {
      const fs = await import("fs");
      const path = await import("path");

      let historicalData: any;
      const possiblePaths = [
        path.join(process.cwd(), "server", "historical_data.json"),
        path.join(process.cwd(), "dist", "historical_data.json"),
        path.join(__dirname, "historical_data.json"),
      ];
      for (const p of possiblePaths) {
        try {
          historicalData = JSON.parse(fs.readFileSync(p, "utf8"));
          break;
        } catch {}
      }
      if (!historicalData) return res.status(404).json({ message: "Historical data file not found" });

      const clubResult = await db.execute(sql`SELECT id FROM clubs WHERE name ILIKE '%badminton performance group%' LIMIT 1`);
      let clubId = (clubResult as any).rows?.[0]?.id;
      if (!clubId) {
        const firstClub = await db.execute(sql`SELECT id FROM clubs ORDER BY id LIMIT 1`);
        clubId = (firstClub as any).rows?.[0]?.id;
      }
      if (!clubId) return res.status(404).json({ message: "No club found" });

      const venueResult = await db.execute(sql`SELECT id FROM venues WHERE club_id = ${clubId} LIMIT 1`);
      const venueId = (venueResult as any).rows?.[0]?.id || null;

      const existingCheck = await db.execute(sql`
        SELECT COUNT(*) as cnt FROM sessions WHERE club_id = ${clubId} AND status = 'COMPLETED' AND title LIKE '%|%'
      `);
      const existingCount = Number((existingCheck as any).rows?.[0]?.cnt || 0);
      if (existingCount > 100) {
        return res.json({ message: "Historical sessions already imported", existingCount });
      }

      const allUsers = await db.execute(sql`SELECT id, full_name FROM users`);
      const userRows = (allUsers as any).rows || [];
      const nameToUserId = new Map<string, number>();
      for (const u of userRows) {
        nameToUserId.set(u.full_name.toLowerCase().trim(), u.id);
      }

      const trialSuffix = /\s*\(trial\)\s*/i;
      const findUserId = (name: string): number | null => {
        const lower = name.toLowerCase().trim();
        if (nameToUserId.has(lower)) return nameToUserId.get(lower)!;
        const withoutTrial = lower.replace(trialSuffix, "").trim();
        if (nameToUserId.has(withoutTrial)) return nameToUserId.get(withoutTrial)!;
        const normalized = lower.replace(/-/g, " ").replace(/\s+/g, " ");
        for (const [k, v] of nameToUserId) {
          if (k.replace(/-/g, " ").replace(/\s+/g, " ") === normalized) return v;
        }
        const manualMap: Record<string, string> = {
          "gisselle gonzalez lopato": "gisselle pascaline gonzalez lopato",
          "franz joseph zaragoza": "franz joseph",
          "mif choudhury (trial)": "mif choudhury",
          "sri injeti": "srichand injeti",
          "syndia": "syndia wu",
          "kunal kukreja": "kunal",
          "saptak chatterjee": "saptak",
          "ojas k": "ojas",
          "emily": "emily jiang",
        };
        const mapped = manualMap[lower];
        if (mapped && nameToUserId.has(mapped)) return nameToUserId.get(mapped)!;
        return null;
      };

      let sessionsCreated = 0;
      let signupsCreated = 0;
      let unmatchedNames = new Set<string>();

      for (const s of historicalData.sessions) {
        const sessionDate = new Date(s.d);

        const existingSessions = await db.execute(sql`
          SELECT id FROM sessions WHERE title = ${s.t} AND date = ${sessionDate} AND club_id = ${clubId} LIMIT 1
        `);
        let sessionId: number;
        if ((existingSessions as any).rows?.length > 0) {
          sessionId = (existingSessions as any).rows[0].id;
        } else {
          const is1to1 = s.t.toLowerCase().includes("1 to 1") || s.t.toLowerCase().includes("1to1");
          const defaultFee = is1to1 ? 3500 : 2000;
          const maxPlayers = is1to1 ? 2 : 20;

          const hours = sessionDate.getUTCHours().toString().padStart(2, "0");
          const mins = sessionDate.getUTCMinutes().toString().padStart(2, "0");
          const startTime = `${hours}:${mins}`;

          const courtsAvailable = is1to1 ? 1 : 3;
          const allowedCategories = JSON.stringify(["C3", "C2", "C1", "B3", "B2", "B1", "A3", "A2", "A1"]);

          const insertResult = await db.execute(sql`
            INSERT INTO sessions (title, date, start_time, duration_minutes, club_id, venue_id, status, session_fee, max_players, courts_available, allowed_categories, created_by, match_mode, is_private, gender_restriction, session_type, players_per_side, match_gender_type, number_of_sets, auto_generate_active, ai_brain_enabled)
            VALUES (${s.t}, ${sessionDate}, ${startTime}, 120, ${clubId}, ${venueId}, 'COMPLETED', ${defaultFee}, ${maxPlayers}, ${courtsAvailable}, ${allowedCategories}::jsonb, ${user.id}, 'SOCIAL', false, 'ALL', 'OPEN', 2, 'MIXED', 1, false, false)
            RETURNING id
          `);
          sessionId = (insertResult as any).rows[0].id;
          sessionsCreated++;
        }

        for (const memberName of s.a) {
          const userId = findUserId(memberName);
          if (!userId) {
            unmatchedNames.add(memberName);
            continue;
          }

          const profiles = await db.execute(sql`
            SELECT id FROM player_profiles WHERE user_id = ${userId} AND club_id = ${clubId} LIMIT 1
          `);
          let profileId: number;
          if ((profiles as any).rows?.length > 0) {
            profileId = (profiles as any).rows[0].id;
          } else {
            const insertProfile = await db.execute(sql`
              INSERT INTO player_profiles (user_id, club_id, club_role) VALUES (${userId}, ${clubId}, 'PLAYER') RETURNING id
            `);
            profileId = (insertProfile as any).rows[0].id;
          }

          const existingSignup = await db.execute(sql`
            SELECT id FROM session_signups WHERE session_id = ${sessionId} AND player_id = ${profileId} LIMIT 1
          `);
          if ((existingSignup as any).rows?.length > 0) continue;

          const feeInfo = historicalData.fees[memberName] || { g: 20, o: 35 };
          const is1to1 = s.t.toLowerCase().includes("1 to 1") || s.t.toLowerCase().includes("1to1");
          const feePence = is1to1 ? feeInfo.o * 100 : feeInfo.g * 100;

          await db.execute(sql`
            INSERT INTO session_signups (session_id, player_id, fee, payment_status, attendance_status, signup_status, signup_time, is_paused, payment_method)
            VALUES (${sessionId}, ${profileId}, ${feePence}, 'PAID', 'ATTENDED', 'CONFIRMED', ${sessionDate}, false, 'CASH')
          `);
          signupsCreated++;
        }
      }

      await db.execute(sql`
        UPDATE player_profiles pp SET matches_played = sub.cnt
        FROM (
          SELECT ss.player_id, COUNT(DISTINCT ss.session_id) as cnt
          FROM session_signups ss WHERE ss.attendance_status = 'ATTENDED'
          GROUP BY ss.player_id
        ) sub
        WHERE pp.id = sub.player_id
      `);

      res.json({
        message: "Historical data import complete",
        sessionsCreated,
        signupsCreated,
        unmatchedNames: [...unmatchedNames],
      });
    } catch (err: any) {
      console.error("Historical import error:", err);
      res.status(500).json({ message: "Import failed", error: err.message });
    }
  });

