  // --- Merchandise Orders ---

  app.post("/api/merchandise/orders", async (req, res) => {
    if (!req.isAuthenticated()) return res.sendStatus(401);
    try {
      const body = z.object({
        productId: z.number().int(),
        size: z.string().nullable().optional(),
        gender: z.string().nullable().optional(),
        style: z.string().nullable().optional(),
        quantity: z.number().int().min(1).max(50).nullable().optional(),
        notes: z.string().max(500).nullable().optional(),
        backName: z.string().max(40).nullable().optional(),
      }).parse(req.body);
      const [product] = await db.select().from(merchandiseProducts).where(eq(merchandiseProducts.id, body.productId));
      if (!product) return res.status(404).json({ message: "Product not found" });
      if (product.status !== "active") return res.status(400).json({ message: "Product is not available" });
      const memberCheck = await db.select({ id: playerProfiles.id }).from(playerProfiles)
        .where(and(eq(playerProfiles.userId, req.user!.id), eq(playerProfiles.clubId, product.clubId), eq(playerProfiles.membershipStatus, "APPROVED")))
        .limit(1);
      if (memberCheck.length === 0) return res.status(403).json({ message: "You must be a member of this club to order" });
      const qty = body.quantity || 1;
      if ((product.stock ?? 0) <= 0) return res.status(400).json({ message: "Out of stock" });
      if ((product.stock ?? 0) < qty) return res.status(400).json({ message: `Only ${product.stock} left in stock` });
      const variationLabelParts = [body.size, body.gender, body.style].filter(Boolean);
      const [order] = await db.insert(merchandiseOrderItems).values({
        clubId: product.clubId,
        productId: body.productId,
        userId: req.user!.id,
        size: body.size || null,
        gender: body.gender || null,
        style: body.style || null,
        quantity: qty,
        notes: body.notes || null,
        backName: body.backName?.trim() || null,
        unitPrice: product.price ?? 0,
        variationLabel: variationLabelParts.length ? variationLabelParts.join(" / ") : null,
      }).returning();

      // Notify club admins of the new merchandise order (in-app + email)
      try {
        const buyer = req.user!;
        const owners = await storage.getUsersByRole("OWNER");
        const clubProfiles = await storage.getClubPlayersWithDetails(product.clubId);
        const clubAdmins = (clubProfiles || [])
          .filter((m: any) => (m.clubRole === "ADMIN" || m.clubRole === "OWNER")
            && m.membershipStatus === "APPROVED")
          .map((m: any) => m.userId);
        const notifyUserIds = new Set<number>([...owners.map((o: any) => o.id), ...clubAdmins]);
        notifyUserIds.delete(buyer.id);
        const variationStr = variationLabelParts.length ? ` (${variationLabelParts.join(" / ")})` : "";
        const phoneStr = (buyer as any).phone ? `\nPhone: ${(buyer as any).phone}` : "";
        for (const notifyUserId of notifyUserIds) {
          await notifyUser({
            userId: notifyUserId,
            type: "MERCHANDISE_ORDER",
            title: "New Merchandise Order",
            message: `${buyer.fullName} ordered ${qty}× ${product.name}${variationStr}.${phoneStr}`,
            linkUrl: "/admin/merchandise",
          });
        }
      } catch (notifyErr: any) {
        console.error("Failed to send merchandise order notifications:", notifyErr?.message || notifyErr);
      }

      res.json(order);
    } catch (err: any) {
      if (err instanceof z.ZodError) return res.status(400).json({ message: "Invalid data", errors: err.errors });
      res.status(500).json({ message: err.message || "Failed to create order" });
    }
  });

