  // Resolves a club logoUrl to a safe absolute path under public/uploads/clubs.
  // Returns null if the URL is missing, outside the allowed directory, or the file
  // does not exist on disk. Prevents path-traversal via crafted logoUrl values.
  const resolveSafeClubLogoPath = (logoUrl: string | null | undefined): string | null => {
    if (!logoUrl || typeof logoUrl !== "string") return null;
    if (!logoUrl.startsWith("/uploads/clubs/")) return null;
    const allowedRoot = path.resolve(process.cwd(), "public", "uploads", "clubs");
    const candidate = path.resolve(process.cwd(), "public", logoUrl.replace(/^\/+/, ""));
    if (!candidate.startsWith(allowedRoot + path.sep)) return null;
    try {
      if (!fs.existsSync(candidate) || !fs.statSync(candidate).isFile()) return null;
    } catch {
      return null;
    }
    return candidate;
  };

  // Cross-club supplier order sheet — admin can select orders from any club they manage.
  app.post("/api/merchandise/orders/supplier-sheet", async (req, res) => {
    if (!req.isAuthenticated()) return res.sendStatus(401);
    try {
      const body = z.object({ orderIds: z.array(z.number().int().positive()).min(1).max(500) }).parse(req.body);

      const rows = await db.select({
        order: merchandiseOrderItems,
        product: merchandiseProducts,
        userName: users.fullName,
        userEmail: users.email,
        clubName: clubs.name,
        clubLogoUrl: clubs.logoUrl,
      }).from(merchandiseOrderItems)
        .innerJoin(merchandiseProducts, and(
          eq(merchandiseOrderItems.productId, merchandiseProducts.id),
          eq(merchandiseOrderItems.clubId, merchandiseProducts.clubId),
        ))
        .innerJoin(users, eq(merchandiseOrderItems.userId, users.id))
        .innerJoin(clubs, eq(merchandiseOrderItems.clubId, clubs.id))
        .where(inArray(merchandiseOrderItems.id, body.orderIds));

      if (rows.length === 0) return res.status(404).json({ message: "No matching orders found." });

      // Verify the user has admin permission for every club in the selection.
      const clubIds = Array.from(new Set(rows.map(r => r.order.clubId)));
      for (const cid of clubIds) {
        const ok = await canPerform({ id: req.user!.id, role: req.user!.role }, "MANAGE_MEMBERSHIPS", cid);
        if (!ok) return res.status(403).json({ message: "You don't have access to one or more selected clubs." });
      }

      const generatedAt = new Date();
      const orders = rows.map(r => ({
        id: r.order.id,
        size: r.order.size,
        gender: r.order.gender,
        style: r.order.style,
        quantity: r.order.quantity,
        notes: r.order.notes,
        adminNotes: r.order.adminNotes,
        backName: r.order.backName,
        status: r.order.status,
        paymentStatus: r.order.paymentStatus ?? null,
        createdAt: r.order.createdAt,
        userName: r.userName || `User #${r.order.userId}`,
        userEmail: r.userEmail || null,
        clubName: r.clubName,
        product: {
          id: r.product.id,
          name: r.product.name,
          description: r.product.description,
          shortDescription: r.product.shortDescription,
          materials: r.product.materials,
          specifications: r.product.specifications,
          categoryName: r.product.categoryName,
          price: r.product.price,
        },
      }));

      const uniqueClubNames = Array.from(new Set(rows.map(r => r.clubName))).filter(Boolean) as string[];
      const headingClubName = uniqueClubNames.length === 1
        ? uniqueClubNames[0]
        : uniqueClubNames.length <= 3
          ? `${uniqueClubNames.length} clubs · ${uniqueClubNames.join(", ")}`
          : `${uniqueClubNames.length} clubs selected`;
      const filenameBase = uniqueClubNames.length === 1
        ? uniqueClubNames[0].replace(/[^a-z0-9-]+/gi, "-").toLowerCase()
        : "multi-club";
      const filename = `supplier-order-${filenameBase}-${generatedAt.toISOString().slice(0, 10)}.pdf`;

      // Collect one safely-resolved logo per unique club for the PDF header.
      const seenClubIds = new Set<number>();
      const clubLogos = rows.reduce<{ name: string; logoPath: string | null }[]>((acc, r) => {
        if (seenClubIds.has(r.order.clubId)) return acc;
        seenClubIds.add(r.order.clubId);
        acc.push({ name: r.clubName || "Club", logoPath: resolveSafeClubLogoPath(r.clubLogoUrl) });
        return acc;
      }, []);

      res.setHeader("Content-Type", "application/pdf");
      res.setHeader("Content-Disposition", `attachment; filename="${filename}"`);

      const doc = generateSupplierOrderSheet(orders, {
        clubName: headingClubName,
        generatedByName: req.user!.fullName || req.user!.username,
        generatedAt,
        showClubColumn: uniqueClubNames.length > 1,
        clubLogos,
      });
      doc.on("error", (err) => {
        console.error("[SUPPLIER SHEET MULTI] PDF stream error", err);
        try { if (!res.headersSent) res.status(500).end(); else res.end(); } catch {}
      });
      res.on("close", () => { try { doc.end(); } catch {} });
      doc.pipe(res);
      doc.end();
    } catch (err: any) {
      if (err instanceof z.ZodError) return res.status(400).json({ message: "Invalid data", errors: err.errors });
      console.error("[SUPPLIER SHEET MULTI] failed", err);
      if (!res.headersSent) res.status(500).json({ message: err.message || "Failed to build supplier sheet" });
    }
  });

  // Supplier order sheet — admin downloads a PDF for selected merch orders.
  app.post("/api/clubs/:clubId/merchandise/orders/supplier-sheet", async (req, res) => {
    if (!req.isAuthenticated()) return res.sendStatus(401);
    try {
      const clubId = Number(req.params.clubId);
      const allowed = await canPerform({ id: req.user!.id, role: req.user!.role }, "MANAGE_MEMBERSHIPS", clubId);
      if (!allowed) return res.sendStatus(403);
      const body = z.object({ orderIds: z.array(z.number().int().positive()).min(1).max(500) }).parse(req.body);

      const rows = await db.select({
        order: merchandiseOrderItems,
        product: merchandiseProducts,
        userName: users.fullName,
        userEmail: users.email,
      }).from(merchandiseOrderItems)
        .innerJoin(merchandiseProducts, and(
          eq(merchandiseOrderItems.productId, merchandiseProducts.id),
          eq(merchandiseProducts.clubId, clubId),
        ))
        .innerJoin(users, eq(merchandiseOrderItems.userId, users.id))
        .where(and(
          eq(merchandiseOrderItems.clubId, clubId),
          inArray(merchandiseOrderItems.id, body.orderIds),
        ));

      if (rows.length === 0) return res.status(404).json({ message: "No matching orders for this club." });

      const [club] = await db.select({ name: clubs.name, logoUrl: clubs.logoUrl }).from(clubs).where(eq(clubs.id, clubId));
      const generatedAt = new Date();
      const orders = rows.map(r => ({
        id: r.order.id,
        size: r.order.size,
        gender: r.order.gender,
        style: r.order.style,
        quantity: r.order.quantity,
        notes: r.order.notes,
        adminNotes: r.order.adminNotes,
        backName: r.order.backName,
        status: r.order.status,
        paymentStatus: r.order.paymentStatus ?? null,
        createdAt: r.order.createdAt,
        userName: r.userName || `User #${r.order.userId}`,
        userEmail: r.userEmail || null,
        product: {
          id: r.product.id,
          name: r.product.name,
          description: r.product.description,
          shortDescription: r.product.shortDescription,
          materials: r.product.materials,
          specifications: r.product.specifications,
          categoryName: r.product.categoryName,
          price: r.product.price,
        },
      }));

      const filename = `supplier-order-${(club?.name || "club").replace(/[^a-z0-9-]+/gi, "-").toLowerCase()}-${generatedAt.toISOString().slice(0, 10)}.pdf`;
      res.setHeader("Content-Type", "application/pdf");
      res.setHeader("Content-Disposition", `attachment; filename="${filename}"`);

      const clubLogoPath = resolveSafeClubLogoPath(club?.logoUrl);

      const doc = generateSupplierOrderSheet(orders, {
        clubName: club?.name || "Club",
        generatedByName: req.user!.fullName || req.user!.username,
        generatedAt,
        clubLogos: [{ name: club?.name || "Club", logoPath: clubLogoPath }],
      });
      doc.on("error", (err) => {
        console.error("[SUPPLIER SHEET] PDF stream error", err);
        try { if (!res.headersSent) res.status(500).end(); else res.end(); } catch {}
      });
      res.on("close", () => { try { doc.end(); } catch {} });
      doc.pipe(res);
      doc.end();
    } catch (err: any) {
      if (err instanceof z.ZodError) return res.status(400).json({ message: "Invalid data", errors: err.errors });
      console.error("[SUPPLIER SHEET] failed", err);
      if (!res.headersSent) res.status(500).json({ message: err.message || "Failed to build supplier sheet" });
    }
  });

